properties.Script Body:
// TransformSOTransfer_Custom.groovy
// Full-file SO Transfer CSV transformer for Nevco custom delivery data.
// Each source row = one delivery line item (product).
// Rows sharing the same sid = one stock.picking (delivery order).
//
// Only 'Success' status rows are included; 'Pending' rows are skipped
// because they have not yet shipped and should not appear as done in inventory.
//
// NiFi flow:
//   TransformSOTransfer_Custom → SplitRecord → insert_so_transfer_custom
//
// Pre-requisite: run LoadSOSerialCache_Custom on ImportSOTRansferSerial.xlsx
//   BEFORE running insert_so_transfer_custom, so that DMAP key
//   'so.serial.{id}' is populated for each row.
//
// Source columns (case-insensitive lookup):
//   id, sid, RefSOid, Pid, Code, ProductName, Description, Quantity, Price, Tax,
//   Date, ChallanNo, ChallanDate, CustomerNameId, CustomerAddressID,
//   ContactPersonID, CustomerDeliverId, CompanyName, Unit, UnitName,
//   StatusName, BranchName, Branchid, SONo
//
// Output columns (subset forwarded to insert_so_transfer_custom):
//   id, sid, RefSOid, Pid, Code, ProductName, Description,
//   Quantity, Price, Tax, Date, ChallanNo, ChallanDate,
//   CustomerNameId, CustomerAddressID, ContactPersonID, CustomerDeliverId,
//   CompanyName, Unit, UnitName, StatusName, BranchName, Branchid, SONo

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets
import java.time.LocalDate
import java.time.format.DateTimeFormatter

def flowFile = session.get()
if (!flowFile) return

// ── Helpers ───────────────────────────────────────────────────────────────────

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : ''
}

def escCsv = { String v ->
    // NiFi CSVReader: Escape Character = \
    // Quote empty fields as "" to prevent trailing-field drop.
    // Double-backslash inside quoted fields so NiFi reads literal \.
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def cleanNum = { String raw ->
    if (!raw) return '0'
    def s = raw.trim().replaceAll(/[,\s]/, '')
    if (s =~ /^[\d.]+[Ee][+\-]?\d+$/) {
        try {
            return new BigDecimal(s).toPlainString().replaceAll(/\.0+$/, '')
        } catch (ignored) { return '0' }
    }
    if (s =~ /^\([\d.]+\)$/) s = '-' + s.replaceAll(/[()]/, '')
    if (!s || s == '-' || s == '.') return '0'
    try { Double.parseDouble(s); return s } catch (ignored) { return '0' }
}

def toDateStr = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    if (s =~ /^\d{4}-\d{2}-\d{2}$/) return s
    if (s =~ /^\d{8}$/) return "${s[0..3]}-${s[4..5]}-${s[6..7]}"
    def m = (s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/)
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())
    def m2 = (s =~ /^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/)
    if (m2) return String.format('%s-%02d-%02d', m2[0][3], m2[0][2].toInteger(), m2[0][1].toInteger())
    // Excel date serial (e.g. 44932 = 2023-01-06): epoch is 1899-12-30
    if (s =~ /^\d+\.?\d*$/) {
        try {
            long serial = Math.round(s.toDouble())
            if (serial > 25569 && serial < 100000) {
                return LocalDate.of(1899, 12, 30).plusDays(serial)
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
        } catch (ignored) {}
    }
    return ''
}

// Robust CSV row assembler — handles multi-line quoted fields.
def assembleRows = { String text ->
    def rows = []
    def sb   = new StringBuilder()
    int qCount = 0
    text.eachLine { line ->
        if (sb.length() > 0) sb.append('\n')
        sb.append(line)
        qCount += line.count('"')
        if (qCount % 2 == 0) {
            rows << sb.toString()
            sb.setLength(0)
            qCount = 0
        }
    }
    if (sb.length() > 0) rows << sb.toString()
    return rows
}

def parseCsvRow = { String line ->
    def cells = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)'"') {
                sb.append('"'); ci++
            } else {
                inQ = !inQ
            }
        } else if (c == (char)',' && !inQ) {
            cells << sb.toString(); sb.setLength(0)
        } else {
            sb.append(c)
        }
    }
    cells << sb.toString()
    return cells
}

try {
    // ── 1. Read file ──────────────────────────────────────────────────────────
    String rawText = ''
    session.read(flowFile, { is ->
        rawText = new String(is.bytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
    } as InputStreamCallback)

    if (!rawText.trim()) {
        log.warn('[TransformSOTransfer_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Detect delimiter ───────────────────────────────────────────────────
    def firstLine = rawText.readLines().find { it.trim() } ?: ''
    def useTab    = firstLine.contains('\t')

    List<String> logicalRows
    List<String> headerCells

    if (useTab) {
        def lines = rawText.readLines().findAll { it.trim() }
        logicalRows = lines
        headerCells = lines[0].split('\t', -1).collect { it.trim() }
    } else {
        logicalRows = assembleRows(rawText).findAll { it.trim() }
        headerCells = parseCsvRow(logicalRows[0]).collect { it.trim() }
    }

    if (logicalRows.size() < 2) {
        log.warn('[TransformSOTransfer_Custom] No data rows found')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Build header index (case-insensitive) ──────────────────────────────
    def hdrIdx = [:]
    headerCells.eachWithIndex { h, i -> def k = h?.toLowerCase()?.trim() ?: ''; if (k) hdrIdx[k] = i }

    def get = { List cells, int idx ->
        idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx])
    }

    def mappingsPath  = flowFile.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
    def tableFields   = new JsonSlurper().parse(new File(mappingsPath)).tables?.so_transfer_custom?.fields ?: [:]
    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) return -1
        def aliases = []
        if (fDef.source_col) aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        for (String alias in aliases) { def k = alias.toLowerCase(); if (hdrIdx.containsKey(k)) return hdrIdx[k] }
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            def found = hdrIdx.find { hk, hv -> hk && (hk.contains(k) || k.contains(hk)) }
            if (found) return found.value
        }
        return -1
    }

    // ── 4. Locate each column ─────────────────────────────────────────────────
    def idIdx        = resolveColIdx('id')
    def sidIdx       = resolveColIdx('sid')
    def refSoIdx     = resolveColIdx('RefSOid')
    def pidIdx       = resolveColIdx('Pid')
    def codeIdx      = resolveColIdx('Code')
    def nameIdx      = resolveColIdx('ProductName')
    def descIdx      = resolveColIdx('Description')
    def qtyIdx       = resolveColIdx('Quantity')
    def priceIdx     = resolveColIdx('Price')
    def taxIdx       = resolveColIdx('Tax')
    def dateIdx      = resolveColIdx('Date')
    def challanNoIdx = resolveColIdx('ChallanNo')
    def challanDtIdx = resolveColIdx('ChallanDate')
    def custNmIdx    = resolveColIdx('CustomerNameId')
    def custAdIdx    = resolveColIdx('CustomerAddressID')
    def contactIdx   = resolveColIdx('ContactPersonID')
    def delivAdIdx   = resolveColIdx('CustomerDeliverId')
    def compNmIdx    = resolveColIdx('CompanyName')
    def unitIdx      = resolveColIdx('Unit')
    def unitNmIdx    = resolveColIdx('UnitName')
    def statusIdx    = resolveColIdx('StatusName')
    def branchNmIdx  = resolveColIdx('BranchName')
    def branchIdIdx  = resolveColIdx('Branchid')
    def soNoIdx      = resolveColIdx('SONo')

    if (idIdx < 0 || sidIdx < 0) {
        log.error("[TransformSOTransfer_Custom] Cannot find 'id' or 'sid' columns. hdrIdx=${hdrIdx}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    log.info("[TransformSOTransfer_Custom] id:${idIdx} sid:${sidIdx} code:${codeIdx} " +
             "qty:${qtyIdx} date:${dateIdx} status:${statusIdx} challanNo:${challanNoIdx}")

    // ── 5. Fixed output columns ───────────────────────────────────────────────
    def COLS = ['id', 'sid', 'RefSOid', 'Pid', 'Code', 'ProductName', 'Description',
                'Quantity', 'Price', 'Tax', 'Date', 'ChallanNo', 'ChallanDate',
                'CustomerNameId', 'CustomerAddressID', 'ContactPersonID', 'CustomerDeliverId',
                'CompanyName', 'Unit', 'UnitName', 'StatusName', 'BranchName', 'Branchid', 'SONo']

    def sb = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0, pending = 0

    // ── 6. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < logicalRows.size(); i++) {
        def cells = useTab
            ? logicalRows[i].split('\t', -1).collect { nvl(it) }
            : parseCsvRow(logicalRows[i])

        def rowId = get(cells, idIdx).replaceAll(/\.0$/, '')
        if (!rowId || rowId.toLowerCase() in ['id', 'row id', 'rowid']) { skipped++; continue }

        def sid = get(cells, sidIdx).replaceAll(/\.0$/, '')
        if (!sid) { skipped++; continue }

        def qty = cleanNum(get(cells, qtyIdx))
        if (qty == '0') { skipped++; continue }

        // Skip pending deliveries — they have not shipped yet
        def status = get(cells, statusIdx)
        if (status.equalsIgnoreCase('Pending')) { pending++; continue }

        def refSoId   = get(cells, refSoIdx).replaceAll(/\.0$/, '').replaceAll(/^#N\/A$/, '')
        def pid       = get(cells, pidIdx).replaceAll(/\.0$/, '')
        def code      = get(cells, codeIdx)
        def prodName  = get(cells, nameIdx)
        def desc      = get(cells, descIdx).replaceAll(/\s*[\r\n]+\s*/, ' ').trim()
        def price     = cleanNum(get(cells, priceIdx))
        def tax       = cleanNum(get(cells, taxIdx))
        def dateStr   = toDateStr(get(cells, dateIdx))
        def challanNo = get(cells, challanNoIdx)
        def challanDt = toDateStr(get(cells, challanDtIdx))
        def custNmId  = get(cells, custNmIdx).replaceAll(/\.0$/, '')
        def custAdId  = get(cells, custAdIdx).replaceAll(/\.0$/, '')
        def contactId = get(cells, contactIdx).replaceAll(/\.0$/, '')
        def delivAdId = get(cells, delivAdIdx).replaceAll(/\.0$/, '')
        def compNm    = get(cells, compNmIdx)
        def unit      = get(cells, unitIdx).replaceAll(/\.0$/, '')
        def unitNm    = get(cells, unitNmIdx)
        def branchNm  = get(cells, branchNmIdx)
        def branchId  = get(cells, branchIdIdx).replaceAll(/\.0$/, '')
        def soNo      = get(cells, soNoIdx)

        def row = [rowId, sid, refSoId, pid, code, prodName, desc,
                   qty, price, tax, dateStr, challanNo, challanDt,
                   custNmId, custAdId, contactId, delivAdId,
                   compNm, unit, unitNm, status, branchNm, branchId, soNo]

        sb.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[TransformSOTransfer_Custom] No valid rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 7. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformSOTransfer_Custom] Done — ${written} rows written, " +
             "${skipped} skipped (zero qty/no sid), ${pending} pending skipped")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformSOTransfer_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// insert_so_transfer_batch.groovy  (NiFi 2.x — SO Transfer batch)
//
// NiFi flow: TransformSOTransfer_Custom → SplitRecord(500/split, JSON array writer)
//              → [THIS]
//
// Pre-requisite: LoadSOSerialCache_Custom must run first to populate DMAP
//   key 'so.serial.{id}' for each transfer line's serial numbers.
//
// Insert order per unique batch:
//   1. stock_picking  (one per unique sid)
//   2. stock_move     (one per row)
//   3. stock_lot      (find-or-create per serial+product_id)
//   4. stock_move_line (one per serial qty=1, or one with full qty if no serials)
//
// IMPORTANT: All SQL.myPool.eachRow calls MUST stay outside withTransaction.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]
def uomAliases   = customCfg.uom_aliases     ?: [:]
def soXferCfg    = customCfg.so_transfer_defaults ?: [:]

def compXidPfx = xidPfx.company      ?: 'cust_company_'
def persXidPfx = xidPfx.person       ?: 'cust_person_'
def tmplXidPfx = xidPfx.product_tmpl ?: 'cust_tmpl_'
def pickXidPfx = xidPfx.so_picking   ?: 'cust_picking_'
def moveXidPfx = xidPfx.so_move      ?: 'cust_move_'
def mlXidPfx   = xidPfx.so_move_line ?: 'cust_move_line_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) {}
    try { return (long) s.toDouble() } catch (ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def sl = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
              .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(60)
    sl ?: 'unknown'
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[SOTransferBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // Fixed location/operation IDs (override from mapping.json if needed)
    final long PICKING_TYPE_ID = safeLong(soXferCfg.picking_type_id) ?: 2L
    final long LOCATION_SRC_ID = safeLong(soXferCfg.location_src_id) ?: 5L
    final long LOCATION_DST_ID = safeLong(soXferCfg.location_dest_id) ?: 2L

    // ── 3. Schema probes (Phase 1) ────────────────────────────────────────────
    def colIn = { String tbl, String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name=? AND column_name=? LIMIT 1",
            [tbl, col]
        ) { found = true }
        return found
    }
    def hasMoveDescPicking    = colIn('stock_move', 'description_picking_manual')
    def hasMovePicked         = colIn('stock_move', 'picked')
    def hasMoveQty            = colIn('stock_move', 'quantity')        // Odoo 17; older = qty_done
    def hasMlQtyProductUom    = colIn('stock_move_line', 'quantity_product_uom')
    def hasMlPicked           = colIn('stock_move_line', 'picked')
    def hasPickIsLocked       = colIn('stock_picking', 'is_locked')
    def hasPickPrinted        = colIn('stock_picking', 'printed')
    def hasPickHasDeadline    = colIn('stock_picking', 'has_deadline_issue')
    log.info("[SOTransferBatch] Schema: moveDescPicking=${hasMoveDescPicking} moveQty=${hasMoveQty} mlQtyProdUom=${hasMlQtyProductUom}")

    // ── 4. Helpers defined here to access module, SQL ─────────────────────────
    def resolveProduct = { String code, String pid, String prodName ->
        Long tmplId = null; Long varId = null
        if (code) tmplId = safeLong(cacheGet('product.code.' + code))
        if (pid)  varId  = safeLong(cacheGet('cust.prodid.' + pid))
        if (!tmplId && varId) {
            SQL.myPool.eachRow('SELECT product_tmpl_id FROM product_product WHERE id=? LIMIT 1', [varId]) { r ->
                tmplId = safeLong(r['product_tmpl_id'])
            }
        }
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='product.template' LIMIT 1",
                [module, tmplXidPfx + slugify(code)]
            ) { r -> tmplId = safeLong(r['res_id']) }
        }
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='product.template' LIMIT 1",
                [module, 'tally_product_template_TALLY_PRODUCT_RC_' + slugify(code)]
            ) { r -> tmplId = safeLong(r['res_id']) }
        }
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_template WHERE default_code=? AND active=true LIMIT 1", [code]
            ) { r -> tmplId = safeLong(r['id']) }
        }
        if (!tmplId && prodName) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_template WHERE name::text ILIKE ? AND active=true LIMIT 1", [prodName]
            ) { r -> tmplId = safeLong(r['id']) }
        }
        if (tmplId && !varId) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_product WHERE product_tmpl_id=? AND active=true LIMIT 1", [tmplId]
            ) { r -> varId = safeLong(r['id']) }
        }
        if (!varId && tmplId) varId = tmplId
        return [tmplId: tmplId, varId: varId]
    }

    def resolveUom = { String unitName ->
        def resolvedName = unitName
            ? (uomAliases[unitName] ?: uomAliases[unitName.replaceAll(/\.$/, '')] ?: unitName)
            : 'Units'
        Long uomId = safeLong(cacheGet('lookup.uom.' + resolvedName))
        if (!uomId && resolvedName) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE ? AND active=true LIMIT 1", [resolvedName]
            ) { r ->
                uomId = safeLong(r['id'])
                if (uomId) cacheSet('lookup.uom.' + resolvedName, uomId.toString())
            }
        }
        if (!uomId && unitName && unitName != resolvedName) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE ? AND active=true LIMIT 1", [unitName]
            ) { r -> uomId = safeLong(r['id']) }
        }
        if (!uomId) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE 'Units' AND active=true LIMIT 1"
            ) { r -> uomId = safeLong(r['id']) }
            if (!uomId) uomId = 1L
        }
        return uomId
    }

    // Reference validity check (same rules as original)
    def isValidRef = { String v ->
        if (!v) return false
        def s = v.trim()
        if (!s) return false
        if (s in ['#N/A','#NA','NA','N/A','null','\\N','#NULL!','#REF!','0']) return false
        if (s.startsWith('\\')) return false
        if (s.startsWith('₹') || s.startsWith('$') || s.startsWith('€') || s.startsWith('£')) return false
        if (s =~ /^\d+\.?\d*$/) return false
        if (s.startsWith('http://') || s.startsWith('https://')) return false
        if (s.length() > 30) return false
        if (s =~ /(?i)\b(pvt|private|limited|ltd|llp|inc)\b/) return false
        return true
    }

    def invalidSerials = ['na','0','null','','\\n','n/a','none','#n/a','#na'] as Set

    // Invalid sid markers (Excel/Tally error values that must not reach the DB)
    def invalidSids = { String s ->
        !s || s =~ /(?i)(^#|^ERROR|^null$|^\\N$|^0$|^NA$|^N\/A$)/ || s.length() > 60
    }

    // ── 5. Group rows by sid — first row used for picking header data ──────────
    def sidGroups = [:]  // sid → first row
    rows.each { row ->
        def sidRaw = nvl(row['sid'])
        if (!sidRaw) return
        def sid = sidRaw.replaceAll(/\.0$/, '').trim()
        if (invalidSids(sid)) { log.warn("[SOTransferBatch] Invalid sid='${sid}' — skipping row"); return }
        if (!sidGroups.containsKey(sid)) sidGroups[sid] = row
    }
    log.info("[SOTransferBatch] Unique sids: ${sidGroups.size()}")

    // ── 6. Phase 1: picking idempotency + partner resolution ──────────────────
    def existingPickingIds   = [:]  // sid → Long dbId (pre-existing)
    def pickingItemsToInsert = []
    def cacheUpdates         = []
    int skipCount            = 0

    sidGroups.each { sid, row ->
        def sidSlug    = slugify(sid)          // safe for ir_model_data.name constraint
        def pickingXid = pickXidPfx + sidSlug
        def pickCk     = 'xid.picking.' + pickingXid
        def pickName   = 'CUST/OUT/' + sidSlug.take(20)  // computed early for name-based lookup

        // Idempotency level 1: cache
        Long dbId = safeLong(cacheGet(pickCk))
        if (dbId) {
            def found = false
            SQL.myPool.eachRow('SELECT id FROM stock_picking WHERE id=? LIMIT 1', [dbId]) { found = true }
            if (!found) { cacheSet(pickCk, 'CLEARED'); dbId = null }
        }
        // Idempotency level 2: ir_model_data XID
        if (!dbId) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='stock.picking' LIMIT 1",
                [module, pickingXid]
            ) { r ->
                def rid = safeLong(r['res_id'])
                if (rid) {
                    def found = false
                    SQL.myPool.eachRow('SELECT id FROM stock_picking WHERE id=? LIMIT 1', [rid]) { found = true }
                    if (found) dbId = rid
                }
            }
        }
        // Idempotency level 3: name + company_id (picking exists but XID was never registered)
        if (!dbId) {
            SQL.myPool.eachRow(
                'SELECT id FROM stock_picking WHERE name=? AND company_id=? LIMIT 1',
                [pickName, compId]
            ) { r -> dbId = safeLong(r['id']) }
            if (dbId) log.info("[SOTransferBatch] Found picking by name: ${pickName} → ${dbId}")
        }
        if (dbId) {
            existingPickingIds[sid] = dbId
            cacheUpdates << [pickCk, dbId.toString()]
            log.info("[SOTransferBatch] Picking already exists: ${pickingXid} → ${dbId}")
            return
        }

        // Partner resolution (5-level, slugify-corrected)
        def custNameId  = nvl(row['CustomerNameId'])
        def custAddrId  = nvl(row['CustomerAddressID'])
        def delivAdId   = nvl(row['CustomerDeliverId'])
        def companyName = nvl(row['CompanyName'])
        def nameSlug    = custNameId ? slugify(custNameId) : null
        def addrSlug    = custAddrId ? slugify(custAddrId) : null

        Long partnerId = null
        if (custNameId) partnerId = safeLong(cacheGet('cust.nameid.'   + custNameId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.personid.' + custAddrId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.addrid.'   + custAddrId))
        if (!partnerId && nameSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, compXidPfx + nameSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && addrSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, persXidPfx + addrSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE name ILIKE ? AND active=true ORDER BY is_company DESC, id LIMIT 1",
                [companyName]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE (commercial_company_name ILIKE ? OR complete_name ILIKE ?) AND active=true ORDER BY is_company DESC, id LIMIT 1",
                ["%${companyName}%", "%${companyName}%"]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId) log.warn("[SOTransferBatch] partner_id not resolved for sid=${sid}")

        // Delivery partner
        Long delivPartnerId = null
        if (delivAdId) {
            delivPartnerId = safeLong(cacheGet('cust.addrid.' + delivAdId))
            if (!delivPartnerId) {
                SQL.myPool.eachRow(
                    "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                    [module, persXidPfx + slugify(delivAdId)]
                ) { r -> delivPartnerId = safeLong(r['res_id']) }
            }
        }
        if (!delivPartnerId) delivPartnerId = partnerId

        def dateStr   = nvl(row['Date'])
        def challanDt = nvl(row['ChallanDate'])
        def challanNo = nvl(row['ChallanNo'])
        def soNo      = nvl(row['SONo'])

        def transferDate = (dateStr  && dateStr  =~ /^\d{4}-\d{2}-\d{2}/) ? dateStr :
                           (challanDt && challanDt =~ /^\d{4}-\d{2}-\d{2}/) ? challanDt : null

        def origin = (isValidRef(soNo) ? soNo : null) ?: (isValidRef(challanNo) ? challanNo : null)

        pickingItemsToInsert << [
            sid            : sid,
            pickingXid     : pickingXid,
            pickCk         : pickCk,
            pickName       : pickName,
            partnerId      : partnerId,
            delivPartnerId : delivPartnerId,
            origin         : origin,
            transferDate   : transferDate,
        ]
    }

    // Sids that couldn't get a picking (failed product/partner) will have moves skipped
    def resolvedSids = new HashSet(existingPickingIds.keySet())
    pickingItemsToInsert.each { resolvedSids.add(it.sid) }
    def failedSids = sidGroups.keySet().findAll { !resolvedSids.contains(it) } as Set

    // ── 7. Phase 1: move idempotency + product/UOM/serial resolution ──────────
    def moveItems = []

    rows.each { row ->
        def rowId  = nvl(row['id'])
        def sidRaw = nvl(row['sid'])
        if (!rowId || !sidRaw) { skipCount++; return }
        def sid = sidRaw.replaceAll(/\.0$/, '').trim()
        if (invalidSids(sid)) { skipCount++; return }

        if (failedSids.contains(sid)) { skipCount++; return }

        def qty = safeBD(row['Quantity'])
        if (qty <= BigDecimal.ZERO) {
            log.warn("[SOTransferBatch] Zero qty: sid=${sid} rowId=${rowId} — skipping")
            skipCount++; return
        }

        def code     = nvl(row['Code'])
        def prodName = nvl(row['ProductName'])
        if (!code && !prodName) {
            log.warn("[SOTransferBatch] No Code/ProductName: rowId=${rowId} — skipping")
            skipCount++; return
        }

        // Move idempotency
        def moveXid = moveXidPfx + rowId
        Long existingMoveId = null
        SQL.myPool.eachRow(
            "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='stock.move' LIMIT 1",
            [module, moveXid]
        ) { r ->
            def rid = safeLong(r['res_id'])
            if (rid) {
                def found = false
                SQL.myPool.eachRow('SELECT id FROM stock_move WHERE id=? LIMIT 1', [rid]) { found = true }
                if (found) existingMoveId = rid
            }
        }
        if (existingMoveId) { skipCount++; return }

        // Product resolution
        def pid = nvl(row['Pid'])
        def prod = resolveProduct(code, pid, prodName)
        if (!prod.tmplId) {
            log.warn("[SOTransferBatch] Product not resolved: rowId=${rowId} code=${code} — skipping")
            skipCount++; return
        }

        // UOM resolution
        Long uomId = resolveUom(nvl(row['UnitName']))

        // Date
        def dateStr   = nvl(row['Date'])
        def challanDt = nvl(row['ChallanDate'])
        def transferDate = (dateStr   && dateStr   =~ /^\d{4}-\d{2}-\d{2}/) ? dateStr :
                           (challanDt && challanDt  =~ /^\d{4}-\d{2}-\d{2}/) ? challanDt : null
        def moveDate = transferDate ?: new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date())

        // Serial lookup from DMAP cache
        def rawSerial = cacheGet('so.serial.' + rowId) ?: ''
        def serials = rawSerial.split(',').collect { it.trim() }
                               .findAll { it && !(it.toLowerCase() in invalidSerials) }

        def challanNo = nvl(row['ChallanNo'])
        def soNo      = nvl(row['SONo'])
        def origin    = (isValidRef(soNo) ? soNo : null) ?: (isValidRef(challanNo) ? challanNo : null)
        def pickName  = 'CUST/OUT/' + slugify(sid).take(20)

        moveItems << [
            rowId       : rowId,
            sid         : sid,
            moveXid     : moveXid,
            varId       : prod.varId,
            tmplId      : prod.tmplId,
            uomId       : uomId,
            qty         : qty,
            price       : safeBD(row['Price']),
            moveName    : (prodName ?: code ?: 'Transfer').take(256),
            moveDate    : moveDate,
            transferDate: transferDate,
            pickName    : pickName,
            serials     : serials,
        ]
    }

    log.info("[SOTransferBatch] Pickings to insert: ${pickingItemsToInsert.size()}, moves to insert: ${moveItems.size()}")

    // ── 8. Phase 1: pre-resolve existing stock_lots for all serials ────────────
    def serialLotMap = [:]  // "${sn}_${varId}" → Long lotId
    def allSerialKeys = moveItems.collectMany { item ->
        item.serials.collect { sn -> [sn, item.varId] }
    }.unique()

    allSerialKeys.each { sn, vid ->
        def key = "${sn}_${vid}"
        if (!serialLotMap.containsKey(key)) {
            SQL.myPool.eachRow(
                'SELECT id FROM stock_lot WHERE name=? AND product_id=? AND company_id=? LIMIT 1',
                [sn, vid, compId]
            ) { r -> serialLotMap[key] = safeLong(r['id']) }
        }
    }
    log.info("[SOTransferBatch] Pre-resolved ${serialLotMap.size()} unique serial/product lots")

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: only conn.prepareStatement inside
    // ════════════════════════════════════════════════════════════════════════
    int pickWritten = 0
    int moveWritten = 0
    int lineWritten = 0
    def xidBatch    = []

    SQL.myPool.withTransaction { conn ->
        // Working maps
        def pickingIdMap  = new HashMap(existingPickingIds)
        def lotIdResolved = new HashMap(serialLotMap)  // sn_varId → lotId (grows as new lots are inserted)

        // ── INSERT stock_picking headers ──────────────────────────────────────
        pickingItemsToInsert.each { item ->
            def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
            delPs.setString(1, module); delPs.setString(2, item.pickingXid)
            delPs.executeUpdate(); delPs.close()

            def pickCols = ['name','company_id','partner_id',
                            'location_id','location_dest_id','picking_type_id',
                            'origin','move_type','state',
                            'scheduled_date','date_done',
                            'create_uid','write_uid','create_date','write_date']
            def pickVals = ['?','?','?',
                            "${LOCATION_SRC_ID}","${LOCATION_DST_ID}","${PICKING_TYPE_ID}",
                            '?',"'direct'","'done'",
                            '?::timestamp','?::timestamp',
                            '?','?','NOW()','NOW()']
            def pickParams = [item.pickName, compId,
                              item.delivPartnerId ?: null,
                              item.origin,
                              item.transferDate ? item.transferDate + ' 00:00:00' : null,
                              item.transferDate ? item.transferDate + ' 00:00:00' : null,
                              adminUid, adminUid] as List

            if (hasPickIsLocked)    { pickCols.add(8, 'is_locked');         pickVals.add(8, 'true') }
            if (hasPickPrinted)     { pickCols.add(9, 'printed');           pickVals.add(9, 'false') }
            if (hasPickHasDeadline) { pickCols.add(10,'has_deadline_issue'); pickVals.add(10,'false') }

            def pkPs = conn.prepareStatement(
                "INSERT INTO stock_picking (${pickCols.join(',')}) VALUES (${pickVals.join(',')}) ON CONFLICT (name,company_id) DO NOTHING RETURNING id"
            )
            pickParams.eachWithIndex { v, i ->
                int pos = i + 1
                if (v == null)              pkPs.setObject(pos, null)
                else if (v instanceof Long) pkPs.setLong(pos, v)
                else                        pkPs.setString(pos, v.toString())
            }
            def pkRs = pkPs.executeQuery()
            Long pickId
            if (pkRs.next()) {
                // Normal insert
                pickId = pkRs.getLong(1)
                pickWritten++
                log.info("[SOTransferBatch] stock_picking INSERTED: ${item.pickingXid} → ${pickId}")
            } else {
                // Conflict — concurrent batch already inserted this picking; look it up by name
                def selPs = conn.prepareStatement(
                    'SELECT id FROM stock_picking WHERE name=? AND company_id=? LIMIT 1'
                )
                selPs.setString(1, item.pickName); selPs.setLong(2, compId)
                def selRs = selPs.executeQuery()
                if (selRs.next()) pickId = selRs.getLong(1)
                selRs.close(); selPs.close()
                log.info("[SOTransferBatch] Picking conflict resolved by name: ${item.pickName} → ${pickId}")
            }
            pkRs.close(); pkPs.close()
            if (!pickId) throw new Exception("Could not resolve picking id for ${item.pickingXid}")

            pickingIdMap[item.sid] = pickId
            xidBatch     << [module, item.pickingXid, 'stock.picking', pickId]
            cacheUpdates << [item.pickCk, pickId.toString()]
        }

        // ── INSERT stock_move + stock_lot + stock_move_line per row ───────────
        moveItems.each { item ->
            Long pickingId = pickingIdMap[item.sid]
            if (!pickingId) {
                log.warn("[SOTransferBatch] No pickingId for sid=${item.sid} rowId=${item.rowId} — skipping move")
                return
            }

            // ── INSERT stock_move ─────────────────────────────────────────────
            def mvNameCol = hasMoveDescPicking ? 'description_picking_manual' : 'name'
            def mvQtyCol  = hasMoveQty         ? 'quantity'                   : 'qty_done'

            def mvCols = [mvNameCol, 'company_id','product_id','product_uom',
                          'location_id','location_dest_id','picking_id','picking_type_id',
                          'state','product_uom_qty', mvQtyCol,
                          'procure_method','price_unit','date','reference',
                          'create_uid','write_uid','create_date','write_date']
            def mvVals = ['?','?','?','?',
                          "${LOCATION_SRC_ID}","${LOCATION_DST_ID}",'?',"${PICKING_TYPE_ID}",
                          "'done'",'?','?',
                          "'make_to_stock'",'?','?::timestamp','?',
                          '?','?','NOW()','NOW()']
            def mvParams = [item.moveName, compId, item.varId, item.uomId,
                            pickingId,
                            item.qty, item.qty,
                            item.price, item.moveDate + ' 00:00:00', item.pickName,
                            adminUid, adminUid] as List

            if (hasMovePicked) { mvCols.add(mvCols.indexOf(mvQtyCol) + 1, 'picked'); mvVals.add(mvVals.indexOf('?') + 11, 'true') }

            // Build move INSERT without the picked flag complication — add it at end
            def mvColsFinal = [mvNameCol, 'company_id','product_id','product_uom',
                               'location_id','location_dest_id','picking_id','picking_type_id',
                               'state','product_uom_qty',mvQtyCol,
                               'procure_method','price_unit','date','reference',
                               'create_uid','write_uid','create_date','write_date']
            def mvValsFinal = ['?','?','?','?',
                               "${LOCATION_SRC_ID}","${LOCATION_DST_ID}",'?',"${PICKING_TYPE_ID}",
                               "'done'",'?','?',
                               "'make_to_stock'",'?','?::timestamp','?',
                               '?','?','NOW()','NOW()']
            def mvParamsFinal = [item.moveName, compId, item.varId, item.uomId,
                                 pickingId,
                                 item.qty, item.qty,
                                 item.price, item.moveDate + ' 00:00:00', item.pickName,
                                 adminUid, adminUid] as List
            if (hasMovePicked) { mvColsFinal << 'picked'; mvValsFinal << 'true' }

            def mvPs = conn.prepareStatement(
                "INSERT INTO stock_move (${mvColsFinal.join(',')}) VALUES (${mvValsFinal.join(',')}) RETURNING id"
            )
            mvParamsFinal.eachWithIndex { v, i ->
                int pos = i + 1
                if (v == null)                    mvPs.setObject(pos, null)
                else if (v instanceof Long)       mvPs.setLong(pos, v)
                else if (v instanceof BigDecimal) mvPs.setBigDecimal(pos, v)
                else                              mvPs.setString(pos, v.toString())
            }
            def mvRs = mvPs.executeQuery()
            mvRs.next(); long moveId = mvRs.getLong(1); mvRs.close(); mvPs.close()

            xidBatch << [module, item.moveXid, 'stock.move', moveId]
            moveWritten++

            // ── INSERT stock_move_line(s) ─────────────────────────────────────
            if (item.serials) {
                item.serials.eachWithIndex { sn, idx ->
                    def lotKey = "${sn}_${item.varId}"
                    Long lotId = lotIdResolved[lotKey]

                    if (!lotId) {
                        // New lot — insert it
                        def ltPs = conn.prepareStatement("""
                            INSERT INTO stock_lot
                              (name, product_id, company_id, create_uid, write_uid, create_date, write_date)
                            VALUES (?,?,?,?,?,NOW(),NOW())
                            RETURNING id
                        """)
                        ltPs.setString(1, sn); ltPs.setLong(2, item.varId)
                        ltPs.setLong(3, compId); ltPs.setLong(4, adminUid); ltPs.setLong(5, adminUid)
                        def ltRs = ltPs.executeQuery()
                        ltRs.next(); lotId = ltRs.getLong(1); ltRs.close(); ltPs.close()
                        lotIdResolved[lotKey] = lotId
                        log.info("[SOTransferBatch] stock_lot created: id=${lotId} serial='${sn}' product=${item.varId}")
                    }

                    // INSERT move_line (qty=1 per serial)
                    def mlCols = ['picking_id','move_id','company_id','product_id','product_uom_id',
                                  'location_id','location_dest_id',
                                  'quantity', 'lot_id','lot_name',
                                  'state','date',
                                  'create_uid','write_uid','create_date','write_date']
                    def mlVals = ['?','?','?','?','?',
                                  "${LOCATION_SRC_ID}","${LOCATION_DST_ID}",
                                  '1.0','?','?',
                                  "'done'",'?::timestamp',
                                  '?','?','NOW()','NOW()']
                    def mlParams = [pickingId, moveId, compId, item.varId, item.uomId,
                                    lotId, sn,
                                    item.moveDate + ' 00:00:00',
                                    adminUid, adminUid] as List
                    if (hasMlQtyProductUom) { mlCols.add(8, 'quantity_product_uom'); mlVals.add(8, '1.0') }
                    if (hasMlPicked)        { mlCols << 'picked';                    mlVals << 'true' }

                    def mlPs = conn.prepareStatement(
                        "INSERT INTO stock_move_line (${mlCols.join(',')}) VALUES (${mlVals.join(',')}) RETURNING id"
                    )
                    mlParams.eachWithIndex { v, i ->
                        int pos = i + 1
                        if (v == null)                    mlPs.setObject(pos, null)
                        else if (v instanceof Long)       mlPs.setLong(pos, v)
                        else if (v instanceof BigDecimal) mlPs.setBigDecimal(pos, v)
                        else                              mlPs.setString(pos, v.toString())
                    }
                    def mlRs = mlPs.executeQuery()
                    mlRs.next(); long mlId = mlRs.getLong(1); mlRs.close(); mlPs.close()

                    xidBatch << [module, mlXidPfx + item.rowId + '_' + idx, 'stock.move.line', mlId]
                    lineWritten++
                }
            } else {
                // No serials — single move_line with full qty
                def mlCols = ['picking_id','move_id','company_id','product_id','product_uom_id',
                              'location_id','location_dest_id',
                              'quantity',
                              'state','date',
                              'create_uid','write_uid','create_date','write_date']
                def mlVals = ['?','?','?','?','?',
                              "${LOCATION_SRC_ID}","${LOCATION_DST_ID}",
                              '?',
                              "'done'",'?::timestamp',
                              '?','?','NOW()','NOW()']
                def mlParams = [pickingId, moveId, compId, item.varId, item.uomId,
                                item.qty,
                                item.moveDate + ' 00:00:00',
                                adminUid, adminUid] as List
                if (hasMlQtyProductUom) { mlCols.add(8, 'quantity_product_uom'); mlVals.add(8, '?'); mlParams.add(6, item.qty) }
                if (hasMlPicked)        { mlCols << 'picked'; mlVals << 'true' }

                def mlPs = conn.prepareStatement(
                    "INSERT INTO stock_move_line (${mlCols.join(',')}) VALUES (${mlVals.join(',')}) RETURNING id"
                )
                mlParams.eachWithIndex { v, i ->
                    int pos = i + 1
                    if (v == null)                    mlPs.setObject(pos, null)
                    else if (v instanceof Long)       mlPs.setLong(pos, v)
                    else if (v instanceof BigDecimal) mlPs.setBigDecimal(pos, v)
                    else                              mlPs.setString(pos, v.toString())
                }
                def mlRs = mlPs.executeQuery()
                mlRs.next(); long mlId = mlRs.getLong(1); mlRs.close(); mlPs.close()

                xidBatch << [module, mlXidPfx + item.rowId + '_0', 'stock.move.line', mlId]
                lineWritten++
            }
        }

        // ── Batch XID inserts (sorted to prevent deadlocks) ───────────────────
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m, n, mdl, rid ->
                xidPs.setString(1, m); xidPs.setString(2, n)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try { xidPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                log.error("[SOTransferBatch] XID batch failed: ${bue.message}")
                throw bue
            }
            xidPs.close()
        }

        log.info("[SOTransferBatch] Committed — pickings:${pickWritten} moves:${moveWritten} lines:${lineWritten}")
    }

    // Post-commit cache
    cacheUpdates.each { ck, v -> cacheSet(ck, v) }

    ff = session.putAllAttributes(ff, [
        'picking.written'  : pickWritten.toString(),
        'move.written'     : moveWritten.toString(),
        'move_line.written': lineWritten.toString(),
        'skipped'          : skipCount.toString(),
        'batch.size'       : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[SOTransferBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// balance_check_and_post.groovy  (NiFi 2.x — invoice batch, step 3 of 3)
//
// NiFi flow: TransformInvoice → SplitRecord(500/split, JSON array writer)
//              → insert_account_move_batch
//              → insert_account_move_line_batch
//              → [THIS] balance_check_and_post
//
// Input:  JSON array — pass-through from step 2
// Action: For each unique Invoice Number (Name):
//           1. Verify SUM(balance) = 0 across all account_move_line rows
//           2. Read move_type + compute amount breakdown from lines (read-only, outside tx)
//           3. Promote lines: UPDATE parent_state = 'posted' WHERE parent_state = 'draft'
//           4. Set amount_residual on payment_term line
//           5. UPDATE account_move: amount_untaxed, amount_tax, amount_total, payment_state
//
// IMPORTANT: All SQL.myPool.eachRow(...) calls MUST stay outside withTransaction.
//   Groovy's Sql.withTransaction caches the connection at the Sql instance level — any
//   SQL.myPool.* call inside the closure reuses the transactional connection, so a failed
//   read aborts the transaction and the UPDATE never executes.
//
// Output: Pass-through with balance.ok / balance.fail / balance.skip attributes.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]

def invXidPfx = xidPfx.invoice ?: 'cust_inv_'

def balanceTolerance = new BigDecimal('0.01')

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch(ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(80)
    slug ?: 'unknown'
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[BalanceCheck] Batch size: ${rows.size()}")

    def module = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // ── 2. Schema probes (all outside any transaction) ────────────────────────
    def amCol = { String tbl, String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name=? AND column_name=? LIMIT 1",
            [tbl, col]
        ) { found = true }
        return found
    }
    def hasPaymentState          = amCol('account_move',      'payment_state')
    def hasAmountTax             = amCol('account_move',      'amount_tax')
    def hasAmountResidual        = amCol('account_move_line', 'amount_residual')
    def hasAmountResidualCurr    = amCol('account_move_line', 'amount_residual_currency')
    def hasInvPartnerDisplayName = amCol('account_move',      'invoice_partner_display_name')
    log.info("[BalanceCheck] Schema: paymentState=${hasPaymentState} amountTax=${hasAmountTax} amlResidual=${hasAmountResidual}")

    // ── 3. Collect unique invoice numbers ─────────────────────────────────────
    def uniqueInvNos = rows.collect { nvl(it['Invoice Number (Name)']) }.findAll { it }.unique()
    log.info("[BalanceCheck] Unique invoices: ${uniqueInvNos.size()}")

    // ── 4. Process each invoice ───────────────────────────────────────────────
    int okCount = 0, failCount = 0, skipCount = 0
    def failedInvNos = []

    uniqueInvNos.each { invNo ->
        def slug  = slugify(invNo)
        Long moveId = safeLong(cacheGet('invoice.move.' + slug))
        if (!moveId) {
            SQL.myPool.eachRow(
                'SELECT res_id FROM ir_model_data WHERE module=? AND name=? LIMIT 1',
                [module, invXidPfx + slug]
            ) { r -> moveId = safeLong(r['res_id']) }
        }
        if (!moveId) { log.warn("[BalanceCheck] No move_id for '${invNo}' — skipping"); skipCount++; return }

        try {
            // ── READ PHASE (all SQL.myPool.eachRow here, outside any withTransaction) ──

            // Balance summary
            long lineCount = 0, draftCount = 0
            BigDecimal totalBalance = BigDecimal.ZERO
            SQL.myPool.eachRow("""
                SELECT COALESCE(SUM(balance),0)                               AS total_balance,
                       COUNT(*)                                                AS line_count,
                       COUNT(CASE WHEN parent_state='draft' THEN 1 END)       AS draft_count
                FROM account_move_line WHERE move_id=?
            """, [moveId]) { r ->
                totalBalance = safeBD(r['total_balance'])
                lineCount    = r['line_count']  as Long ?: 0L
                draftCount   = r['draft_count'] as Long ?: 0L
            }

            if (lineCount == 0) {
                log.warn("[BalanceCheck] No lines for move=${moveId} ('${invNo}') — skipping")
                skipCount++; return
            }
            if (totalBalance.abs() > balanceTolerance) {
                log.error("[BalanceCheck] UNBALANCED: '${invNo}' move=${moveId} SUM(balance)=${totalBalance}")
                failCount++; failedInvNos << invNo; return
            }
            if (draftCount == 0) {
                log.info("[BalanceCheck] Already posted: '${invNo}' move=${moveId}")
                okCount++; return
            }

            // Read move_type + invoice_date + partner name (for sign logic, due date, and display name)
            String moveType        = 'out_invoice'
            String invoiceDt       = null
            String partnerDispName = null
            SQL.myPool.eachRow("""
                SELECT am.move_type, am.invoice_date::text AS idate, rp.name AS partner_name
                FROM account_move am
                LEFT JOIN res_partner rp ON rp.id = am.partner_id
                WHERE am.id=? LIMIT 1
            """, [moveId]) { r ->
                moveType        = r['move_type']?.toString() ?: 'out_invoice'
                invoiceDt       = r['idate']?.toString()
                partnerDispName = r['partner_name']?.toString()
            }

            def payState = (moveType in ['out_invoice','in_invoice','out_refund','in_refund']) ? 'paid' : null

            // Compute amounts from lines (read-only)
            // For out_invoice / in_refund: product/tax lines have negative balance, payment_term positive
            // For in_invoice / out_refund: product/tax lines have positive balance, payment_term negative
            BigDecimal amtUntaxed = BigDecimal.ZERO
            BigDecimal amtTax     = BigDecimal.ZERO
            BigDecimal amtTotal   = BigDecimal.ZERO
            SQL.myPool.eachRow("""
                SELECT
                    COALESCE(ABS(SUM(CASE WHEN display_type='product'      THEN balance ELSE 0 END)), 0) AS untaxed,
                    COALESCE(ABS(SUM(CASE WHEN display_type='tax'           THEN balance ELSE 0 END)), 0) AS tax_amt,
                    COALESCE(ABS(SUM(CASE WHEN display_type='payment_term'  THEN balance ELSE 0 END)), 0) AS total
                FROM account_move_line WHERE move_id=?
            """, [moveId]) { r ->
                amtUntaxed = safeBD(r['untaxed'])
                amtTax     = safeBD(r['tax_amt'])
                amtTotal   = safeBD(r['total'])
            }
            // Fallback: if payment_term line balance is 0 (no term line), total = untaxed + tax
            if (amtTotal == BigDecimal.ZERO) amtTotal = amtUntaxed.add(amtTax)

            // Odoo list view reads _signed and _in_currency_signed columns, not plain amounts.
            // out_invoice / in_refund → positive; in_invoice / out_refund → negative
            def signMul = (moveType in ['out_invoice', 'in_refund']) ? BigDecimal.ONE : new BigDecimal('-1')
            def amtUntaxedSigned  = amtUntaxed.multiply(signMul)
            def amtTaxSigned      = amtTax.multiply(signMul)
            def amtTotalSigned    = amtTotal.multiply(signMul)
            // Residual = 0 because invoices are marked as paid (fully settled in Tally)
            def amtResidualSigned = BigDecimal.ZERO

            log.info("[BalanceCheck] Amounts for '${invNo}': untaxed=${amtUntaxed} tax=${amtTax} total=${amtTotal} type=${moveType}")

            // ── WRITE PHASE (only conn.prepareStatement inside withTransaction) ──
            SQL.myPool.withTransaction { conn ->
                // Promote draft lines to posted
                def lineUpPs = conn.prepareStatement(
                    "UPDATE account_move_line SET parent_state='posted' WHERE move_id=? AND parent_state='draft'"
                )
                lineUpPs.setLong(1, moveId)
                int lineUpd = lineUpPs.executeUpdate()
                lineUpPs.close()

                // Set amount_residual = 0 on payment_term line (invoice is paid → nothing outstanding)
                if (hasAmountResidual) {
                    def rSql = hasAmountResidualCurr
                        ? "UPDATE account_move_line SET amount_residual=0, amount_residual_currency=0 WHERE move_id=? AND display_type='payment_term'"
                        : "UPDATE account_move_line SET amount_residual=0 WHERE move_id=? AND display_type='payment_term'"
                    def rPs = conn.prepareStatement(rSql)
                    rPs.setLong(1, moveId)
                    rPs.executeUpdate()
                    rPs.close()
                }

                // UPDATE account_move — build SQL dynamically based on available columns
                // Always set plain amounts + all _signed/_in_currency_signed variants (used by Odoo list view)
                def amCols = [
                    'amount_untaxed=?', 'amount_total=?', 'amount_residual=?',
                    'amount_untaxed_signed=?', 'amount_tax_signed=?', 'amount_total_signed=?',
                    'amount_untaxed_in_currency_signed=?', 'amount_total_in_currency_signed=?',
                    'amount_residual_signed=?'
                ]
                def amVals = [
                    amtUntaxed, amtTotal, BigDecimal.ZERO,   // residual=0 → paid
                    amtUntaxedSigned, amtTaxSigned, amtTotalSigned,
                    amtUntaxedSigned, amtTotalSigned,
                    BigDecimal.ZERO                           // residual_signed=0 → paid
                ]
                if (hasAmountTax)    { amCols.add(0, 'amount_tax=?');    amVals.add(0, amtTax)    }
                if (hasPaymentState && payState) { amCols << 'payment_state=?'; amVals << payState }
                if (hasInvPartnerDisplayName && partnerDispName) {
                    amCols << 'invoice_partner_display_name=?'; amVals << partnerDispName
                }
                def moveUpPs = conn.prepareStatement(
                    "UPDATE account_move SET ${amCols.join(',')} WHERE id=?"
                )
                amVals.eachWithIndex { v, i ->
                    int pos = i + 1
                    if (v instanceof BigDecimal) moveUpPs.setBigDecimal(pos, v)
                    else                         moveUpPs.setString(pos, v.toString())
                }
                moveUpPs.setLong(amVals.size() + 1, moveId)
                moveUpPs.executeUpdate()
                moveUpPs.close()

                log.info("[BalanceCheck] POSTED: '${invNo}' move=${moveId} lines=${lineUpd} untaxed=${amtUntaxed} total=${amtTotal}")
            }

            okCount++

        } catch (Exception invEx) {
            log.error("[BalanceCheck] Error for '${invNo}' move=${moveId}: ${invEx.message}", invEx)
            failCount++
            failedInvNos << invNo
        }
    }

    log.info("[BalanceCheck] Done — ok:${okCount} fail:${failCount} skip:${skipCount}")
    if (failedInvNos) log.warn("[BalanceCheck] Failed invoices: ${failedInvNos.join(', ')}")

    ff = session.putAllAttributes(ff, [
        'balance.ok'  : okCount.toString(),
        'balance.fail': failCount.toString(),
        'balance.skip': skipCount.toString(),
        'batch.size'  : rows.size().toString()
    ])

    if (failCount > 0 && okCount == 0 && skipCount == 0) {
        ff = session.putAttribute(ff, 'error', "All ${failCount} invoices failed — see logs")
        session.transfer(ff, REL_FAILURE)
    } else {
        session.transfer(ff, REL_SUCCESS)
    }

} catch (Exception e) {
    log.error('[BalanceCheck] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// insert_account_move_batch.groovy  (NiFi 2.x — invoice batch, step 1 of 3)
//
// NiFi flow: TransformInvoice → SplitRecord(500/split, JSON array writer)
//              → [THIS] → insert_account_move_line_batch → balance_check_and_post
//
// Input:  JSON array — one row per invoice line item; multiple rows share same
//         'Invoice Number (Name)' for multi-line invoices.
// Action: Inserts ONE account_move header per unique Invoice Number (Name).
//         Caches 'invoice.move.<slug>' → move_id for downstream scripts.
// Output: Pass-through — same JSON forwarded unchanged to insert_account_move_line_batch.
//
// JSON keys from TransformInvoice_Custom output:
//   'Invoice Number (Name)', Date, CustomerNameId, CustomerAddressID,
//   CompanyName, PaymentTerm, Remarks, InvoiceTypes

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes  ?: [:]
def invDefaults  = customCfg.invoice_defaults ?: [:]
def invTypeMap   = customCfg.invoice_type_map ?: [:]

def invXidPfx  = xidPfx.invoice ?: 'cust_inv_'
def compXidPfx = xidPfx.company ?: 'cust_company_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(80)
    slug ?: 'unknown'
}
def getMoveType = { String rawType ->
    def t = rawType?.toLowerCase()?.trim() ?: ''
    return invTypeMap[t] ?: invTypeMap['__default__'] ?: 'out_invoice'
}
// Normalise any date representation to YYYY-MM-DD string (or null)
// Handles: ISO date, epoch-ms (13-digit), Unix seconds (10-digit), slash/dash formats.
// NiFi SplitRecord JsonRecordSetWriter serialises DATE schema columns as epoch-ms.
def toDateStr = { def v ->
    if (v == null) return null
    def s = v.toString().trim()
    if (!s || s == 'null' || s == '\\N') return null
    if (s =~ /^\d{4}-\d{2}-\d{2}/) return s.take(10)
    if (s ==~ /\d{13}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong())) }
        catch(ignored) {}
    }
    if (s ==~ /\d{10}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong() * 1000L)) }
        catch(ignored) {}
    }
    def m = s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())
    return null
}
def bindPs = { ps, List params ->
    params.eachWithIndex { v, i ->
        int pos = i + 1
        if (v == null)             ps.setObject(pos, null)
        else if (v instanceof Long) ps.setLong(pos, v)
        else                        ps.setString(pos, v.toString())
    }
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[AccountMoveBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
    def currId   = safeLong(cacheGet('lookup.currency_id_inr')) ?: safeLong(cacheGet('lookup.currency_id'))
    if (!currId) throw new Exception('currency_id not in cache — run bootstrap first')

    // ── 3. Schema probes (once per batch) ─────────────────────────────────────
    def amColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_move' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def hasInvoiceDate       = amColExists('invoice_date')
    def hasRef               = amColExists('ref')
    def hasNarration         = amColExists('narration')
    def hasPaymentState      = amColExists('payment_state')
    def hasAmountFields      = amColExists('amount_untaxed')
    def hasCommercialPartner = amColExists('commercial_partner_id')
    def hasPaymentTermId     = amColExists('invoice_payment_term_id')
    def hasAlwaysTaxExig     = amColExists('always_tax_exigible')
    log.info("[AccountMoveBatch] Schema: invoiceDate=${hasInvoiceDate} paymentState=${hasPaymentState} " +
             "amountFields=${hasAmountFields} commercialPartner=${hasCommercialPartner} paymentTermId=${hasPaymentTermId}")

    // ── 4. Resolve sale journal (once, cached) ────────────────────────────────
    Long jrnlId = safeLong(cacheGet('lookup.journal.sale'))
    if (!jrnlId) {
        for (String jn in (invDefaults.journal_name_fallbacks ?: ['Customer Invoices', 'Sales'])) {
            if (jrnlId) break
            SQL.myPool.eachRow(
                "SELECT id FROM account_journal WHERE company_id=? AND active=true AND name->>'en_US' ILIKE ? ORDER BY id LIMIT 1",
                [compId, jn]
            ) { r -> jrnlId = safeLong(r['id']) }
        }
        if (!jrnlId) {
            SQL.myPool.eachRow(
                "SELECT id FROM account_journal WHERE company_id=? AND active=true AND type='sale' ORDER BY id LIMIT 1",
                [compId]
            ) { r -> jrnlId = safeLong(r['id']) }
        }
        if (jrnlId) cacheSet('lookup.journal.sale', jrnlId.toString())
    }
    if (!jrnlId) throw new Exception("No sale journal found for company_id=${compId}")

    // ── 5. Collect unique invoices (first row per invNo = header data) ─────────
    def invoiceHeaderMap = [:]   // invNo → first row
    rows.each { row ->
        def invNo = nvl(row['Invoice Number (Name)'])
        if (invNo && !invoiceHeaderMap.containsKey(invNo)) invoiceHeaderMap[invNo] = row
    }
    log.info("[AccountMoveBatch] Unique invoices: ${invoiceHeaderMap.size()}")

    // ── 6. Partner pre-resolution (Phase 1, read-only) ───────────────────────
    def partnerIdMap = [:]  // invNo → Long partnerId

    invoiceHeaderMap.each { invNo, row ->
        def custNameId  = nvl(row['CustomerNameId'])
        def custAddrId  = nvl(row['CustomerAddressID'])
        def companyName = nvl(row['CompanyName'])
        Long partnerId  = null

        def persXidPfx  = customCfg.xid_prefixes?.person ?: 'cust_person_'
        def custNameSlug = custNameId ? slugify(custNameId) : null
        def custAddrSlug = custAddrId ? slugify(custAddrId) : null

        // 1. DistributedMapCache (fastest — set by contacts pipeline)
        // insert_res_partner stores: cust.nameid.<custNameId> and cust.personid.<rowId>
        if (custNameId)  partnerId = safeLong(cacheGet('cust.nameid.'   + custNameId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.personid.' + custAddrId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.addrid.'   + custAddrId))

        // 2. ir_model_data XID — must use slugify to match how insert_res_partner stored the XID
        if (!partnerId && custNameSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, compXidPfx + custNameSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && custAddrSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, persXidPfx + custAddrSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }

        // 3. Name exact match — prefer companies
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE name ILIKE ? AND active=true ORDER BY is_company DESC, id LIMIT 1",
                [companyName]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        // 4. Broader fallback: commercial_company_name or complete_name partial match
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE (commercial_company_name ILIKE ? OR complete_name ILIKE ?) AND active=true ORDER BY is_company DESC, id LIMIT 1",
                ["%${companyName}%", "%${companyName}%"]
            ) { r -> partnerId = safeLong(r['id']) }
        }

        if (partnerId) {
            partnerIdMap[invNo] = partnerId
        } else {
            log.warn("[AccountMoveBatch] Partner not resolved for '${invNo}' (custNameId=${custNameId} companyName=${companyName})")
        }
    }
    log.info("[AccountMoveBatch] Partners resolved: ${partnerIdMap.size()} / ${invoiceHeaderMap.size()}")

    // ── 6b. Resolve partner display names (invoice_partner_display_name for list view) ──
    def partnerNameMap = [:]  // partnerId → display name string
    partnerIdMap.values().toList().unique().each { Long pid ->
        SQL.myPool.eachRow('SELECT name FROM res_partner WHERE id=? LIMIT 1', [pid]) { r ->
            partnerNameMap[pid] = r['name']?.toString() ?: ''
        }
    }

    // ── 7. Payment term pre-resolution (Phase 1, read-only) ─────────────────
    def payTermIdMap = [:]  // termName → Long termId
    if (hasPaymentTermId) {
        rows.collect { nvl(it['PaymentTerm']) }.findAll { it }.unique().each { termName ->
            Long termId = safeLong(cacheGet('lookup.payterm.' + termName))
            if (!termId) {
                SQL.myPool.eachRow(
                    "SELECT id FROM account_payment_term WHERE active=true AND name->>'en_US' ILIKE ? LIMIT 1",
                    [termName]
                ) { r -> termId = safeLong(r['id']) }
                if (termId) cacheSet('lookup.payterm.' + termName, termId.toString())
            }
            if (termId) payTermIdMap[termName] = termId
        }
    }

    // ── 8. Build INSERT SQL for account_move ──────────────────────────────────
    def hasChecked               = amColExists('checked')
    def hasSequencePrefix        = amColExists('sequence_prefix')
    def hasSequenceNumber        = amColExists('sequence_number')
    def hasInvPartnerDisplayName = amColExists('invoice_partner_display_name')

    def mvCols = ['journal_id','company_id','currency_id','date','move_type',
                  'state','posted_before','auto_post',
                  'name','partner_id','create_uid','write_uid']
    def mvVals = ['?','?','?','?::date','?',
                  "'posted'",'true',"'no'",
                  '?','?','?','?']
    if (hasRef)                    { mvCols << 'ref';                          mvVals << '?'      }
    if (hasNarration)              { mvCols << 'narration';                    mvVals << '?'      }
    if (hasInvoiceDate)            { mvCols << 'invoice_date';                 mvVals << '?::date'}
    if (hasCommercialPartner)      { mvCols << 'commercial_partner_id';        mvVals << '?'      }
    if (hasPaymentTermId)          { mvCols << 'invoice_payment_term_id';      mvVals << '?'      }
    if (hasPaymentState)           { mvCols << 'payment_state';                mvVals << '?'      }
    if (hasInvPartnerDisplayName)  { mvCols << 'invoice_partner_display_name'; mvVals << '?'      }
    if (hasAmountFields)           { mvCols << 'amount_untaxed'; mvVals << '0'
                                     mvCols << 'amount_total';   mvVals << '0'
                                     mvCols << 'amount_residual'; mvVals << '0'                  }
    if (hasAlwaysTaxExig)          { mvCols << 'always_tax_exigible';          mvVals << 'false'  }
    if (hasChecked)                { mvCols << 'checked';                      mvVals << 'true'   }
    if (hasSequencePrefix)         { mvCols << 'sequence_prefix';              mvVals << "'INV/'" }
                                mvCols << 'create_date';             mvVals << 'NOW()'
                                mvCols << 'write_date';              mvVals << 'NOW()'
    def mvSql = "INSERT INTO account_move (${mvCols.join(',')}) VALUES (${mvVals.join(',')}) RETURNING id"

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: insert one account_move per unique invoice
    // ════════════════════════════════════════════════════════════════════════
    int written = 0, skipped = 0
    def xidBatch = []

    SQL.myPool.withTransaction { conn ->
        def mvPs = conn.prepareStatement(mvSql)

        def moveExistsInDb = { Long id ->
            def found = false
            SQL.myPool.eachRow('SELECT 1 FROM account_move WHERE id=? LIMIT 1', [id]) { found = true }
            return found
        }

        invoiceHeaderMap.each { invNo, row ->
            def invSlug  = slugify(invNo)
            def invXid   = invXidPfx + invSlug
            def cacheKey = 'invoice.move.' + invSlug
            def date     = toDateStr(row['Date'])
            if (!date) { log.warn("[AccountMoveBatch] No date for '${invNo}' — skipping"); skipped++; return }

            def rawType  = nvl(row['InvoiceTypes'])
            def moveType = getMoveType(rawType)
            def remarks  = nvl(row['Remarks'])
            def termName = nvl(row['PaymentTerm'])

            // Idempotency check
            Long moveId = null
            def cachedId = cacheGet(cacheKey)
            if (cachedId) {
                def mid = safeLong(cachedId)
                if (mid && moveExistsInDb(mid)) moveId = mid
                else cacheSet(cacheKey, 'CLEARED')
            }
            if (!moveId) {
                SQL.myPool.eachRow('SELECT res_id FROM ir_model_data WHERE module=? AND name=?', [module, invXid]) { r ->
                    moveId = safeLong(r['res_id'])
                }
                if (moveId && !moveExistsInDb(moveId)) {
                    SQL.myPool.execute('DELETE FROM ir_model_data WHERE module=? AND name=?', [module, invXid])
                    moveId = null
                }
            }

            if (!moveId) {
                Long partnerId = partnerIdMap[invNo]
                Long termId    = termName ? payTermIdMap[termName] : null
                def payState   = (moveType in ['out_invoice','in_invoice','out_refund','in_refund']) ? 'paid' : null

                def odooName = 'INV/' + invNo   // e.g. INV/2758/25-26

                def partnerDisplayName = partnerId ? (partnerNameMap[partnerId] ?: '') : null

                def params = [jrnlId, compId, currId, date, moveType,
                              odooName, partnerId, adminUid, adminUid] as List
                if (hasRef)                   params << invNo             // ref = original Tally number
                if (hasNarration)             params << remarks
                if (hasInvoiceDate)           params << date
                if (hasCommercialPartner)     params << partnerId
                if (hasPaymentTermId)         params << termId
                if (hasPaymentState)          params << payState
                if (hasInvPartnerDisplayName) params << partnerDisplayName

                mvPs.clearParameters()
                bindPs(mvPs, params)
                def rs = mvPs.executeQuery()
                rs.next(); moveId = rs.getLong(1); rs.close()
                xidBatch << [module, invXid, 'account.move', moveId]
                log.info("[AccountMoveBatch] INSERTED: '${invNo}' → move=${moveId} type=${moveType}")
            }

            cacheSet(cacheKey, moveId.toString())
            written++
        }

        mvPs.close()

        // Batch XID inserts (sorted for deadlock prevention)
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m, n, mdl, rid ->
                xidPs.setString(1, m); xidPs.setString(2, n)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try { xidPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.error("[AccountMoveBatch] XID batch failed — ${bue.message} | PG: ${pg?.getMessage()}")
                throw bue
            }
            xidPs.close()
        }

        log.info("[AccountMoveBatch] Committed — written:${written} skipped:${skipped} xids:${xidBatch.size()}")
    }

    ff = session.putAllAttributes(ff, [
        'move.count'   : written.toString(),
        'skipped.count': skipped.toString(),
        'batch.size'   : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[AccountMoveBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// TransformInvoice_Custom.groovy
// Full-file invoice CSV transformer.
// Each source row = one invoice line item; invoice header fields repeat across rows.
// Cleans data and normalizes dates. Output column names match what insert scripts read.
//
// NiFi flow:
//   TransformInvoice_Custom → SplitRecord → insert_account_move_custom
//   → insert_account_move_line_custom
//
// Input (Nevco transactional invoice data — column names may vary in case/spacing):
//   Invoice Number (Name), Date, CustomerNameId, CustomerAddressID, CompanyName,
//   PaymentTerm, Remarks, InvoiceTypes, StatusName,
//   ProductName, Code, Description, Quantity, Price, Discount, AfterDiscount,
//   Tax, Taxamount, Unit
//
// All output columns are ALWAYS present (even empty) — prevents SplitRecord column count errors.

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

def splitCsv = { String line ->
    def result = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') { inQ = !inQ }
        else if (c == (char)',' && !inQ) { result << sb.toString(); sb.setLength(0) }
        else { sb.append(c) }
    }
    result << sb.toString()
    return result
}

def escCsv = { String v ->
    // NiFi CSVReader: Escape Character = \
    // Quote empty fields as "" to prevent trailing-field drop.
    // Double-backslash inside quoted fields so NiFi reads literal \.
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : ''
}

def toDateStr = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    if (s =~ /^\d{4}-\d{2}-\d{2}$/) return s
    if (s =~ /^\d{8}$/) return "${s[0..3]}-${s[4..5]}-${s[6..7]}"
    def m = (s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/)
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())
    def m2 = (s =~ /^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/)
    if (m2) return String.format('%s-%02d-%02d', m2[0][3], m2[0][2].toInteger(), m2[0][1].toInteger())
    return s
}

try {
    // ── 1. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { is ->
        csvText = new String(is.bytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
    } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    if (lines.size() < 2) {
        log.warn('[TransformInvoice_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Resolve header indices ─────────────────────────────────────────────
    def rawHdrs = splitCsv(lines[0])
    def hdrIdx  = [:]
    rawHdrs.eachWithIndex { h, i -> def k = h?.trim()?.toLowerCase() ?: ''; if (k) hdrIdx[k] = i }

    def get           = { List cells, int idx -> idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx]) }
    def mappingsPath  = '/home/ubuntu/Raw_tally_data/mapping.json'
    def tableFields   = new JsonSlurper().parse(new File(mappingsPath)).tables?.invoice_custom?.fields ?: [:]
    if (!tableFields) {
        log.error("[TransformInvoice_Custom] mapping.json missing tables.invoice_custom.fields — update mapping.json on the server at: ${mappingsPath}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) return -1
        def aliases = []
        if (fDef.source_col) aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        for (String alias in aliases) { def k = alias.toLowerCase(); if (hdrIdx.containsKey(k)) return hdrIdx[k] }
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            def found = hdrIdx.find { hk, hv -> hk && (hk.contains(k) || k.contains(hk)) }
            if (found) return found.value
        }
        return -1
    }

    def invNoIdx     = resolveColIdx('invoice_number')
    def dateIdx      = resolveColIdx('Date')
    def cnIdx        = resolveColIdx('CustomerNameId')
    def caIdx        = resolveColIdx('CustomerAddressID')
    def compNmIdx    = resolveColIdx('CompanyName')
    def pmtIdx       = resolveColIdx('PaymentTerm')
    def remIdx       = resolveColIdx('Remarks')
    def invTypIdx    = resolveColIdx('InvoiceTypes')
    def statusIdx    = resolveColIdx('StatusName')
    def pnIdx        = resolveColIdx('ProductName')
    def codeIdx      = resolveColIdx('Code')
    def descIdx      = resolveColIdx('Description')
    def qtyIdx       = resolveColIdx('Quantity')
    def priceIdx     = resolveColIdx('Price')
    def discIdx      = resolveColIdx('Discount')
    def afterDiscIdx = resolveColIdx('AfterDiscount')
    def taxIdx       = resolveColIdx('Tax')
    def taxAmtIdx    = resolveColIdx('Taxamount')
    def unitIdx      = resolveColIdx('Unit')

    log.info("[TransformInvoice_Custom] invNo:${invNoIdx} date:${dateIdx} custNameId:${cnIdx} " +
             "code:${codeIdx} qty:${qtyIdx} price:${priceIdx}")

    if (invNoIdx < 0) {
        // Diagnostic: dump all header keys so we can see exactly what the CSV parser sees
        log.error("[TransformInvoice_Custom] Cannot find Invoice Number column — aborting. " +
                  "hdrIdx keys: ${hdrIdx.keySet().toList()} | " +
                  "invoice_number aliases: ${tableFields['invoice_number']?.source_cols}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Fixed output columns (names match insert_account_move_custom) ──────
    def COLS = [
        'Invoice Number (Name)', 'Date', 'CustomerNameId', 'CustomerAddressID',
        'CompanyName', 'PaymentTerm', 'Remarks', 'InvoiceTypes', 'StatusName',
        'ProductName', 'Code', 'Description', 'Quantity', 'Price',
        'Discount', 'AfterDiscount', 'Tax', 'Taxamount', 'Unit'
    ]

    def sb = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0

    // ── 4. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < lines.size(); i++) {
        def c = splitCsv(lines[i])

        def invNo = get(c, invNoIdx)
        if (!invNo) { skipped++; continue }
        // Skip stray header rows
        if (invNo.toLowerCase().contains('invoice number') || invNo.toLowerCase() == 'name') {
            skipped++; continue
        }

        def row = [
            invNo,
            toDateStr(get(c, dateIdx)),
            get(c, cnIdx), get(c, caIdx), get(c, compNmIdx),
            get(c, pmtIdx), get(c, remIdx), get(c, invTypIdx), get(c, statusIdx),
            get(c, pnIdx), get(c, codeIdx), get(c, descIdx),
            get(c, qtyIdx), get(c, priceIdx),
            get(c, discIdx), get(c, afterDiscIdx),
            get(c, taxIdx), get(c, taxAmtIdx), get(c, unitIdx)
        ]
        sb.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[TransformInvoice_Custom] No valid rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 5. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformInvoice_Custom] Done — ${written} rows, ${skipped} skipped")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformInvoice_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// insert_account_move_line_batch.groovy  (NiFi 2.x — invoice batch, step 2 of 3)
//
// NiFi flow: TransformInvoice → SplitRecord(500/split, JSON array writer)
//              → insert_account_move_batch
//              → [THIS] insert_account_move_line_batch
//              → balance_check_and_post
//
// Input:  JSON array — pass-through from step 1 (one row per invoice line item)
// Action: For each unique Invoice Number (Name) inserts account_move_line:
//           - 'product' line per input row
//           - 'tax'     line per unique non-zero tax (aggregated across rows)
//           - 'payment_term' line (AR/AP balance = subtotal + tax)
//         Rows inserted with parent_state='draft'; step 3 promotes to 'posted'.
// Output: Pass-through — same JSON forwarded unchanged to balance_check_and_post.
//
// Depends on cache keys written by step 1:
//   'invoice.move.<slug>'  → move_id

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]
def invTypeMap   = customCfg.invoice_type_map ?: [:]
def defAccs      = mappings.default_accounts  ?: [:]

def invXidPfx = xidPfx.invoice ?: 'cust_inv_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch(ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(80)
    slug ?: 'unknown'
}
def getMoveType = { String rawType ->
    def t = rawType?.toLowerCase()?.trim() ?: ''
    return invTypeMap[t] ?: invTypeMap['__default__'] ?: 'out_invoice'
}
// Debit/credit for income-side lines (product + tax lines)
// out_invoice / in_refund  → credit side
// in_invoice  / out_refund → debit side
def lineDebCred = { String mt, BigDecimal amt ->
    if (mt in ['out_invoice', 'in_refund']) return [BigDecimal.ZERO, amt, amt.negate()]
    return [amt, BigDecimal.ZERO, amt]
}
// Payment-term (AR/AP) line is opposite
def termDebCred = { String mt, BigDecimal amt ->
    if (mt in ['out_invoice', 'in_refund']) return [amt, BigDecimal.ZERO, amt]
    return [BigDecimal.ZERO, amt, amt.negate()]
}
def bindPs = { ps, List params ->
    params.eachWithIndex { v, i ->
        int pos = i + 1
        if (v == null)                    ps.setObject(pos, null)
        else if (v instanceof Long)       ps.setLong(pos, v)
        else if (v instanceof Integer)    ps.setInt(pos, v)
        else if (v instanceof BigDecimal) ps.setBigDecimal(pos, v)
        else                              ps.setString(pos, v.toString())
    }
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[AmlBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
    def currId   = safeLong(cacheGet('lookup.currency_id_inr')) ?: safeLong(cacheGet('lookup.currency_id'))
    if (!currId) throw new Exception('currency_id not in cache — run bootstrap first')

    // ── 3. Schema probes (account_move_line) ──────────────────────────────────
    def amlCol = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_move_line' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def hasQuantity       = amlCol('quantity')
    def hasPriceUnit      = amlCol('price_unit')
    def hasDiscount       = amlCol('discount')
    def hasPriceSubtotal  = amlCol('price_subtotal')
    def hasPriceTotal     = amlCol('price_total')
    def hasProductId      = amlCol('product_id')
    def hasProductUomId   = amlCol('product_uom_id')
    def hasTaxLineId      = amlCol('tax_line_id')
    def hasAmountCurrency = amlCol('amount_currency')
    def hasSequence       = amlCol('sequence')
    log.info("[AmlBatch] Schema: qty=${hasQuantity} priceUnit=${hasPriceUnit} disc=${hasDiscount} " +
             "priceSubtotal=${hasPriceSubtotal} priceTotal=${hasPriceTotal} taxLineId=${hasTaxLineId} " +
             "productId=${hasProductId} amtCurr=${hasAmountCurrency} seq=${hasSequence}")

    // Schema probe for account_tax_repartition_line to know how to query tax accounts
    def atrHasInvoiceTaxId = false
    SQL.myPool.eachRow(
        "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_tax_repartition_line' AND column_name='invoice_tax_id' LIMIT 1"
    ) { atrHasInvoiceTaxId = true }

    // Probe account_tax column types — in Odoo 17, translated fields (name, description)
    // are stored as JSONB; ILIKE directly on JSONB raises "operator does not exist: jsonb ~~* unknown"
    def taxNameIsJsonb = false
    def taxDescIsJsonb = false
    SQL.myPool.eachRow(
        "SELECT column_name, data_type FROM information_schema.columns WHERE table_schema='public' AND table_name='account_tax' AND column_name IN ('name','description')"
    ) { r ->
        if (r['column_name'] == 'name'        && r['data_type'] == 'jsonb') taxNameIsJsonb = true
        if (r['column_name'] == 'description' && r['data_type'] == 'jsonb') taxDescIsJsonb = true
    }
    log.info("[AmlBatch] account_tax column types: nameJsonb=${taxNameIsJsonb} descJsonb=${taxDescIsJsonb}")

    // ── 4. Account pre-resolution (cached, read-only) ─────────────────────────
    def resolveAccSql = { String ck, String sql2, List p ->
        Long id = safeLong(cacheGet(ck))
        if (!id) {
            SQL.myPool.eachRow(sql2, p) { r -> id = safeLong(r['id']) }
            if (id) cacheSet(ck, id.toString())
        }
        return id
    }

    // Probe whether account_account has a 'code' column (absent in some Odoo builds)
    def aaHasCode = false
    SQL.myPool.eachRow(
        "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_account' AND column_name='code' LIMIT 1"
    ) { aaHasCode = true }

    def salesAccCode = defAccs.sales_product_account?.toString()   ?: '41001'
    def purchAccCode = defAccs.purchase_product_account?.toString() ?: '52001'

    Long salesAccId
    Long purchAccId
    if (aaHasCode) {
        salesAccId = resolveAccSql(
            'lookup.account.sales_income.' + salesAccCode,
            "SELECT id FROM account_account WHERE code=? AND active=true ORDER BY id LIMIT 1",
            [salesAccCode])
        purchAccId = resolveAccSql(
            'lookup.account.purchase_expense.' + purchAccCode,
            "SELECT id FROM account_account WHERE code=? AND active=true ORDER BY id LIMIT 1",
            [purchAccCode])
    } else {
        log.warn("[AmlBatch] account_account.code column not found — falling back to account_type lookup")
        salesAccId = resolveAccSql(
            'lookup.account.income.type',
            "SELECT id FROM account_account WHERE account_type IN ('income','income_other') AND active=true ORDER BY id LIMIT 1",
            [])
        purchAccId = resolveAccSql(
            'lookup.account.expense.type',
            "SELECT id FROM account_account WHERE account_type IN ('expense','expense_direct_cost') AND active=true ORDER BY id LIMIT 1",
            [])
    }
    Long arAccId = resolveAccSql(
        'lookup.account.asset_receivable',
        "SELECT id FROM account_account WHERE account_type='asset_receivable' AND active=true ORDER BY id LIMIT 1",
        [])
    Long apAccId = resolveAccSql(
        'lookup.account.liability_payable',
        "SELECT id FROM account_account WHERE account_type='liability_payable' AND active=true ORDER BY id LIMIT 1",
        [])

    if (!arAccId) throw new Exception('asset_receivable account not found')
    if (!apAccId) throw new Exception('liability_payable account not found')
    log.info("[AmlBatch] Accounts: sales=${salesAccId} purch=${purchAccId} ar=${arAccId} ap=${apAccId} (codeCol=${aaHasCode})")

    // ── 5. Collect unique invoices (invNo → [rows]) ───────────────────────────
    def invoiceRowsMap = [:]
    rows.each { row ->
        def invNo = nvl(row['Invoice Number (Name)'])
        if (!invNo) return
        if (!invoiceRowsMap.containsKey(invNo)) invoiceRowsMap[invNo] = []
        invoiceRowsMap[invNo] << row
    }
    log.info("[AmlBatch] Unique invoices: ${invoiceRowsMap.size()}")

    // ── 6. Pre-fetch move headers from DB ─────────────────────────────────────
    def moveHeaderMap = [:]  // invNo → [moveId, jrnlId, date, partnerId, moveType]

    invoiceRowsMap.each { invNo, invRows ->
        def slug  = slugify(invNo)
        Long moveId = safeLong(cacheGet('invoice.move.' + slug))
        if (!moveId) {
            SQL.myPool.eachRow(
                'SELECT res_id FROM ir_model_data WHERE module=? AND name=? LIMIT 1',
                [module, invXidPfx + slug]
            ) { r -> moveId = safeLong(r['res_id']) }
        }
        if (!moveId) { log.warn("[AmlBatch] No move_id for '${invNo}' — will skip"); return }

        def hdr = [moveId: moveId]
        SQL.myPool.eachRow(
            'SELECT journal_id, date, partner_id, move_type FROM account_move WHERE id=? LIMIT 1',
            [moveId]
        ) { r ->
            hdr.jrnlId    = safeLong(r['journal_id'])
            hdr.date      = r['date']?.toString()?.take(10)
            hdr.partnerId = safeLong(r['partner_id'])
            hdr.moveType  = r['move_type']?.toString() ?: 'out_invoice'
        }
        if (hdr.jrnlId) moveHeaderMap[invNo] = hdr
        else log.warn("[AmlBatch] account_move id=${moveId} not found for '${invNo}'")
    }
    log.info("[AmlBatch] Move headers resolved: ${moveHeaderMap.size()} / ${invoiceRowsMap.size()}")

    // ── 7. Tax pre-resolution (taxName → {taxId, invAccId, refundAccId}) ──────
    def taxMap = [:]  // taxName → [taxId: Long, invAccId: Long, refAccId: Long]

    // Build tax lookup expressions based on column types probed above
    def taxNameExpr = taxNameIsJsonb ? "name->>'en_US'" : 'name'
    def taxDescExpr = taxDescIsJsonb ? "description->>'en_US'" : 'description'

    rows.collect { nvl(it['Tax']) }.findAll { it }.unique().each { taxName ->
        def ck = 'lookup.tax.id.' + taxName
        Long taxId = safeLong(cacheGet(ck))
        if (!taxId) {
            // 1. Name ILIKE (e.g. "18% IGST S" matches "18% IGST S")
            SQL.myPool.eachRow(
                "SELECT id FROM account_tax WHERE company_id=? AND active=true AND ${taxNameExpr} ILIKE ? ORDER BY id LIMIT 1",
                [compId, taxName]
            ) { r -> taxId = safeLong(r['id']) }
            // 2. Description ILIKE
            if (!taxId) {
                SQL.myPool.eachRow(
                    "SELECT id FROM account_tax WHERE company_id=? AND active=true AND ${taxDescExpr} ILIKE ? ORDER BY id LIMIT 1",
                    [compId, taxName]
                ) { r -> taxId = safeLong(r['id']) }
            }
            // 3. Numeric rate fallback: Tally exports tax as "18.0", "28.0" etc.
            //    Match by amount column, prefer percent type, sale use, lowest id
            if (!taxId) {
                try {
                    def taxRate = new BigDecimal(taxName.toString().trim())
                    SQL.myPool.eachRow("""
                        SELECT id FROM account_tax
                        WHERE company_id=? AND active=true AND amount=?
                          AND amount_type='percent'
                        ORDER BY CASE WHEN type_tax_use='sale' THEN 0
                                      WHEN type_tax_use='none' THEN 1
                                      ELSE 2 END, id LIMIT 1
                    """, [compId, taxRate]) { r -> taxId = safeLong(r['id']) }
                } catch(ignored) {}
            }
            if (taxId) cacheSet(ck, taxId.toString())
        }
        if (!taxId) { log.warn("[AmlBatch] Tax not found: '${taxName}'"); return }

        Long invAccId  = safeLong(cacheGet('lookup.tax.acc.inv.' + taxId))
        Long refAccId  = safeLong(cacheGet('lookup.tax.acc.ref.' + taxId))

        if (!invAccId) {
            if (atrHasInvoiceTaxId) {
                SQL.myPool.eachRow("""
                    SELECT aa.id FROM account_tax_repartition_line atrl
                    JOIN account_account aa ON aa.id = atrl.account_id
                    WHERE atrl.invoice_tax_id=? AND atrl.repartition_type='tax' LIMIT 1
                """, [taxId]) { r -> invAccId = safeLong(r['id']) }
            } else {
                SQL.myPool.eachRow("""
                    SELECT aa.id FROM account_tax_repartition_line atrl
                    JOIN account_account aa ON aa.id = atrl.account_id
                    WHERE atrl.tax_id=? AND atrl.repartition_type='tax'
                    AND atrl.document_type='invoice' LIMIT 1
                """, [taxId]) { r -> invAccId = safeLong(r['id']) }
            }
            if (invAccId) cacheSet('lookup.tax.acc.inv.' + taxId, invAccId.toString())
        }
        if (!refAccId) {
            if (atrHasInvoiceTaxId) {
                SQL.myPool.eachRow("""
                    SELECT aa.id FROM account_tax_repartition_line atrl
                    JOIN account_account aa ON aa.id = atrl.account_id
                    WHERE atrl.refund_tax_id=? AND atrl.repartition_type='tax' LIMIT 1
                """, [taxId]) { r -> refAccId = safeLong(r['id']) }
            } else {
                SQL.myPool.eachRow("""
                    SELECT aa.id FROM account_tax_repartition_line atrl
                    JOIN account_account aa ON aa.id = atrl.account_id
                    WHERE atrl.tax_id=? AND atrl.repartition_type='tax'
                    AND atrl.document_type='credit_note' LIMIT 1
                """, [taxId]) { r -> refAccId = safeLong(r['id']) }
            }
            if (refAccId) cacheSet('lookup.tax.acc.ref.' + taxId, refAccId.toString())
        }
        taxMap[taxName] = [
            taxId    : taxId,
            invAccId : invAccId ?: salesAccId,
            refAccId : refAccId ?: (invAccId ?: salesAccId)
        ]
    }

    // ── 8. Probe tax_rel table existence (Phase 1 — must NOT be inside withTransaction) ──
    // Groovy's Sql.withTransaction reuses the transactional connection for all SQL.myPool.*
    // calls within the closure, so any SQL.myPool.eachRow inside the transaction would run
    // on the aborted connection if a prior statement fails.
    def relTableExists = false
    SQL.myPool.eachRow(
        "SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='account_move_line_account_tax_rel' LIMIT 1"
    ) { relTableExists = true }
    log.info("[AmlBatch] tax_rel table exists: ${relTableExists}")

    // ── 9. Build INSERT SQLs ──────────────────────────────────────────────────
    // ── 8a. Product line SQL ──────────────────────────────────────────────────
    def prodCols = ['move_id','journal_id','company_id','company_currency_id','currency_id',
                    'account_id','partner_id','name','date','debit','credit','balance',
                    'display_type','parent_state','create_uid','write_uid']
    def prodVals = ['?','?','?','?','?', '?','?','?','?::date','?','?','?', "'product'","'draft'",'?','?']
    if (hasQuantity)      { prodCols << 'quantity';       prodVals << '?' }
    if (hasPriceUnit)     { prodCols << 'price_unit';     prodVals << '?' }
    if (hasDiscount)      { prodCols << 'discount';       prodVals << '?' }
    if (hasPriceSubtotal) { prodCols << 'price_subtotal'; prodVals << '?' }
    if (hasPriceTotal)    { prodCols << 'price_total';    prodVals << '?' }
    if (hasProductId)     { prodCols << 'product_id';     prodVals << '?' }
    if (hasProductUomId)  { prodCols << 'product_uom_id'; prodVals << '?' }
    if (hasAmountCurrency){ prodCols << 'amount_currency'; prodVals << '?' }
    if (hasSequence)      { prodCols << 'sequence';       prodVals << '?' }
    prodCols << 'create_date'; prodVals << 'NOW()'
    prodCols << 'write_date';  prodVals << 'NOW()'
    def prodSql = "INSERT INTO account_move_line (${prodCols.join(',')}) VALUES (${prodVals.join(',')}) RETURNING id"

    // ── 8b. Tax line SQL ──────────────────────────────────────────────────────
    def taxCols = ['move_id','journal_id','company_id','company_currency_id','currency_id',
                   'account_id','partner_id','name','date','debit','credit','balance',
                   'display_type','parent_state','create_uid','write_uid']
    def taxVals = ['?','?','?','?','?', '?','?','?','?::date','?','?','?', "'tax'","'draft'",'?','?']
    if (hasTaxLineId)     { taxCols << 'tax_line_id';    taxVals << '?' }
    if (hasAmountCurrency){ taxCols << 'amount_currency'; taxVals << '?' }
    if (hasSequence)      { taxCols << 'sequence';       taxVals << '?' }
    taxCols << 'create_date'; taxVals << 'NOW()'
    taxCols << 'write_date';  taxVals << 'NOW()'
    def taxLineSql = "INSERT INTO account_move_line (${taxCols.join(',')}) VALUES (${taxVals.join(',')}) RETURNING id"

    // ── 8c. Payment-term (AR/AP) line SQL ─────────────────────────────────────
    def termCols = ['move_id','journal_id','company_id','company_currency_id','currency_id',
                    'account_id','partner_id','name','date','debit','credit','balance',
                    'display_type','parent_state','create_uid','write_uid']
    def termVals = ['?','?','?','?','?', '?','?','?','?::date','?','?','?', "'payment_term'","'draft'",'?','?']
    if (hasAmountCurrency){ termCols << 'amount_currency'; termVals << '?' }
    if (hasSequence)      { termCols << 'sequence';       termVals << '?' }
    termCols << 'create_date'; termVals << 'NOW()'
    termCols << 'write_date';  termVals << 'NOW()'
    def termSql = "INSERT INTO account_move_line (${termCols.join(',')}) VALUES (${termVals.join(',')}) RETURNING id"

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: insert lines for all invoices in this batch
    // ════════════════════════════════════════════════════════════════════════
    int written = 0, skipped = 0, linesInserted = 0
    def taxRelBatch = []  // [lineId, taxId] pairs for M2M

    SQL.myPool.withTransaction { conn ->
        def prodPs = conn.prepareStatement(prodSql)
        def taxPs  = conn.prepareStatement(taxLineSql)
        def termPs = conn.prepareStatement(termSql)

        moveHeaderMap.each { invNo, hdr ->
            Long moveId   = hdr.moveId
            Long jrnlId   = hdr.jrnlId
            String date   = hdr.date
            Long partnerId = hdr.partnerId
            String moveType = hdr.moveType

            // Idempotency: if lines already exist for this move, skip
            def hasLines = false
            def chkPs = conn.prepareStatement('SELECT 1 FROM account_move_line WHERE move_id=? LIMIT 1')
            chkPs.setLong(1, moveId)
            def chkRs = chkPs.executeQuery()
            if (chkRs.next()) hasLines = true
            chkRs.close(); chkPs.close()
            if (hasLines) { log.info("[AmlBatch] Lines already exist for move=${moveId} ('${invNo}') — skipping"); skipped++; return }

            def invRows = invoiceRowsMap[invNo] ?: []

            // Choose income/expense account based on move type
            Long productAccId = (moveType in ['out_invoice', 'out_refund']) ? salesAccId : purchAccId
            Long counterAccId = (moveType in ['out_invoice', 'in_refund'])  ? arAccId    : apAccId

            // Aggregate amounts
            BigDecimal subtotal = BigDecimal.ZERO
            def taxAggMap = [:]  // taxName → BigDecimal amount

            int seqNum = 1

            // ── Insert product lines ──────────────────────────────────────────
            invRows.each { row ->
                def rawName   = nvl(row['ProductName']) ?: nvl(row['Description']) ?: invNo
                def rawCode   = nvl(row['Code'])
                def qty       = safeBD(row['Quantity'])
                def price     = safeBD(row['Price'])
                def disc      = safeBD(row['Discount'])
                def afterDisc = safeBD(row['AfterDiscount'])
                def taxName   = nvl(row['Tax'])
                def taxAmt    = safeBD(row['Taxamount'])

                // Compute line amount
                BigDecimal lineAmt
                if (afterDisc > BigDecimal.ZERO) {
                    lineAmt = afterDisc
                } else if (qty > BigDecimal.ZERO && price > BigDecimal.ZERO) {
                    lineAmt = qty.multiply(price)
                    if (disc > BigDecimal.ZERO) lineAmt = lineAmt.multiply(BigDecimal.ONE - disc.divide(new BigDecimal('100'), 6, java.math.RoundingMode.HALF_UP))
                } else {
                    lineAmt = BigDecimal.ZERO
                }
                lineAmt = lineAmt.setScale(2, java.math.RoundingMode.HALF_UP)
                subtotal = subtotal.add(lineAmt)

                // Aggregate tax by name
                if (taxName && taxAmt > BigDecimal.ZERO) {
                    taxAggMap[taxName] = (taxAggMap[taxName] ?: BigDecimal.ZERO).add(taxAmt)
                }

                def (dbt, crd, bal) = lineDebCred(moveType, lineAmt)

                // Resolve product_id from cache
                Long prodId = null
                if (hasProductId) {
                    if (rawCode) prodId = safeLong(cacheGet('product.code.' + rawCode))
                    if (!prodId && rawName) prodId = safeLong(cacheGet('product.' + rawName))
                }

                def params = [moveId, jrnlId, compId, currId, currId,
                              productAccId, partnerId, rawName, date,
                              dbt, crd, bal,
                              adminUid, adminUid] as List
                if (hasQuantity)      params << qty
                if (hasPriceUnit)     params << price
                if (hasDiscount)      params << disc
                if (hasPriceSubtotal) params << lineAmt
                if (hasPriceTotal)    params << (lineAmt.add(taxAmt.setScale(2, java.math.RoundingMode.HALF_UP)))
                if (hasProductId)     params << prodId
                if (hasProductUomId)  params << null   // UoM not resolved here
                if (hasAmountCurrency) params << bal
                if (hasSequence)      params << seqNum

                prodPs.clearParameters()
                bindPs(prodPs, params)
                def rs = prodPs.executeQuery()
                rs.next()
                Long lineId = rs.getLong(1)
                rs.close()
                linesInserted++
                seqNum++

                // Collect M2M tax rel
                if (taxName && taxMap[taxName]?.taxId) {
                    taxRelBatch << [lineId, taxMap[taxName].taxId]
                }
            }

            // ── Insert tax lines (one per unique non-zero tax) ────────────────
            def isRefund = moveType in ['out_refund', 'in_refund']
            taxAggMap.each { taxName, taxTotalAmt ->
                taxTotalAmt = taxTotalAmt.setScale(2, java.math.RoundingMode.HALF_UP)
                if (taxTotalAmt <= BigDecimal.ZERO) return

                def taxInfo  = taxMap[taxName]
                Long taxAccId = taxInfo ? (isRefund ? taxInfo.refAccId : taxInfo.invAccId) : salesAccId
                Long taxId    = taxInfo?.taxId

                def (dbt, crd, bal) = lineDebCred(moveType, taxTotalAmt)

                def params = [moveId, jrnlId, compId, currId, currId,
                              taxAccId, partnerId, taxName, date,
                              dbt, crd, bal,
                              adminUid, adminUid] as List
                if (hasTaxLineId)     params << taxId
                if (hasAmountCurrency) params << bal
                if (hasSequence)      params << seqNum

                taxPs.clearParameters()
                bindPs(taxPs, params)
                def rs = taxPs.executeQuery()
                rs.next()
                rs.close()
                linesInserted++
                seqNum++
            }

            // ── Insert payment_term (AR/AP) line ──────────────────────────────
            BigDecimal taxTotal  = taxAggMap.values().inject(BigDecimal.ZERO) { acc, v -> acc.add(v) }
                                            .setScale(2, java.math.RoundingMode.HALF_UP)
            BigDecimal moveTotal = subtotal.add(taxTotal).setScale(2, java.math.RoundingMode.HALF_UP)

            def (dbt, crd, bal) = termDebCred(moveType, moveTotal)

            def params = [moveId, jrnlId, compId, currId, currId,
                          counterAccId, partnerId, invNo, date,
                          dbt, crd, bal,
                          adminUid, adminUid] as List
            if (hasAmountCurrency) params << bal
            if (hasSequence)      params << seqNum

            termPs.clearParameters()
            bindPs(termPs, params)
            def rs = termPs.executeQuery()
            rs.next()
            rs.close()
            linesInserted++

            // ── UPDATE account_move amount fields ─────────────────────────────
            conn.prepareStatement(
                'UPDATE account_move SET amount_untaxed=?, amount_total=?, amount_residual=? WHERE id=?'
            ).with { upPs ->
                upPs.setBigDecimal(1, subtotal)
                upPs.setBigDecimal(2, moveTotal)
                upPs.setBigDecimal(3, moveTotal)
                upPs.setLong(4, moveId)
                upPs.executeUpdate()
                upPs.close()
            }

            log.info("[AmlBatch] INSERTED lines for '${invNo}' move=${moveId}: rows=${invRows.size()} taxes=${taxAggMap.size()} subtotal=${subtotal} total=${moveTotal}")
            written++
        }

        prodPs.close()
        taxPs.close()
        termPs.close()

        // ── Batch M2M tax_rel inserts ─────────────────────────────────────────
        if (taxRelBatch && relTableExists) {
            def relPs = conn.prepareStatement(
                'INSERT INTO account_move_line_account_tax_rel (account_move_line_id, account_tax_id) VALUES (?,?) ON CONFLICT DO NOTHING'
            )
            taxRelBatch.each { lId, tId ->
                relPs.setLong(1, lId)
                relPs.setLong(2, tId)
                relPs.addBatch()
            }
            try { relPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.warn("[AmlBatch] tax_rel batch warn — ${bue.message} | PG: ${pg?.getMessage()}")
            }
            relPs.close()
            log.info("[AmlBatch] tax_rel rows inserted: ${taxRelBatch.size()}")
        }

        log.info("[AmlBatch] Committed — invoices written:${written} skipped:${skipped} lines:${linesInserted}")
    }

    ff = session.putAllAttributes(ff, [
        'aml.invoices.written': written.toString(),
        'aml.invoices.skipped': skipped.toString(),
        'aml.lines.inserted'  : linesInserted.toString(),
        'batch.size'          : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[AmlBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// insert_l10n_in_pan_entity_batch.groovy  — Step 2 of 4, contact batch pipeline
//
// NiFi flow:
//   insert_res_partner_category_batch
//     → [THIS] insert_l10n_in_pan_entity_batch
//     → insert_res_partner_batch → insert_partner_category_rel_batch
//
// Input:  JSON array (up to 500 records; passed through from step 1)
// Action: Deduplicates valid PAN numbers, inserts missing l10n_in_pan_entity rows.
//         Populates cache key "lookup.pan_entity.<PAN>" for insert_res_partner_batch.
// Output: Pass-through — same JSON forwarded unchanged to insert_res_partner_batch.
//
// PAN validation: 5 alpha + 4 digits + 1 alpha (10 chars), e.g. ABCDE1234F
//
// Connection pattern: same as step 1 — SQL.myPool.withTransaction { conn -> } with
// pg_advisory_xact_lock(2, ...) so lock + check + insert share ONE JDBC connection
// and the lock auto-releases when the transaction commits.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def safeLong = { def v ->
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

def validPan = { def v ->
    def s = nvl(v)?.replaceAll(/\s+/, '')?.toUpperCase()
    (s && s.length() == 10 && s ==~ /^[A-Z]{5}[0-9]{4}[A-Z]$/) ? s : null
}

def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()

try {
    // ── 1. Read batch ─────────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[PanEntityBatch] Batch size: ${rows.size()}")

    // ── 2. Check if table exists (simple read, no transaction needed) ─────────
    boolean panTableExists = false
    try {
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.tables WHERE table_name='l10n_in_pan_entity' LIMIT 1"
        ) { panTableExists = true }
    } catch (Exception probe) {
        log.warn("[PanEntityBatch] Could not probe l10n_in_pan_entity: ${probe.message}")
    }

    if (!panTableExists) {
        log.info('[PanEntityBatch] l10n_in_pan_entity table not found — skipping, passing through')
        ff = session.putAttribute(ff, 'pan.skipped', 'table_not_found')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 3. Deduplicate valid PANs in this batch ───────────────────────────────
    def uniquePans = rows.collect { r -> validPan(r['l10n_in_pan']) }.findAll { it }.unique()
    log.info("[PanEntityBatch] Unique valid PANs: ${uniquePans.size()}")

    if (!uniquePans) {
        log.info('[PanEntityBatch] No valid PAN numbers in batch — passing through')
        ff = session.putAllAttributes(ff, [
            'pan.inserted': '0',
            'pan.reused'  : '0',
            'batch.size'  : rows.size().toString()
        ])
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 4. Resolve / insert PAN entities ─────────────────────────────────────
    int inserted = 0, reused = 0

    uniquePans.each { panStr ->
        def cacheKey = 'lookup.pan_entity.' + panStr
        Long entityId = safeLong(cacheGet(cacheKey))

        // Fast path — verify cached id still exists in DB
        if (entityId) {
            boolean ok = false
            SQL.myPool.eachRow("SELECT 1 FROM l10n_in_pan_entity WHERE id=? LIMIT 1", [entityId]) { ok = true }
            if (ok) { reused++; return }
            cacheSet(cacheKey, 'CLEARED')
            entityId = null
        }

        // Slow path — pg_advisory_xact_lock inside withTransaction.
        // Lock namespace 2 (namespace 1 is used by category step).
        def lockKey = (panStr.hashCode() & 0x7FFFFFFF) as int

        SQL.myPool.withTransaction { conn ->
            // Acquire transaction-level advisory lock
            def lockPs = conn.prepareStatement('SELECT pg_advisory_xact_lock(2, ?)')
            lockPs.setInt(1, lockKey)
            lockPs.execute()
            lockPs.close()

            // Re-check cache after acquiring lock
            entityId = safeLong(cacheGet(cacheKey))
            if (entityId) {
                def ps = conn.prepareStatement('SELECT 1 FROM l10n_in_pan_entity WHERE id=? LIMIT 1')
                ps.setLong(1, entityId)
                def rs = ps.executeQuery()
                if (!rs.next()) entityId = null
                rs.close(); ps.close()
            }

            // Check DB directly
            if (!entityId) {
                def ps = conn.prepareStatement('SELECT id FROM l10n_in_pan_entity WHERE name=? LIMIT 1')
                ps.setString(1, panStr)
                def rs = ps.executeQuery()
                if (rs.next()) entityId = rs.getLong('id')
                rs.close(); ps.close()
            }

            // Insert new PAN entity
            if (!entityId) {
                // 4th character (index 3) encodes entity type:
                // P=individual, C=company, H=HUF, F=firm, A=AOP, T=trust, etc.
                def panType = panStr.charAt(3).toString().toLowerCase()
                def insPs = conn.prepareStatement(
                    "INSERT INTO l10n_in_pan_entity (name,type,tds_deduction,create_uid,write_uid,create_date,write_date) " +
                    "VALUES (?,?,'normal',?,?,NOW(),NOW()) RETURNING id"
                )
                insPs.setString(1, panStr)
                insPs.setString(2, panType)
                insPs.setLong(3, adminUid)
                insPs.setLong(4, adminUid)
                def rs = insPs.executeQuery()
                if (rs.next()) entityId = rs.getLong(1)
                rs.close(); insPs.close()

                if (entityId) {
                    inserted++
                    log.info("[PanEntityBatch] INSERTED: ${panStr} (type=${panStr.charAt(3)}) → id=${entityId}")
                } else {
                    log.warn("[PanEntityBatch] INSERT returned no id for PAN: ${panStr}")
                }
            } else {
                reused++
            }

            if (entityId) cacheSet(cacheKey, entityId.toString())

            // Transaction commits here; pg_advisory_xact_lock auto-released
        }
    }

    log.info("[PanEntityBatch] Completed — pans=${uniquePans.size()} inserted=${inserted} reused=${reused}")

    ff = session.putAllAttributes(ff, [
        'pan.inserted': inserted.toString(),
        'pan.reused'  : reused.toString(),
        'batch.size'  : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[PanEntityBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    session.transfer(ff, REL_FAILURE)
}

// TransformContact_Custom.groovy
// Full-file custom contact CSV/XLSX transformer for Nevco contact data.
// Reads raw Excel/CSV, validates and normalizes fields, outputs clean NiFi CSV.
//
// NiFi flow:
//   [GetFile/FetchS3/etc.] → TransformContact_Custom → SplitRecord
//       → insert_res_partner_category → Step4C_LoadCustomContacts
//       → insert_l10n_in_pan_entity   → insert_partner_category_rel
//
// Source columns (case-insensitive; aliases driven by mapping.json tables.contact_custom.fields):
//   id, PartyType, BusinessType, CustomerDetails, Address, Date, Time, GSTNo, LandLine,
//   COMPANY Email, Country, State, City, Type, PersonName, PersonMobile, PersonEmail,
//   Department, Designation, customernameid, customerAddressid, BranchName, PanNo, Pincode
//
// Output columns (28 fixed — do NOT change without updating downstream insert scripts):
//   id, customernameid, customerAddressid,
//   name, vat, email, phone,
//   street, city, state_id/name, country_id/name, zip,
//   type, is_company, customer_rank, supplier_rank, lang, tz,
//   l10n_in_pan, l10n_in_gst_treatment,
//   tally_group, business_type, branch_name,
//   person_name, person_mobile, person_email, person_designation, person_department
//
// All output columns always present (even empty) — prevents SplitRecord column count errors.
// XLSX detected via ZIP magic bytes (PK\x03\x04); requires Apache POI on NiFi classpath.

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

// ── Helpers ────────────────────────────────────────────────────────────────────

def nvl = { def v ->
    def s = v?.toString()?.trim()
    if (!s) return ''
    // Reject Tally/MySQL null markers (\N, \\N) and SQL-style nulls
    if (s == '\\N' || s == '\\\\N' || s.equalsIgnoreCase('null') ||
        s.equalsIgnoreCase('none') || s == 'N/A' || s == 'NA') return ''
    return s
}

def escCsv = { String v ->
    // NiFi CSVReader (Escape Character = \): empty→"", backslash→\\, embedded newlines→space
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def cleanId = { String raw ->
    (raw ?: '').trim().replaceAll(/\.0+$/, '')
}

def cleanPhone = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    // Reject null markers — belt-and-suspenders in case nvl was bypassed
    if (s == '\\N' || s == '\\\\N' || s.equalsIgnoreCase('null') ||
        s.equalsIgnoreCase('none') || s == 'N/A' || s == 'NA') return ''
    s = s.replaceAll(/[,\s]/, '')
    if (!s) return ''
    // Handle scientific notation (e.g. 9.885304941E9 for phone numbers stored as Excel numbers)
    if (s =~ /^[\d.]+[Ee][+\-]?\d+$/) {
        try {
            def bd = new BigDecimal(s)
            return bd.toPlainString().replaceAll(/\.0+$/, '')
        } catch (ignored) { return s }
    }
    return s.replaceAll(/\.0+$/, '')
}

def validateGstin = { String raw ->
    if (!raw) return ''
    def g = raw.replaceAll(/\s+/, '').toUpperCase().replace('-', '')
    // Return normalized form only if 15 chars (full structural validation done in insert script)
    return (g.length() == 15) ? g : ''
}

def validatePan = { String raw ->
    if (!raw) return ''
    raw.replaceAll(/\s+/, '').toUpperCase()
}

def computeGstTreatment = { String gstin, String country ->
    def GSTIN_RE = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z][1-9A-Z]Z[0-9A-Z]$/
    if (gstin && gstin.length() == 15 && gstin =~ GSTIN_RE) return 'regular'
    if (country && !['india', 'in', ''].contains(country.trim().toLowerCase())) return 'overseas'
    return 'unregistered'
}

// ── CSV row assembly (handles multi-line quoted fields) ────────────────────────

def assembleRows = { String text ->
    // State-machine CSV row splitter: correctly tracks inQ across characters so that
    // a newline inside a quoted field does NOT end the logical row. Also handles ""
    // as an escaped double-quote (does NOT end the quoted region).
    def rows = []
    def sb   = new StringBuilder()
    boolean inQ = false
    for (int ci = 0; ci < text.length(); ci++) {
        char c = text.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < text.length() && text.charAt(ci + 1) == (char)'"') {
                // Escaped quote inside quoted field — keep both chars and advance past second
                sb.append('"'); sb.append('"'); ci++
            } else {
                inQ = !inQ
                sb.append(c)
            }
        } else if ((c == (char)'\n' || c == (char)'\r') && !inQ) {
            // Skip \r of a \r\n pair
            if (c == (char)'\r' && ci + 1 < text.length() && text.charAt(ci + 1) == (char)'\n') ci++
            if (sb.length() > 0 && sb.toString().trim()) { rows << sb.toString(); sb.setLength(0) }
        } else {
            sb.append(c)
        }
    }
    if (sb.length() > 0 && sb.toString().trim()) rows << sb.toString()
    return rows
}

def parseCsvRow = { String line ->
    def cells = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)'"') {
                sb.append('"'); ci++
            } else { inQ = !inQ }
        } else if (c == (char)',' && !inQ) {
            cells << sb.toString(); sb.setLength(0)
        } else { sb.append(c) }
    }
    cells << sb.toString()
    return cells
}

// ── XLSX cell value reader ─────────────────────────────────────────────────────

def getCellValue = { cell ->
    if (!cell) return ''
    try {
        def ct = cell.cellType
        if (ct.name() == 'FORMULA') {
            try { ct = cell.cachedFormulaResultType } catch (ignored) {}
        }
        switch (ct.name()) {
            case 'NUMERIC':
                try {
                    if (org.apache.poi.ss.usermodel.DateUtil.isCellDateFormatted(cell)) {
                        def dt = cell.dateCellValue
                        return dt ? String.format('%tY-%<tm-%<td', dt) : ''
                    }
                } catch (ignored) {}
                // Handle scientific notation from Excel numeric cells (e.g., phone numbers)
                def bd = new BigDecimal(cell.numericCellValue.toString())
                return bd.toPlainString().replaceAll(/\.0+$/, '')
            case 'STRING':  return cell.stringCellValue?.trim() ?: ''
            case 'BOOLEAN': return cell.booleanCellValue.toString()
            case 'BLANK':   return ''
            default:        return cell.toString()?.trim() ?: ''
        }
    } catch (ignored) { return '' }
}

try {
    // ── 1. Load mappings ────────────────────────────────────────────────────────
    def mappingsPath = flowFile.attributes['mappings.path']
    if (!mappingsPath) {
        def f1 = new File('/home/ubuntu/Raw_tally_data/mapping.json')
        def f2 = new File('/home/ubuntu/Raw_tally_data/mappings.json')
        mappingsPath = f1.exists() ? f1.absolutePath : f2.absolutePath
    }
    def mappings    = new JsonSlurper().parse(new File(mappingsPath))
    def tableFields = mappings.tables?.contact_custom?.fields ?: [:]

    if (!tableFields) {
        log.error("[TransformContact_Custom] mapping.json missing tables.contact_custom.fields — " +
                  "add the contact_custom section to: ${mappingsPath}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    def customCfg      = mappings.custom_settings   ?: [:]
    def ptnDefaults    = customCfg.partner_defaults  ?: [:]
    def ctTypeMap      = customCfg.contact_type_map  ?: [:]
    def defaultCountry = (customCfg.default_country  ?: 'India') as String
    def defaultLang    = (ptnDefaults.lang           ?: 'en_US') as String
    def defaultTz      = (ptnDefaults.tz             ?: 'Asia/Kolkata') as String

    // Creditor keywords from mapping.json party_groups (determine supplier vs customer rank)
    def creditorGroups = (mappings.party_groups?.creditor_groups ?:
        ['creditor', 'vendor', 'supplier', 'payable']) as List
    def creditorKws    = creditorGroups.collect { it.toString().toLowerCase() }

    // Skip-row values from mapping.json (Tally summary rows to discard)
    def skipVals = ((customCfg.skip_row_values ?: mappings.skip_row_values ?:
        ['total', 'grand total', 'subtotal', 'closing stock', 'opening stock']) as List)
        .collect { it.toString().trim().toLowerCase() } as Set

    // Known header-row words for auto-detection
    def knownHdrWords = ['customerdetails', 'customer details', 'customernameid', 'name',
        'gstno', 'gstin', 'panno', 'email', 'phone', 'landline',
        'address', 'city', 'state', 'personname', 'person name'] as Set

    // ── 2. Read FlowFile bytes ─────────────────────────────────────────────────
    byte[] rawBytes = null
    session.read(flowFile, { is -> rawBytes = is.bytes } as InputStreamCallback)

    if (!rawBytes || rawBytes.length == 0) {
        log.warn('[TransformContact_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Detect XLSX by magic bytes (PK\x03\x04 = ZIP = XLSX/XLSM) ──────────
    boolean isXlsx = rawBytes.length >= 4 &&
                     rawBytes[0] == (byte)0x50 && rawBytes[1] == (byte)0x4B &&
                     rawBytes[2] == (byte)0x03 && rawBytes[3] == (byte)0x04

    // allRows: list of rows, each row is a list of string cell values; row[headerIdx] = header
    List<List<String>> allRows = []

    if (isXlsx) {
        log.info('[TransformContact_Custom] Detected XLSX — parsing with Apache POI')
        try {
            def wb    = org.apache.poi.ss.usermodel.WorkbookFactory.create(
                            new java.io.ByteArrayInputStream(rawBytes))
            def sheet = wb.getSheetAt(0)
            sheet.each { row ->
                int last = row.lastCellNum > 0 ? row.lastCellNum : 0
                def cells = (0..<last).collect { i ->
                    nvl(getCellValue(row.getCell(i,
                        org.apache.poi.ss.usermodel.Row.MissingCellPolicy.RETURN_BLANK_AS_NULL)))
                }
                if (cells.any { it }) allRows << cells
            }
            wb.close()
        } catch (ClassNotFoundException cnfe) {
            log.error('[TransformContact_Custom] Apache POI not on NiFi classpath. ' +
                      'Copy poi-ooxml-*.jar and its dependencies to NiFi lib/: ' + cnfe.message)
            session.transfer(flowFile, REL_FAILURE)
            return
        }
    } else {
        // CSV path — decode bytes, then assemble logical rows (handles multi-line fields)
        String rawText
        try {
            rawText = new String(rawBytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
        } catch (ignored) {
            rawText = new String(rawBytes, 'ISO-8859-1')
            log.warn('[TransformContact_Custom] UTF-8 decode failed — using ISO-8859-1')
        }

        if (!rawText.trim()) {
            log.warn('[TransformContact_Custom] Empty file body')
            session.transfer(flowFile, REL_FAILURE)
            return
        }

        def firstLine = rawText.readLines().find { it.trim() } ?: ''
        if (firstLine.contains('\t')) {
            // Tab-delimited: no multi-line quoting; simple split per line
            rawText.readLines().findAll { it.trim() }.each { line ->
                allRows << line.split('\t', -1).collect { nvl(it) }
            }
        } else {
            assembleRows(rawText).findAll { it.trim() }.each { line ->
                allRows << parseCsvRow(line).collect { nvl(it) }
            }
        }
    }

    if (allRows.size() < 2) {
        log.warn('[TransformContact_Custom] No data rows found')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 4. Auto-detect header row (skip Excel title/junk rows at top) ──────────
    int headerIdx = -1
    for (int i = 0; i < Math.min(10, allRows.size()); i++) {
        def lower = allRows[i].collect { it?.trim()?.toLowerCase() ?: '' }
        int matches = lower.count { it in knownHdrWords }
        if (matches >= 2 || 'customerdetails' in lower || 'customernameid' in lower ||
            'customer details' in lower) {
            headerIdx = i; break
        }
    }

    if (headerIdx < 0) {
        log.error("[TransformContact_Custom] Cannot detect header row in first 10 rows — " +
                  "row[0]: ${allRows[0]}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (headerIdx > 0) {
        log.info("[TransformContact_Custom] Skipped ${headerIdx} junk row(s). " +
                 "Header: ${allRows[headerIdx]}")
    }

    // ── 5. Build header index (case-insensitive) ───────────────────────────────
    def hdrIdx = [:]
    allRows[headerIdx].eachWithIndex { h, i ->
        def k = h?.trim()?.toLowerCase() ?: ''
        if (k) hdrIdx[k] = i
    }
    log.info("[TransformContact_Custom] Header: ${allRows[headerIdx]}")

    def get = { List cells, int idx ->
        idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx])
    }

    // ── 6. Resolve column indices from mapping.json tables.contact_custom.fields ─
    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) return -1
        def aliases = []
        if (fDef.source_col) aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        // Pass 1: exact case-insensitive match
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            if (hdrIdx.containsKey(k)) return hdrIdx[k]
        }
        // Pass 2: header contains candidate (one direction only — prevents "email address" matching "address")
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            if (k.length() < 3) continue  // skip single-char / two-char candidates in substring mode
            def found = hdrIdx.find { hk, hv -> hk && hk.contains(k) }
            if (found) return found.value
        }
        return -1
    }

    def idIdx      = resolveColIdx('id')
    def cnIdx      = resolveColIdx('CustomerNameId')
    def caIdx      = resolveColIdx('CustomerAddressID')
    def nameIdx    = resolveColIdx('CustomerDetails')
    def partyIdx   = resolveColIdx('PartyType')
    def btypeIdx   = resolveColIdx('BusinessType')
    def gstIdx     = resolveColIdx('GSTNo')
    def emailIdx   = resolveColIdx('COMPANY Email')
    def phoneIdx   = resolveColIdx('LandLine')
    def streetIdx  = resolveColIdx('Address')
    def cityIdx    = resolveColIdx('City')
    def stateIdx   = resolveColIdx('State')
    def countryIdx = resolveColIdx('Country')
    def zipIdx     = resolveColIdx('Pincode')
    def typeIdx    = resolveColIdx('Type')
    def panIdx     = resolveColIdx('PanNo')
    def pnameIdx   = resolveColIdx('PersonName')
    def pmobIdx    = resolveColIdx('PersonMobile')
    def pemailIdx  = resolveColIdx('PersonEmail')
    def deptIdx    = resolveColIdx('Department')
    def desigIdx   = resolveColIdx('Designation')
    def branchIdx  = resolveColIdx('BranchName')

    log.info("[TransformContact_Custom] COLUMN INDICES: " +
             "id:${idIdx} custNameId:${cnIdx} custAddrId:${caIdx} name:${nameIdx} " +
             "partyType:${partyIdx} bizType:${btypeIdx} gst:${gstIdx} " +
             "email:${emailIdx} phone:${phoneIdx} street:${streetIdx} " +
             "city:${cityIdx} state:${stateIdx} country:${countryIdx} zip:${zipIdx} " +
             "type:${typeIdx} pan:${panIdx} branch:${branchIdx} " +
             "pname:${pnameIdx} pmob:${pmobIdx} pemail:${pemailIdx} " +
             "desig:${desigIdx} dept:${deptIdx}")
    log.info("[TransformContact_Custom] HEADERS: ${allRows[headerIdx]}")

    if (nameIdx < 0) {
        log.error("[TransformContact_Custom] Cannot find CustomerDetails/name column — aborting. " +
                  "hdrIdx keys: ${hdrIdx.keySet().toList()} | " +
                  "CustomerDetails aliases: ${tableFields['CustomerDetails']?.source_cols}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (cnIdx < 0) {
        log.error("[TransformContact_Custom] Cannot find CustomerNameId column — aborting. " +
                  "hdrIdx keys: ${hdrIdx.keySet().toList()}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 7. Fixed output columns ────────────────────────────────────────────────
    def COLS = [
        'id', 'customernameid', 'customerAddressid',
        'name', 'vat', 'email', 'phone',
        'street', 'city', 'state_id/name', 'country_id/name', 'zip',
        'type', 'is_company', 'customer_rank', 'supplier_rank', 'lang', 'tz',
        'l10n_in_pan', 'l10n_in_gst_treatment',
        'tally_group', 'business_type', 'branch_name',
        'person_name', 'person_mobile', 'person_email', 'person_designation', 'person_department'
    ]

    def out = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0

    // ── 8. Process rows ────────────────────────────────────────────────────────
    for (int i = headerIdx + 1; i < allRows.size(); i++) {
        def cells = allRows[i]

        def companyName = get(cells, nameIdx)
        def custNameId  = get(cells, cnIdx)

        if (!companyName || !custNameId)                                     { skipped++; continue }
        if (['customerdetails', 'name', 'customer details']
            .contains(companyName.toLowerCase()))                            { skipped++; continue }
        if (companyName.toLowerCase() in skipVals)                           { skipped++; continue }
        // Skip Apache POI binary-object placeholder rows (embedded images/OLE in source XLSX)
        if (cells.any { it?.trim() == 'Binary file' })                      { skipped++; continue }

        // GSTIN: strip whitespace, uppercase, return only if 15 chars
        def gstin = validateGstin(get(cells, gstIdx))

        // PAN: strip whitespace, uppercase
        def pan = validatePan(get(cells, panIdx))

        def country    = get(cells, countryIdx) ?: defaultCountry
        def gstTreat   = computeGstTreatment(gstin, country)

        // Contact type from mapping.json contact_type_map
        def rawType  = get(cells, typeIdx)
        def odooType = ctTypeMap.get(rawType.toLowerCase()) ?: ctTypeMap.get('__default__') ?: 'contact'

        // Determine customer/supplier rank from tally_group using mapping.json creditor_groups
        def tallyGroup   = get(cells, partyIdx)
        def tallyGroupLc = tallyGroup.toLowerCase()
        def isSupplier   = creditorKws.any { tallyGroupLc.contains(it) }
        def custRank     = isSupplier ? 0 : 1
        def suppRank     = isSupplier ? 1 : 0

        def row = [
            cleanId(get(cells, idIdx)),    // id — strip Excel trailing .0
            custNameId,                     // customernameid
            get(cells, caIdx),              // customerAddressid
            companyName,                    // name (company)
            gstin,                          // vat (GSTIN — normalized, 15 chars or empty)
            get(cells, emailIdx),           // email
            cleanPhone(get(cells, phoneIdx)), // phone (handles scientific notation)
            get(cells, streetIdx),          // street
            get(cells, cityIdx),            // city
            get(cells, stateIdx),           // state_id/name
            country,                        // country_id/name
            get(cells, zipIdx),             // zip
            odooType,                       // type (contact/other/delivery)
            'true',                         // is_company (all company rows = true)
            custRank.toString(),            // customer_rank (1 for debtors, 0 for creditors)
            suppRank.toString(),            // supplier_rank (1 for creditors, 0 for debtors)
            defaultLang,                    // lang (from mapping.json partner_defaults)
            defaultTz,                      // tz  (from mapping.json partner_defaults)
            pan,                            // l10n_in_pan (PAN normalized)
            gstTreat,                       // l10n_in_gst_treatment
            tallyGroup,                     // tally_group (for res_partner_category)
            get(cells, btypeIdx),           // business_type
            get(cells, branchIdx),          // branch_name
            get(cells, pnameIdx),           // person_name
            cleanPhone(get(cells, pmobIdx)), // person_mobile (handles scientific notation)
            get(cells, pemailIdx),          // person_email
            get(cells, desigIdx),           // person_designation
            get(cells, deptIdx),            // person_department
        ]

        out.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[TransformContact_Custom] No valid rows produced — check source file and column mapping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 9. Write output ────────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(out.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformContact_Custom] Done — ${written} rows written, ${skipped} skipped")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformContact_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// insert_res_partner_category_batch.groovy  — Step 1 of 4, contact batch pipeline
//
// NiFi flow: Transform_Contacts_data → SplitRecord (500/split, JSON array writer)
//              → [THIS] → insert_l10n_in_pan_entity_batch
//              → insert_res_partner_batch → insert_partner_category_rel_batch
//
// Input:  JSON array (up to 500 records from SplitRecord)
// Action: Deduplicates tally_group values, inserts missing res_partner_category rows.
//         Populates cache key "category.<groupName>" for downstream scripts.
// Output: Pass-through — same JSON forwarded unchanged to next processor.
//
// Connection pattern:
//   OSql.createConnection() always returns a NEW pool connection — it ignores any
//   cacheConnection flag.  To guarantee lock + check + insert share ONE session we
//   use SQL.myPool.withTransaction { conn -> } which passes the raw JDBC Connection
//   directly into the closure.  pg_advisory_xact_lock is used (not pg_advisory_lock)
//   so the lock is automatically released when the transaction commits — no explicit
//   unlock call needed and no unlock/commit race window.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Config ────────────────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def module       = System.getenv('MIGRATION_MODULE') ?: '__migration__'
def adminUid     = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()

// ── Cache helpers ─────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def safeLong = { def v ->
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read batch ─────────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[CategoryBatch] Batch size: ${rows.size()}")

    // ── 2. Deduplicate tally_group values in this batch ───────────────────────
    def uniqueGroups = rows.collect { nvl(it['tally_group']) }.findAll { it }.unique()
    log.info("[CategoryBatch] Unique groups: ${uniqueGroups.size()} — ${uniqueGroups}")

    if (!uniqueGroups) {
        log.warn('[CategoryBatch] No tally_group values in batch — passing through')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 3. Resolve / insert categories ───────────────────────────────────────
    int inserted = 0, reused = 0

    uniqueGroups.each { groupName ->
        def catCacheKey = 'category.' + groupName
        Long catId      = safeLong(cacheGet(catCacheKey))

        // Fast path — verify cached id still exists in DB
        if (catId) {
            boolean ok = false
            SQL.myPool.eachRow('SELECT 1 FROM res_partner_category WHERE id=? LIMIT 1', [catId]) { ok = true }
            if (ok) { reused++; return }
            cacheSet(catCacheKey, 'CLEARED')
            catId = null
        }

        // Slow path — pg_advisory_xact_lock inside withTransaction.
        // withTransaction passes the raw JDBC Connection into the closure, so lock,
        // check, and insert all run on the SAME physical connection.
        // pg_advisory_xact_lock auto-releases when the transaction commits —
        // the insert becomes visible to other threads at exactly the moment the
        // lock is released, eliminating the race window of session-level locks.
        def groupSlug = groupName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
        def extId     = 'partner_category_' + groupSlug
        def lockKey   = (groupName.hashCode() & 0x7FFFFFFF) as int

        SQL.myPool.withTransaction { conn ->
            // Acquire transaction-level advisory lock
            def lockPs = conn.prepareStatement('SELECT pg_advisory_xact_lock(1, ?)')
            lockPs.setInt(1, lockKey)
            lockPs.execute()
            lockPs.close()

            // Re-check cache after acquiring lock
            catId = safeLong(cacheGet(catCacheKey))
            if (catId) {
                def ps = conn.prepareStatement('SELECT 1 FROM res_partner_category WHERE id=? LIMIT 1')
                ps.setLong(1, catId)
                def rs = ps.executeQuery()
                if (!rs.next()) catId = null
                rs.close(); ps.close()
            }

            // Check ir_model_data XID
            if (!catId) {
                def ps = conn.prepareStatement('SELECT res_id FROM ir_model_data WHERE module=? AND name=?')
                ps.setString(1, module); ps.setString(2, extId)
                def rs = ps.executeQuery()
                if (rs.next()) catId = rs.getLong('res_id') ?: null
                rs.close(); ps.close()

                if (catId) {
                    def ps2 = conn.prepareStatement('SELECT 1 FROM res_partner_category WHERE id=? LIMIT 1')
                    ps2.setLong(1, catId)
                    def rs2 = ps2.executeQuery()
                    if (!rs2.next()) catId = null
                    rs2.close(); ps2.close()
                }
            }

            // Insert new category
            if (!catId) {
                def nameJson = '{"en_US":"' + groupName.replace('\\', '\\\\').replace('"', '\\"') + '"}'
                def insPs = conn.prepareStatement(
                    'INSERT INTO res_partner_category (name,active,color,create_uid,write_uid,create_date,write_date) ' +
                    'VALUES (?::jsonb,true,0,?,?,NOW(),NOW()) RETURNING id'
                )
                insPs.setString(1, nameJson)
                insPs.setLong(2, adminUid)
                insPs.setLong(3, adminUid)
                def rs = insPs.executeQuery()
                if (rs.next()) catId = rs.getLong(1)
                rs.close(); insPs.close()

                if (catId) {
                    def xidPs = conn.prepareStatement(
                        'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                        'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
                    )
                    xidPs.setString(1, module); xidPs.setString(2, extId)
                    xidPs.setString(3, 'res.partner.category'); xidPs.setLong(4, catId)
                    xidPs.executeUpdate(); xidPs.close()
                    inserted++
                    log.info("[CategoryBatch] INSERTED: '${groupName}' → id=${catId}")
                } else {
                    log.warn("[CategoryBatch] INSERT returned no id for group: '${groupName}'")
                }
            } else {
                reused++
            }

            // Populate cache inside transaction — visible after commit
            if (catId) cacheSet(catCacheKey, catId.toString())

            // Transaction commits here; pg_advisory_xact_lock auto-released
        }
    }

    log.info("[CategoryBatch] Completed — groups=${uniqueGroups.size()} inserted=${inserted} reused=${reused}")

    ff = session.putAllAttributes(ff, [
        'category.inserted': inserted.toString(),
        'category.reused'  : reused.toString(),
        'batch.size'       : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[CategoryBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    session.transfer(ff, REL_FAILURE)
}

// insert_partner_category_rel_batch.groovy  — Step 3 of 3, contact batch pipeline
//
// NiFi flow: insert_res_partner_batch → [THIS] insert_partner_category_rel_batch
//
// Input:  JSON array (up to 500 records; same flowfile passed through from step 2)
// Action: For each record looks up category_id and partner_id from cache (written by
//         steps 1 and 2), then batch-inserts all rows into
//         res_partner_res_partner_category_rel using addBatch/executeBatch in a
//         single transaction. ON CONFLICT DO NOTHING makes it idempotent.
// Output: REL_SUCCESS with rel.inserted / rel.skipped attributes.
//
// Cache keys read (written by upstream scripts):
//   category.<groupName>      → category_id  (written by insert_res_partner_category_batch)
//   cust.nameid.<custNameId>  → partner_id   (written by insert_res_partner_batch)
//
// Connection pattern: SQL.myPool.withTransaction { conn -> } gets a fresh JDBC
// connection, sets autoCommit=false, commits on success, rolls back on exception.

import groovy.json.JsonSlurper
import groovy.sql.Sql
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def safeLong = { def v ->
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}

try {
    // ── 1. Read batch ─────────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[CatRelBatch] Batch size: ${rows.size()}")

    // ── 2. Build (category_id, partner_id) pairs from cache ───────────────────
    // Deduplicate: a company may appear only once per category, but multiple rows
    // with the same custNameId / tally_group would produce duplicate pairs.
    def relSet = [] as LinkedHashSet  // preserves insertion order, deduplicates

    int lookupMiss = 0
    rows.each { row ->
        def tallyGroup = nvl(row['tally_group'])
        def custNameId = nvl(row['customernameid'])

        if (!tallyGroup || !custNameId) { lookupMiss++; return }

        Long catId  = safeLong(cacheGet('category.' + tallyGroup))
        Long partId = safeLong(cacheGet('cust.nameid.' + custNameId))

        if (!catId || !partId) {
            log.warn("[CatRelBatch] Cache miss — tally_group='${tallyGroup}' cat=${catId} custNameId='${custNameId}' partner=${partId}")
            lookupMiss++
            return
        }

        relSet << [catId, partId]
    }

    if (lookupMiss > 0) {
        log.warn("[CatRelBatch] ${lookupMiss} rows skipped due to cache miss (categories/partners not yet in DB)")
    }

    if (!relSet) {
        log.info('[CatRelBatch] No category relationships to insert — passing through')
        ff = session.putAllAttributes(ff, [
            'rel.inserted': '0',
            'rel.skipped' : lookupMiss.toString(),
            'batch.size'  : rows.size().toString()
        ])
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("[CatRelBatch] Inserting ${relSet.size()} unique (category_id, partner_id) pairs")

    // ── 3. Batch-insert all rels in one transaction ───────────────────────────
    int inserted = 0

    SQL.myPool.withTransaction { conn ->
        def relPs = conn.prepareStatement(
            'INSERT INTO res_partner_res_partner_category_rel (category_id, partner_id) ' +
            'VALUES (?, ?) ON CONFLICT DO NOTHING'
        )

        // Sort by (category_id, partner_id) — prevents deadlock when multiple
        // NiFi threads insert into this junction table concurrently.
        def sortedPairs = relSet.sort { a, b -> a[0] <=> b[0] ?: a[1] <=> b[1] }
        sortedPairs.each { pair ->
            relPs.setLong(1, pair[0])  // category_id
            relPs.setLong(2, pair[1])  // partner_id
            relPs.addBatch()
        }

        def counts = relPs.executeBatch()
        relPs.close()

        // executeBatch returns array of update counts; sum non-negative values
        inserted = counts.count { it >= 0 }

        log.info("[CatRelBatch] Transaction committed — pairs=${relSet.size()} inserted=${inserted}")
    }

    // ── Output ────────────────────────────────────────────────────────────────
    ff = session.putAllAttributes(ff, [
        'rel.inserted': inserted.toString(),
        'rel.skipped' : lookupMiss.toString(),
        'batch.size'  : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[CatRelBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// insert_res_partner_batch.groovy  — Step 3 of 4, contact batch pipeline
//
// NiFi flow:
//   insert_l10n_in_pan_entity_batch
//     → [THIS] insert_res_partner_batch
//     → insert_partner_category_rel_batch
//
// Input:  JSON array (up to 500 records; same flowfile passed through from step 2)
// Action:
//   Phase 1 (auto-commit, plain SQL — no cacheConnection needed):
//     - Schema probes for optional columns (once per batch)
//     - Read PAN entity IDs from cache (inserted by insert_l10n_in_pan_entity_batch)
//     - Resolve country / state IDs (read-only cache + DB lookups)
//   Phase 2 (single transaction via withTransaction):
//     - Insert res_partner rows for company + optional person contact
//     - Backfills commercial_partner_id=id and complete_name=name for new companies
//       in ONE UPDATE ... WHERE id=ANY(?) after all inserts
//     - Batch-inserts ir_model_data XIDs wiAth addBatch/executeBatch
// Output: Pass-through — same JSON forwarded unchanged to insert_partner_category_rel_batch.
//
// Cache keys written (consumed by insert_partner_category_rel_batch):
//   xid.partner.<xid>         → company res_id
//   partner.<companyName>     → company res_id
//   cust.nameid.<custNameId>  → company res_id
//   cust.addrid.<custAddrId>  → company res_id  (when present)
//   partner.gstin.<gstin>     → company res_id  (when gstin present)
//   cust.personid.<rowId>     → person  res_id  (when person present)
//
// Connection pattern:
//   Phase 1: plain SQL.myPool calls (auto-commit, no advisory locks).
//   Phase 2: SQL.myPool.withTransaction { conn -> } — fresh JDBC conn, auto-commit=false.
//   NEVER set sql.cacheConnection = true — OSql does not support that syntax.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Config ────────────────────────────────────────────────────────────────────
def mappingsPath  = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings      = new JsonSlurper().parse(new File(mappingsPath))
def customCfg     = mappings.custom_settings   ?: [:]
def xidPfx        = customCfg.xid_prefixes    ?: [:]
def ptnDefaults   = customCfg.partner_defaults ?: [:]
def creditorGroups = ((mappings.party_groups?.creditor_groups) ?: [
    'sundry creditors','creditors','vendor','vendors','supplier','suppliers',
    'trade payables','accounts payable'
]).collect { it.toString().toLowerCase() } as Set

def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()

def AUTOPOST_BILLS = 'nothing'
def GROUP_RFQ      = 'individual'
def GROUP_ON       = 'invoice'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def safeLong = { def v ->
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(60)
    slug ?: 'unknown'
}

def validPan = { def v ->
    def s = nvl(v)?.replaceAll(/\s+/, '')?.toUpperCase()
    (s && s.length() == 10 && s ==~ /^[A-Z]{5}[0-9]{4}[A-Z]$/) ? s : null
}

def bindParams = { ps, List params ->
    params.eachWithIndex { v, i ->
        int pos = i + 1
        if (v == null)                 ps.setObject(pos, null)
        else if (v instanceof Long)    ps.setLong(pos, v)
        else if (v instanceof Integer) ps.setInt(pos, v)
        else if (v instanceof Boolean) ps.setBoolean(pos, v)
        else                           ps.setString(pos, v.toString())
    }
}

try {
    // ── 1. Read batch ─────────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[PartnerBatch] Batch size: ${rows.size()}")

    def compId = safeLong(cacheGet('lookup.company_id')) ?: 1L

    // Lookup maps built in Phase 1
    def panEntityIdMap = [:]
    def countryIdMap   = [:]
    def stateIdMap     = [:]

    // Schema flags
    def hasEmployee     = false
    def hasColor        = false
    def hasMsgBounce    = false
    def hasPartnerShare = false
    def hasGroupRfq     = false
    def hasGroupOn      = false
    def hasPanEntity    = false
    def hasGstTreatment = false
    def hasFunction     = false
    def hasMobile       = false
    def bizTypeCol      = null
    def hasBizType      = false
    def branchNameCol   = null
    def hasBranchName   = false

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 1 — auto-commit: schema probes, cache reads, country/state lookups.
    // No advisory locks here — PAN entities already resolved by step 2.
    //
    // IMPORTANT: never store SQL.myPool in a variable and never call .close() on
    // it.  NiFi returns the same cached OSql instance every time SQL.myPool is
    // accessed; closing it breaks all subsequent SQL.myPool calls in this script.
    // ════════════════════════════════════════════════════════════════════════════

    // ── 2. Schema probes (once per batch) ────────────────────────────────────
    def colExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='res_partner' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }

    hasEmployee     = colExists('employee')
    hasColor        = colExists('color')
    hasMsgBounce    = colExists('message_bounce')
    hasPartnerShare = colExists('partner_share')
    hasGroupRfq     = colExists('group_rfq')
    hasGroupOn      = colExists('group_on')
    hasPanEntity    = colExists('l10n_in_pan_entity_id')
    hasGstTreatment = colExists('l10n_in_gst_treatment')
    hasFunction     = colExists('function')
    hasMobile       = colExists('mobile')
    def biz1 = colExists('business_type'); def biz2 = colExists('x_business_type')
    bizTypeCol    = biz1 ? 'business_type' : (biz2 ? 'x_business_type' : null)
    hasBizType    = bizTypeCol != null
    def br1 = colExists('branch_name');    def br2 = colExists('x_branch_name')
    branchNameCol = br1 ? 'branch_name' : (br2 ? 'x_branch_name' : null)
    hasBranchName = branchNameCol != null

    log.info("[PartnerBatch] Schema: employee=${hasEmployee} color=${hasColor} msgBounce=${hasMsgBounce} " +
             "partnerShare=${hasPartnerShare} groupRfq=${hasGroupRfq} groupOn=${hasGroupOn} " +
             "panEntity=${hasPanEntity} gstTreatment=${hasGstTreatment} " +
             "function=${hasFunction} mobile=${hasMobile} " +
             "bizType=${hasBizType}(${bizTypeCol}) branchName=${hasBranchName}(${branchNameCol})")

    // ── 3. Read PAN entity IDs from cache (inserted by step 2) ───────────────
    rows.collect { r -> validPan(r['l10n_in_pan']) }.findAll { it }.unique().each { panStr ->
        Long eid = safeLong(cacheGet('lookup.pan_entity.' + panStr))
        if (eid) panEntityIdMap[panStr] = eid
    }
    log.info("[PartnerBatch] PAN entities from cache: ${panEntityIdMap.size()}")

    // ── 4. Resolve countries (cache + DB, read-only) ──────────────────────────
    rows.collect { r ->
        (nvl(r['country_id/name']) ?: nvl(r['country_id_name'])) ?: 'India'
    }.unique().each { cn ->
        Long cid = safeLong(cacheGet('lookup.country.' + cn))
        if (!cid) {
            SQL.myPool.eachRow("SELECT id FROM res_country WHERE lower(name::text) ILIKE lower(?) LIMIT 1", [cn]) { r ->
                cid = r.getLong('id')
            }
            if (cid) cacheSet('lookup.country.' + cn, cid.toString())
        }
        if (!cid) cid = safeLong(cacheGet('lookup.country_id_in'))
        if (cid) countryIdMap[cn] = cid
    }

    // ── 5. Resolve states (cache + DB, read-only) ─────────────────────────────
    rows.collect { r ->
        nvl(r['state_id/name']) ?: nvl(r['state_id_name'])
    }.findAll { it }.unique().each { sn ->
        Long sid = safeLong(cacheGet('lookup.state.' + sn))
        if (!sid) {
            SQL.myPool.eachRow("SELECT id FROM res_country_state WHERE lower(name::text) ILIKE lower(?) LIMIT 1", [sn]) { r ->
                sid = r.getLong('id')
            }
            if (sid) cacheSet('lookup.state.' + sn, sid.toString())
        }
        if (sid) stateIdMap[sn] = sid
    }

    // ── 6. Build INSERT SQL templates (dynamic based on schema flags) ─────────
    def cmpCols = ['name','vat','customer_rank','supplier_rank',
                   'street','city','zip','country_id','state_id','company_id',
                   'is_company','active','type','email','phone','lang','tz',
                   'create_uid','write_uid']
    def cmpVals = ['?','?','?','?',
                   '?','?','?','?','?','?',
                   'true','true','?','?','?','?','?',
                   '?','?']
    if (hasPartnerShare) { cmpCols << 'partner_share';          cmpVals << 'true'  }
    if (hasMsgBounce)    { cmpCols << 'message_bounce';         cmpVals << '?'     }
    if (hasColor)        { cmpCols << 'color';                  cmpVals << '?'     }
    if (hasEmployee)     { cmpCols << 'employee';               cmpVals << 'false' }
                           cmpCols << 'autopost_bills';         cmpVals << '?'
    if (hasGroupRfq)     { cmpCols << 'group_rfq';              cmpVals << '?'     }
    if (hasGroupOn)      { cmpCols << 'group_on';               cmpVals << '?'     }
    if (hasGstTreatment) { cmpCols << 'l10n_in_gst_treatment';  cmpVals << '?'     }
    if (hasPanEntity)    { cmpCols << 'l10n_in_pan_entity_id';  cmpVals << '?'     }
    if (hasBizType)      { cmpCols << bizTypeCol;               cmpVals << '?'     }
    if (hasBranchName)   { cmpCols << branchNameCol;            cmpVals << '?'     }
                           cmpCols << 'create_date';            cmpVals << 'NOW()'
                           cmpCols << 'write_date';             cmpVals << 'NOW()'
    def cmpSql = "INSERT INTO res_partner (${cmpCols.join(',')}) VALUES (${cmpVals.join(',')}) RETURNING id"

    def perCols = ['name','parent_id','commercial_partner_id','company_id',
                   'is_company','active','type','customer_rank','supplier_rank',
                   'email','lang','tz','create_uid','write_uid']
    def perVals = ['?','?','?','?',
                   'false','true','?','0','0',
                   '?','?','?','?','?']
    if (hasMobile)       { perCols << 'mobile';          perVals << '?'     }
    if (hasFunction)     { perCols << 'function';        perVals << '?'     }
    if (hasPartnerShare) { perCols << 'partner_share';   perVals << 'true'  }
    if (hasMsgBounce)    { perCols << 'message_bounce';  perVals << '?'     }
    if (hasColor)        { perCols << 'color';           perVals << '?'     }
    if (hasEmployee)     { perCols << 'employee';        perVals << 'false' }
                           perCols << 'autopost_bills';  perVals << '?'
    if (hasGroupRfq)     { perCols << 'group_rfq';       perVals << '?'     }
    if (hasGroupOn)      { perCols << 'group_on';        perVals << '?'     }
                           perCols << 'complete_name';   perVals << '?'
                           perCols << 'create_date';     perVals << 'NOW()'
                           perCols << 'write_date';      perVals << 'NOW()'
    def perSql = "INSERT INTO res_partner (${perCols.join(',')}) VALUES (${perVals.join(',')}) RETURNING id"

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — single transaction for all records in this batch.
    // withTransaction: fresh JDBC connection, autoCommit=false,
    // commits on success, rolls back on any exception.
    // ════════════════════════════════════════════════════════════════════════
    int written = 0, skipped = 0
    def xidBatch      = []
    def newCompanyIds = []

    SQL.myPool.withTransaction { conn ->
        def cmpPs = conn.prepareStatement(cmpSql)
        def perPs = conn.prepareStatement(perSql)

        def partnerExistsInDb = { Long id ->
            def chkPs = conn.prepareStatement('SELECT 1 FROM res_partner WHERE id=? LIMIT 1')
            chkPs.setLong(1, id)
            def rs = chkPs.executeQuery()
            def found = rs.next()
            rs.close(); chkPs.close()
            return found
        }

        rows.each { row ->
            def rowId        = nvl(row['id'])
            def custNameId   = nvl(row['customernameid'])
            def custAddrId   = nvl(row['customerAddressid'])
            def companyName  = nvl(row['name'])
            def gstin        = nvl(row['vat'])?.replaceAll(/\s+/, '')?.toUpperCase()
            def companyEmail = nvl(row['email'])
            def landLine     = nvl(row['phone'])
            def address      = nvl(row['street'])
            def city         = nvl(row['city'])
            def stateName    = nvl(row['state_id/name']) ?: nvl(row['state_id_name'])
            def countryName  = (nvl(row['country_id/name']) ?: nvl(row['country_id_name'])) ?: 'India'
            def pincode      = nvl(row['zip'])
            def partnerType  = nvl(row['type']) ?: 'contact'
            def panNo        = validPan(row['l10n_in_pan'])
            def gstTreatRaw  = nvl(row['l10n_in_gst_treatment'])
            def tallyGroup   = nvl(row['tally_group'])
            def personName   = nvl(row['person_name'])
            def personMobile = nvl(row['person_mobile'])
            def personEmail  = nvl(row['person_email'])
            def designation  = nvl(row['person_designation'])
            def businessType = nvl(row['business_type'])
            def branchName   = nvl(row['branch_name'])

            if (!companyName || !custNameId) { skipped++; return }

            def isCreditor   = tallyGroup && creditorGroups.contains(tallyGroup.toLowerCase())
            def customerRank = isCreditor ? 0 : 1
            def supplierRank = isCreditor ? 1 : 0

            def ctryId      = countryIdMap[countryName]
            def stateId     = stateName ? stateIdMap[stateName] : null
            def panEntityId = panNo ? panEntityIdMap[panNo] : null
            def gstTreat    = hasGstTreatment ? gstTreatRaw : null

            // ── Company insert / lookup ───────────────────────────────────
            def companyXid      = (xidPfx.company ?: 'cust_company_') + slugify(custNameId)
            def companyCacheKey = 'xid.partner.' + companyXid
            Long companyResId   = null

            def cachedCid = cacheGet(companyCacheKey)
            if (cachedCid) {
                def cid = safeLong(cachedCid)
                if (cid && partnerExistsInDb(cid)) companyResId = cid
                else cacheSet(companyCacheKey, 'CLEARED')
            }

            if (!companyResId) {
                def chkPs = conn.prepareStatement('SELECT res_id FROM ir_model_data WHERE module=? AND name=?')
                chkPs.setString(1, module); chkPs.setString(2, companyXid)
                def rs = chkPs.executeQuery()
                if (rs.next()) companyResId = rs.getLong('res_id') ?: null
                rs.close(); chkPs.close()

                if (companyResId && !partnerExistsInDb(companyResId)) {
                    def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
                    delPs.setString(1, module); delPs.setString(2, companyXid)
                    delPs.executeUpdate(); delPs.close()
                    companyResId = null
                }
            }

            if (!companyResId) {
                def params = [companyName, gstin, customerRank, supplierRank,
                              address, city, pincode, ctryId, stateId, compId,
                              partnerType, companyEmail, landLine,
                              (ptnDefaults.lang ?: 'en_US'), (ptnDefaults.tz ?: 'Asia/Kolkata'),
                              adminUid, adminUid] as List
                if (hasMsgBounce)    params << 0
                if (hasColor)        params << 0
                                     params << AUTOPOST_BILLS
                if (hasGroupRfq)     params << GROUP_RFQ
                if (hasGroupOn)      params << GROUP_ON
                if (hasGstTreatment) params << gstTreat
                if (hasPanEntity)    params << panEntityId
                if (hasBizType)      params << businessType
                if (hasBranchName)   params << branchName

                cmpPs.clearParameters()
                bindParams(cmpPs, params)
                def rs = cmpPs.executeQuery()
                rs.next()
                companyResId = rs.getLong(1)
                rs.close()

                newCompanyIds << companyResId
                xidBatch << [module, companyXid, 'res.partner', companyResId]
                log.info("[PartnerBatch] Company INSERTED: '${companyName}' → ${companyResId}")
            }

            cacheSet(companyCacheKey,              companyResId.toString())
            cacheSet('partner.' + companyName,     companyResId.toString())
            cacheSet('cust.nameid.' + custNameId,  companyResId.toString())
            if (custAddrId) cacheSet('cust.addrid.' + custAddrId, companyResId.toString())
            if (gstin)      cacheSet('partner.gstin.' + gstin,    companyResId.toString())

            // ── Person contact insert / lookup ────────────────────────────
            if (personName && rowId) {
                def personXid      = (xidPfx.person ?: 'cust_person_') + slugify(rowId)
                def personCacheKey = 'xid.partner.' + personXid
                Long personResId   = null

                def cachedPid = cacheGet(personCacheKey)
                if (cachedPid) {
                    def pid = safeLong(cachedPid)
                    if (pid && partnerExistsInDb(pid)) personResId = pid
                    else cacheSet(personCacheKey, 'CLEARED')
                }

                if (!personResId) {
                    def chkPs = conn.prepareStatement('SELECT res_id FROM ir_model_data WHERE module=? AND name=?')
                    chkPs.setString(1, module); chkPs.setString(2, personXid)
                    def rs = chkPs.executeQuery()
                    if (rs.next()) personResId = rs.getLong('res_id') ?: null
                    rs.close(); chkPs.close()

                    if (personResId && !partnerExistsInDb(personResId)) {
                        def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
                        delPs.setString(1, module); delPs.setString(2, personXid)
                        delPs.executeUpdate(); delPs.close()
                        personResId = null
                    }
                }

                if (!personResId) {
                    def pParams = [personName, companyResId, companyResId, compId,
                                   'contact', personEmail,
                                   (ptnDefaults.lang ?: 'en_US'), (ptnDefaults.tz ?: 'Asia/Kolkata'),
                                   adminUid, adminUid] as List
                    if (hasMobile)    pParams << personMobile
                    if (hasFunction)  pParams << designation
                    if (hasMsgBounce) pParams << 0
                    if (hasColor)     pParams << 0
                                      pParams << AUTOPOST_BILLS
                    if (hasGroupRfq)  pParams << GROUP_RFQ
                    if (hasGroupOn)   pParams << GROUP_ON
                                      pParams << "${companyName}, ${personName}"

                    perPs.clearParameters()
                    bindParams(perPs, pParams)
                    def pRs = perPs.executeQuery()
                    pRs.next()
                    personResId = pRs.getLong(1)
                    pRs.close()

                    xidBatch << [module, personXid, 'res.partner', personResId]
                    log.info("[PartnerBatch] Person INSERTED: '${personName}' → ${personResId} (parent: ${companyResId})")
                }

                cacheSet(personCacheKey,           personResId.toString())
                cacheSet('cust.personid.' + rowId, personResId.toString())
            }

            written++
        }

        cmpPs.close()
        perPs.close()

        // ── Backfill new companies in one UPDATE (major batch speedup) ────────
        if (newCompanyIds) {
            def arr  = conn.createArrayOf('bigint', newCompanyIds.toArray(new Long[0]))
            def bfPs = conn.prepareStatement(
                'UPDATE res_partner SET commercial_partner_id=id, complete_name=name WHERE id=ANY(?)'
            )
            bfPs.setArray(1, arr)
            bfPs.executeUpdate()
            bfPs.close()
            log.info("[PartnerBatch] Backfilled ${newCompanyIds.size()} new companies")
        }

        // ── Batch-insert ir_model_data XIDs ───────────────────────────────────
        if (xidBatch) {
        xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m2, n2, mdl, rid ->
                xidPs.setString(1, m2); xidPs.setString(2, n2)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            xidPs.executeBatch()
            xidPs.close()
            log.info("[PartnerBatch] XID batch: ${xidBatch.size()} rows")
        }

        log.info("[PartnerBatch] Transaction committed — written=${written} skipped=${skipped} " +
                 "newCompanies=${newCompanyIds.size()} xids=${xidBatch.size()}")
    }

    ff = session.putAllAttributes(ff, [
        'row.count'    : written.toString(),
        'skipped.count': skipped.toString(),
        'batch.size'   : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[PartnerBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// TransformProduct_Custom.groovy
// Full-file custom product CSV/XLSX transformer for Nevco product data.
// Reads raw Excel/CSV, validates and normalizes fields, outputs clean NiFi CSV.
//
// NiFi flow:
//   [GetFile (.xlsx)] → TransformProduct_Custom → SplitRecord
//       → insert_product_template_custom.groovy
//
// Source columns (case-insensitive; aliases driven by mapping.json tables.product_custom.fields):
//   id, Name, Internal Reference, Product category, HSN/SAC Code,
//   Sales Price, Unit of Measure, Product Type, Tracking,
//   Customer Taxes, Vendor Taxes, barcode
//
// Output columns (12 fixed — do NOT change without updating downstream insert scripts):
//   id, Name, Internal Reference, Product category, HSN/SAC Code,
//   Sales Price, Unit of Measure, Product Type, Tracking,
//   Customer Taxes, Vendor Taxes, barcode
//
// All output columns always present (even empty) — prevents SplitRecord column count errors.
// XLSX detected via ZIP magic bytes (PK\x03\x04); requires Apache POI on NiFi classpath.

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

// ── Helpers ────────────────────────────────────────────────────────────────────

def nvl = { def v ->
    def s = v?.toString()?.trim()
    if (!s) return ''
    if (s == '\\N' || s == '\\\\N' || s.equalsIgnoreCase('null') ||
        s.equalsIgnoreCase('none') || s == 'N/A' || s == 'NA') return ''
    return s
}

def escCsv = { String v ->
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def cleanId = { String raw ->
    (raw ?: '').trim().replaceAll(/\.0+$/, '')
}

def cleanNum = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
        .replace(',', '')
        .replace('₹', '')
        .replace('$', '')
        .replace('%', '')
        .replace(' ', '')
    def m = s =~ /^\(([0-9.]+)\)$/
    if (m) s = '-' + m[0][1]
    if (!s || s in ['-', '.']) return ''
    try { new BigDecimal(s); return s } catch (ignored) { return '' }
}

def cleanTax = { String raw ->
    if (!raw) return ''
    // First try standard clean (handles "18", "18.0", "18%", "18.0%")
    def s = cleanNum(raw)
    // Fallback: extract first numeric sequence from strings like "GST@18%" or "CGST 9"
    if (!s) {
        def fm = (raw =~ /([0-9]+(?:\.[0-9]*)?)/)
        s = fm ? fm[0][1] : ''
    }
    if (!s) return ''
    try {
        def v = new BigDecimal(s)
        // Reject clearly wrong values like 150000 (data leak from price column)
        if (v >= BigDecimal.ZERO && v <= 100G) {
            // Return as integer string if whole number (18.0 → "18"), else as-is
            def vi = v.setScale(0, java.math.RoundingMode.HALF_UP)
            return (v.compareTo(vi) == 0) ? vi.toBigInteger().toString() : s
        }
    } catch (ignored) {}
    return ''
}

def normUom = { String raw, Map uomMap, Map uomAliases ->
    if (!raw) return ''
    def trimmed = raw.trim()
    if (uomAliases[trimmed]) return uomAliases[trimmed]
    def lower = trimmed.toLowerCase()
    if (uomAliases[lower]) return uomAliases[lower]
    if (uomMap[lower]) return uomMap[lower]
    return trimmed
}

def normTracking = { String t1, String t2 ->
    def s1 = (t1 ?: '').trim().toLowerCase()
    def s2 = (t2 ?: '').trim().toLowerCase()
    if (s1 in ['true', '1', 'yes', 'serial', 'by serial number']) return 'True'
    if (s2 in ['serial', 'by serial number', 'by serial'])        return 'True'
    return 'False'
}

// ── CSV row assembly (handles multi-line quoted fields) ────────────────────────

def assembleRows = { String text ->
    def rows = []; def sb = new StringBuilder(); int qCount = 0
    text.eachLine { line ->
        if (sb.length() > 0) sb.append('\n')
        sb.append(line)
        qCount += line.count('"')
        if (qCount % 2 == 0) { rows << sb.toString(); sb.setLength(0); qCount = 0 }
    }
    if (sb.length() > 0) rows << sb.toString()
    return rows
}

def parseCsvRow = { String line ->
    def cells = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)'"') {
                sb.append('"'); ci++
            } else { inQ = !inQ }
        } else if (c == (char)',' && !inQ) {
            cells << sb.toString(); sb.setLength(0)
        } else { sb.append(c) }
    }
    cells << sb.toString()
    return cells
}

// ── XLSX cell value reader ─────────────────────────────────────────────────────

def getCellValue = { cell ->
    if (!cell) return ''
    try {
        def ct = cell.cellType
        if (ct.name() == 'FORMULA') {
            try { ct = cell.cachedFormulaResultType } catch (ignored) {}
        }
        switch (ct.name()) {
            case 'NUMERIC':
                try {
                    if (org.apache.poi.ss.usermodel.DateUtil.isCellDateFormatted(cell)) {
                        def dt = cell.dateCellValue
                        return dt ? String.format('%tY-%<tm-%<td', dt) : ''
                    }
                } catch (ignored) {}
                def bd = new BigDecimal(cell.numericCellValue.toString())
                return bd.toPlainString().replaceAll(/\.0+$/, '')
            case 'STRING':  return cell.stringCellValue?.trim() ?: ''
            case 'BOOLEAN': return cell.booleanCellValue.toString()
            case 'BLANK':   return ''
            default:        return cell.toString()?.trim() ?: ''
        }
    } catch (ignored) { return '' }
}

try {
    // ── 1. Load mappings ────────────────────────────────────────────────────────
    def mappingsPath = flowFile.attributes['mappings.path']
    if (!mappingsPath) {
        def f1 = new File('/home/ubuntu/Raw_tally_data/mapping.json')
        def f2 = new File('/home/ubuntu/Raw_tally_data/mappings.json')
        mappingsPath = f1.exists() ? f1.absolutePath : f2.absolutePath
    }
    def mappings    = new JsonSlurper().parse(new File(mappingsPath))
    def tableFields = mappings.tables?.product_custom?.fields ?: [:]

    if (!tableFields) {
        log.error("[TransformProduct_Custom] mapping.json missing tables.product_custom.fields — " +
                  "add the product_custom section to: ${mappingsPath}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    def customCfg  = mappings.custom_settings ?: [:]
    def uomMap     = (mappings.uom_map        ?: [:]) as Map
    def uomAliases = (customCfg.uom_aliases   ?: [:]) as Map

    def skipVals = ((customCfg.skip_row_values ?: mappings.skip_row_values ?:
        ['total', 'grand total', 'subtotal', 'closing stock', 'opening stock',
         'name', 'product name', 'item name']) as List)
        .collect { it.toString().trim().toLowerCase() } as Set

    // Header detection groups from mapping.json (≥2 matches → this is a product header row)
    def hdrGroups = (mappings.tables?.product_custom?.header_detection_groups ?: [
        ['name', 'product name', 'item name'],
        ['internal reference', 'default_code', 'sku', 'product code'],
        ['hsn/sac code', 'hsn code', 'hsn'],
        ['sales price', 'list_price', 'price', 'rate'],
        ['product type', 'type'],
        ['unit of measure', 'uom', 'unit'],
        ['product category', 'category']
    ]) as List

    def isProductSheet = { List<String> hdrs ->
        def lower = hdrs.collect { it?.trim()?.toLowerCase() ?: '' } as Set
        int score = 0
        hdrGroups.each { grp ->
            if ((grp as List).any { it in lower }) score++
        }
        return score >= 2
    }

    // ── 2. resolveColIdx — reads aliases from mapping.json, two-pass match ─────
    def resolveColIdx = { String fieldName, List<String> hdrs ->
        def fieldDef = tableFields[fieldName]
        if (!fieldDef) return -1
        def candidates = []
        if (fieldDef.source_col) candidates << fieldDef.source_col.toString().toLowerCase()
        if (fieldDef.source_cols) candidates.addAll(
            (fieldDef.source_cols as List).collect { it.toString().toLowerCase() }
        )
        // Pass 1: exact (case-insensitive)
        for (int i = 0; i < hdrs.size(); i++) {
            def h = hdrs[i]?.trim()?.toLowerCase() ?: ''
            if (h && h in candidates) return i
        }
        // Pass 2: substring
        for (int i = 0; i < hdrs.size(); i++) {
            def h = hdrs[i]?.trim()?.toLowerCase() ?: ''
            if (!h) continue
            for (def cand : candidates) {
                if (h.contains(cand) || cand.contains(h)) return i
            }
        }
        return -1
    }

    // ── 3. Read FlowFile bytes ─────────────────────────────────────────────────
    byte[] rawBytes = null
    session.read(flowFile, { is -> rawBytes = is.bytes } as InputStreamCallback)

    if (!rawBytes || rawBytes.length == 0) {
        log.warn('[TransformProduct_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 4. Detect XLSX by magic bytes ─────────────────────────────────────────
    boolean isXlsx = rawBytes.length >= 4 &&
                     rawBytes[0] == (byte)0x50 && rawBytes[1] == (byte)0x4B &&
                     rawBytes[2] == (byte)0x03 && rawBytes[3] == (byte)0x04

    List<List<String>> allRows = []
    int headerRowIdx = -1

    if (isXlsx) {
        log.info('[TransformProduct_Custom] Detected XLSX — parsing with Apache POI')
        try {
            def wb = org.apache.poi.ss.usermodel.WorkbookFactory.create(
                         new java.io.ByteArrayInputStream(rawBytes))
            List<List<String>> bestRows = []
            int bestData = 0, bestHdrIdx = -1

            for (int si = 0; si < wb.numberOfSheets; si++) {
                def sheet = wb.getSheetAt(si)
                List<List<String>> sheetRows = []
                sheet.each { row ->
                    int last = row.lastCellNum > 0 ? row.lastCellNum : 0
                    def cells = (0..<last).collect { i ->
                        nvl(getCellValue(row.getCell(i,
                            org.apache.poi.ss.usermodel.Row.MissingCellPolicy.RETURN_BLANK_AS_NULL)))
                    }
                    if (cells.any { it }) sheetRows << cells
                }
                int hIdx = -1
                for (int ri = 0; ri < Math.min(15, sheetRows.size()); ri++) {
                    if (isProductSheet(sheetRows[ri])) { hIdx = ri; break }
                }
                if (hIdx < 0) continue
                int dataCount = sheetRows.size() - hIdx - 1
                log.info("[TransformProduct_Custom] Sheet '${sheet.sheetName}': ${dataCount} data rows")
                if (dataCount > bestData) {
                    bestData = dataCount; bestRows = sheetRows; bestHdrIdx = hIdx
                }
            }
            wb.close()

            if (bestHdrIdx < 0) {
                log.error('[TransformProduct_Custom] No product sheet found in workbook')
                session.transfer(flowFile, REL_FAILURE)
                return
            }
            allRows = bestRows; headerRowIdx = bestHdrIdx

        } catch (ClassNotFoundException cnfe) {
            log.error('[TransformProduct_Custom] Apache POI not on classpath: ' + cnfe.message)
            session.transfer(flowFile, REL_FAILURE)
            return
        }
    } else {
        log.info('[TransformProduct_Custom] Detected CSV — parsing as text')
        def text = new String(rawBytes, StandardCharsets.UTF_8).replaceAll(/^﻿/, '')
        assembleRows(text).each { allRows << parseCsvRow(it) }
        for (int ri = 0; ri < Math.min(15, allRows.size()); ri++) {
            if (isProductSheet(allRows[ri])) { headerRowIdx = ri; break }
        }
        if (headerRowIdx < 0) {
            log.error('[TransformProduct_Custom] Cannot detect product header row in CSV')
            session.transfer(flowFile, REL_FAILURE)
            return
        }
    }

    // ── 5. Resolve column indices via mapping.json aliases ─────────────────────
    def headers = allRows[headerRowIdx]
    log.info("[TransformProduct_Custom] Header (${headers.size()} cols): ${headers.take(20)}")

    def idIdx      = resolveColIdx('id',                 headers)
    def nameIdx    = resolveColIdx('Name',               headers)
    def codeIdx    = resolveColIdx('Internal Reference', headers)
    def categIdx   = resolveColIdx('Product category',   headers)
    def hsnIdx     = resolveColIdx('HSN/SAC Code',       headers)
    def priceIdx   = resolveColIdx('Sales Price',        headers)
    def uomIdx     = resolveColIdx('Unit of Measure',    headers)
    def typeIdx    = resolveColIdx('Product Type',       headers)
    def barcodeIdx = resolveColIdx('barcode',            headers)
    def ctaxIdx    = resolveColIdx('Customer Taxes',     headers)
    def vtaxIdx    = resolveColIdx('Vendor Taxes',       headers)

    // Tracking: may have TWO matching columns (bool col + 'By Serial Number' text col)
    def trackCandidates = []
    def trackFieldDef = tableFields['Tracking']
    if (trackFieldDef?.source_col)  trackCandidates << trackFieldDef.source_col.toString().toLowerCase()
    if (trackFieldDef?.source_cols) trackCandidates.addAll(
        (trackFieldDef.source_cols as List).collect { it.toString().toLowerCase() }
    )
    def trackingCols = []
    headers.eachWithIndex { h, i ->
        if (h?.trim()?.toLowerCase() in trackCandidates) trackingCols << i
    }
    def trackIdx  = trackingCols.size() >= 1 ? trackingCols[0] : -1
    def track2Idx = trackingCols.size() >= 2 ? trackingCols[1] : -1

    if (nameIdx < 0) {
        log.error('[TransformProduct_Custom] Name column not found — check mapping.json tables.product_custom.fields.Name.source_cols')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    log.info("[TransformProduct_Custom] Indices — " +
             "id:${idIdx} name:${nameIdx} code:${codeIdx} categ:${categIdx} " +
             "hsn:${hsnIdx} price:${priceIdx} uom:${uomIdx} type:${typeIdx} " +
             "tracking:${trackIdx},${track2Idx} ctax:${ctaxIdx} vtax:${vtaxIdx} barcode:${barcodeIdx}")

    def getCell = { List<String> row, int idx ->
        if (idx < 0 || idx >= row.size()) return ''
        nvl(row[idx])
    }

    // ── 6. Build output CSV ────────────────────────────────────────────────────
    def OUTPUT_COLS = ['id', 'Name', 'Internal Reference', 'Product category',
                       'HSN/SAC Code', 'Sales Price', 'Unit of Measure',
                       'Product Type', 'Tracking',
                       'Customer Taxes', 'Vendor Taxes', 'barcode']

    def outLines = []
    outLines << OUTPUT_COLS.collect { escCsv(it) }.join(',')

    int written = 0, skipped = 0
    Map<String, Integer> seenCodes = [:]

    for (int ri = headerRowIdx + 1; ri < allRows.size(); ri++) {
        def row = allRows[ri]

        def rawName = getCell(row, nameIdx)
        if (!rawName) { skipped++; continue }
        if (rawName.toLowerCase() in skipVals) { skipped++; continue }

        def rowId = cleanId(getCell(row, idIdx))

        // Internal Reference — deduplicate within file
        def rawCode = getCell(row, codeIdx)
        if (rawCode.length() > 64) rawCode = rawCode.take(64)
        if (rawCode) {
            def cnt = (seenCodes[rawCode] ?: 0) + 1
            seenCodes[rawCode] = cnt
            if (cnt > 1) {
                def suffix = "-${cnt}"
                rawCode = rawCode.take(64 - suffix.length()) + suffix
            }
        }

        def cleanUom   = normUom(getCell(row, uomIdx), uomMap, uomAliases)
        def cleanPrice = cleanNum(getCell(row, priceIdx))

        def t1 = getCell(row, trackIdx)
        def t2 = track2Idx >= 0 ? getCell(row, track2Idx) : ''
        def normTrack = normTracking(t1, t2)

        def ctax    = cleanTax(getCell(row, ctaxIdx))
        def vtax    = cleanTax(getCell(row, vtaxIdx))

        def rawBc   = getCell(row, barcodeIdx).replaceAll(/\D/, '')
        def barcode = (rawBc.length() >= 8 && rawBc.length() <= 13) ? rawBc : ''

        outLines << [
            escCsv(rowId),
            escCsv(rawName),
            escCsv(rawCode),
            escCsv(getCell(row, categIdx)),
            escCsv(getCell(row, hsnIdx)),
            escCsv(cleanPrice),
            escCsv(cleanUom),
            escCsv(getCell(row, typeIdx)),
            escCsv(normTrack),
            escCsv(ctax),
            escCsv(vtax),
            escCsv(barcode),
        ].join(',')
        written++
    }

    log.info("[TransformProduct_Custom] Done — ${written} rows written, ${skipped} skipped")

    if (written == 0) {
        log.error('[TransformProduct_Custom] No valid product rows — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 7. Write output into FlowFile ──────────────────────────────────────────
    def csvOut = outLines.join('\n') + '\n'
    flowFile = session.write(flowFile, { is, os ->
        os.write(csvOut.getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    flowFile = session.putAttribute(flowFile, 'transform.rows.written', written.toString())
    flowFile = session.putAttribute(flowFile, 'transform.rows.skipped', skipped.toString())
    flowFile = session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformProduct_Custom] Failed: ' + e.message, e)
    flowFile = session.putAttribute(flowFile, 'error',       e.message)
    flowFile = session.putAttribute(flowFile, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(flowFile, REL_FAILURE)
}

// insert_products_batch.groovy  (NiFi 2.x — products batch, v2)
// Replaces single-record insert_product_template_custom.groovy
//
// Input:  SplitRecord FlowFile — JSON array, up to 500 records
//         JSON keys match TransformProduct_Custom output:
//           id, Name, 'Internal Reference', 'Product category', 'HSN/SAC Code',
//           'Sales Price', 'Unit of Measure', 'Product Type', Tracking,
//           'Customer Taxes', 'Vendor Taxes', barcode
// Output: REL_SUCCESS with row.count / skipped.count / batch.size attributes
//
// Connection pattern (NiFi 2.x — NO cacheConnection, OSql does not support it):
//   Phase 1 (schema probes, UoM, tax): SQL.myPool.eachRow — read-only, no locking.
//   Phase 1 (product categories): SQL.myPool.withTransaction { conn -> } with
//     pg_advisory_xact_lock(3, ?) — lock + check + insert share ONE JDBC connection;
//     lock auto-releases when the transaction commits.
//   Phase 2 (product_template + product_product): SQL.myPool.withTransaction { conn -> }
//     — single JDBC transaction; xidBatch sorted before executeBatch (deadlock prevention).

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import groovy.sql.Sql
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings   ?: [:]
def xidPfx       = customCfg.xid_prefixes    ?: [:]
def uomAliases   = customCfg.uom_aliases      ?: [:]
def prodTypeMap  = customCfg.product_type_map ?: [:]
def globalUomMap = mappings.uom_map           ?: [:]

def tmplXidPfx = xidPfx.product_tmpl ?: 'cust_tmpl_'
def prodXidPfx = xidPfx.product_prod ?: 'cust_prod_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}

def safeBD = { def v ->
    def s = v?.toString()?.trim()?.replaceAll(/,/, '')
    if (!s || s == 'null' || s == '\\N') return BigDecimal.ZERO
    try { return new BigDecimal(s) } catch(ignored) { return BigDecimal.ZERO }
}

def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}

def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(60)
    slug ?: 'unknown'
}

def bindParams = { ps, List params ->
    params.eachWithIndex { v, i ->
        int pos = i + 1
        if (v == null)                    ps.setObject(pos, null)
        else if (v instanceof Long)       ps.setLong(pos, v)
        else if (v instanceof Integer)    ps.setInt(pos, v)
        else if (v instanceof BigDecimal) ps.setBigDecimal(pos, v)
        else if (v instanceof Double)     ps.setDouble(pos, v)
        else if (v instanceof Boolean)    ps.setBoolean(pos, v)
        else                              ps.setString(pos, v.toString())
    }
}

// Normalize UoM name: custom aliases first, then global uom_map, then as-is
def normalizeUom = { String raw ->
    if (!raw) return 'Units'
    def s = raw.trim()
    return uomAliases[s] ?: globalUomMap[s.toLowerCase()] ?: s
}

// Derive finalType / finalTracking / finalIsStorable from CSV columns
def deriveProductType = { String rawType, String trackingStr ->
    def t = rawType?.toLowerCase()?.trim() ?: ''
    def isTracked = (trackingStr?.trim() == 'True')
    def entry = prodTypeMap[t]
    if (entry) {
        return [type: entry.type ?: 'consu', tracking: entry.tracking ?: 'none',
                isStorable: entry.is_storable ?: false]
    }
    if (isTracked) {
        def e = prodTypeMap['__goods_tracked__'] ?: [:]
        return [type: e.type ?: 'consu', tracking: e.tracking ?: 'serial',
                isStorable: e.is_storable != null ? e.is_storable : true]
    }
    def e = prodTypeMap['__goods_default__'] ?: [:]
    return [type: e.type ?: 'consu', tracking: e.tracking ?: 'none',
            isStorable: e.is_storable ?: false]
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[ProductsBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // Lookup maps built in Phase 1, consumed in Phase 2
    def categoryIdMap = [:]
    def uomIdMap      = [:]
    def custTaxIdMap  = [:]
    def vendTaxIdMap  = [:]

    // Schema flags
    def hasTracking        = false
    def hasServiceTracking = false
    def hasInvoicePolicy   = false
    def hasConfigAttribs   = false
    def hasDetailedType    = false
    def hasIsStorable      = false
    def hasHsn             = false
    def hasUomPo           = false
    def hasCombIdx         = false

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 1 — schema probes + pre-resolution
    // Schema probes and read-only lookups: SQL.myPool.eachRow (auto-commit).
    // Category inserts: SQL.myPool.withTransaction { conn -> } with
    //   pg_advisory_xact_lock so lock + check + insert share ONE connection.
    // ════════════════════════════════════════════════════════════════════════

    // ── 3. Schema probes (once per batch) ─────────────────────────────────────
    def ptColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='product_template' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def ppColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='product_product' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }

    hasTracking        = ptColExists('tracking')
    hasServiceTracking = ptColExists('service_tracking')
    hasInvoicePolicy   = ptColExists('invoice_policy')
    hasConfigAttribs   = ptColExists('has_configurable_attributes')
    hasDetailedType    = ptColExists('detailed_type')
    hasIsStorable      = ptColExists('is_storable')
    hasHsn             = ptColExists('l10n_in_hsn_code')
    hasUomPo           = ptColExists('uom_po_id')
    hasCombIdx         = ppColExists('combination_indices')

    log.info("[ProductsBatch] Schema: tracking=${hasTracking} svcTracking=${hasServiceTracking} " +
             "invoicePolicy=${hasInvoicePolicy} configAttribs=${hasConfigAttribs} " +
             "detailedType=${hasDetailedType} isStorable=${hasIsStorable} " +
             "hsn=${hasHsn} uomPo=${hasUomPo} combIdx=${hasCombIdx}")

    // ── 4. Resolve product categories ─────────────────────────────────────────
    // product_category.name is plain VARCHAR (NOT JSONB unlike res_partner_category)
    def uniqueCategs = rows.collect { nvl(it['Product category']) }.findAll { it }.unique()

    uniqueCategs.each { catName ->
        def catCacheKey = 'lookup.product_categ.' + catName
        Long catId      = safeLong(cacheGet(catCacheKey))

        // Fast path — verify cached id still exists in DB
        if (catId) {
            def ok = false
            SQL.myPool.eachRow('SELECT 1 FROM product_category WHERE id=? LIMIT 1', [catId]) { ok = true }
            if (!ok) { cacheSet(catCacheKey, 'CLEARED'); catId = null }
        }

        if (!catId) {
            def catSlug = catName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
            def extId   = 'product_categ_' + catSlug
            def lockKey = (catName.hashCode() & 0x7FFFFFFF) as int

            // Slow path — pg_advisory_xact_lock inside withTransaction ensures
            // lock + check + insert all run on the SAME physical JDBC connection.
            // Lock auto-releases when the transaction commits.
            SQL.myPool.withTransaction { conn ->
                def lockPs = conn.prepareStatement('SELECT pg_advisory_xact_lock(3, ?)')
                lockPs.setInt(1, lockKey)
                lockPs.execute()
                lockPs.close()

                // Re-check cache after acquiring lock
                catId = safeLong(cacheGet(catCacheKey))
                if (catId) {
                    def ps = conn.prepareStatement('SELECT 1 FROM product_category WHERE id=? LIMIT 1')
                    ps.setLong(1, catId)
                    def rs = ps.executeQuery()
                    if (!rs.next()) catId = null
                    rs.close(); ps.close()
                }

                // Check ir_model_data XID
                if (!catId) {
                    def ps = conn.prepareStatement('SELECT res_id FROM ir_model_data WHERE module=? AND name=?')
                    ps.setString(1, module); ps.setString(2, extId)
                    def rs = ps.executeQuery()
                    if (rs.next()) catId = rs.getLong('res_id') ?: null
                    rs.close(); ps.close()
                    if (catId) {
                        def ps2 = conn.prepareStatement('SELECT 1 FROM product_category WHERE id=? LIMIT 1')
                        ps2.setLong(1, catId)
                        def rs2 = ps2.executeQuery()
                        if (!rs2.next()) catId = null
                        rs2.close(); ps2.close()
                    }
                }

                // Check by name directly
                if (!catId) {
                    def ps = conn.prepareStatement('SELECT id FROM product_category WHERE name=? LIMIT 1')
                    ps.setString(1, catName)
                    def rs = ps.executeQuery()
                    if (rs.next()) catId = rs.getLong('id')
                    rs.close(); ps.close()
                }

                // Insert new category
                if (!catId) {
                    def insPs = conn.prepareStatement(
                        "INSERT INTO product_category (name,complete_name,packaging_reserve_method,create_uid,write_uid,create_date,write_date) " +
                        "VALUES (?,?,'at_confirmation',?,?,NOW(),NOW()) RETURNING id"
                    )
                    insPs.setString(1, catName); insPs.setString(2, catName)
                    insPs.setLong(3, adminUid);  insPs.setLong(4, adminUid)
                    def rs = insPs.executeQuery()
                    if (rs.next()) catId = rs.getLong(1)
                    rs.close(); insPs.close()

                    if (catId) {
                        def xidPs = conn.prepareStatement(
                            'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                            'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
                        )
                        xidPs.setString(1, module); xidPs.setString(2, extId)
                        xidPs.setString(3, 'product.category'); xidPs.setLong(4, catId)
                        xidPs.executeUpdate(); xidPs.close()
                        log.info("[ProductsBatch] Category INSERTED: '${catName}' → ${catId}")
                    } else {
                        log.warn("[ProductsBatch] Category INSERT returned no id for: '${catName}'")
                    }
                }

                if (catId) cacheSet(catCacheKey, catId.toString())
                // Transaction commits here; pg_advisory_xact_lock auto-released
            }
        }
        if (catId) categoryIdMap[catName] = catId
    }
    log.info("[ProductsBatch] Categories: ${categoryIdMap.size()} / ${uniqueCategs.size()} resolved")

    // ── 5. Resolve UoM IDs (read-only) ────────────────────────────────────────
    // uom_uom.name is JSONB in Odoo 17 — query via name->>'en_US' ILIKE
    def resolveUomByName = { String normName ->
        if (uomIdMap.containsKey(normName)) return
        Long uomId = safeLong(cacheGet('lookup.uom.' + normName))
        if (!uomId) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE active=true AND (name->>'en_US' ILIKE ? OR name::text ILIKE ?) LIMIT 1",
                [normName, normName]
            ) { r -> uomId = r.getLong('id') }
            if (uomId) cacheSet('lookup.uom.' + normName, uomId.toString())
        }
        if (uomId) uomIdMap[normName] = uomId
    }

    rows.collect { nvl(it['Unit of Measure']) }.findAll { it }.unique().each { raw ->
        resolveUomByName(normalizeUom(raw))
    }

    // Ensure 'Units' fallback is always resolved
    if (!uomIdMap['Units']) {
        Long fbId = safeLong(cacheGet('lookup.uom.Units'))
        if (!fbId) {
            SQL.myPool.eachRow("SELECT id FROM uom_uom WHERE active=true AND name->>'en_US'='Units' LIMIT 1") { r ->
                fbId = r.getLong('id')
            }
            if (fbId) cacheSet('lookup.uom.Units', fbId.toString())
        }
        if (fbId) uomIdMap['Units'] = fbId
    }
    log.info("[ProductsBatch] UoMs resolved: ${uomIdMap.size()}")

    // ── 6. Resolve tax IDs (read-only) ────────────────────────────────────────
    def resolveTax = { String pct, String taxUse, Map targetMap ->
        if (!pct) return
        def cacheKey = "lookup.tax.${taxUse}.${pct}"
        Long taxId = safeLong(cacheGet(cacheKey))
        if (!taxId) {
            try {
                def pctInt = pct.toBigDecimal().intValue()
                SQL.myPool.eachRow(
                    'SELECT id FROM account_tax WHERE active=true AND type_tax_use=? AND company_id=? AND amount::int=? LIMIT 1',
                    [taxUse, compId, pctInt]
                ) { r -> taxId = r.getLong('id') }
                if (taxId) cacheSet(cacheKey, taxId.toString())
            } catch(ignored) {}
        }
        if (taxId) targetMap[pct] = taxId
    }

    rows.collect { nvl(it['Customer Taxes']) }.findAll { it }.unique().each { pct -> resolveTax(pct, 'sale',     custTaxIdMap) }
    rows.collect { nvl(it['Vendor Taxes'])   }.findAll { it }.unique().each { pct -> resolveTax(pct, 'purchase', vendTaxIdMap) }
    log.info("[ProductsBatch] Taxes: sale=${custTaxIdMap.size()} purchase=${vendTaxIdMap.size()}")

    // ── 7. Build INSERT SQL templates ──────────────────────────────────────────
    // product_template — '?' = bound param, literals = hardcoded in SQL
    def tmplCols = ['name','type','uom_id','sale_ok','purchase_ok','active',
                    'list_price','categ_id','default_code','create_uid','write_uid']
    def tmplVals = ['?::jsonb','?','?','true','true','true',
                    '?','?','?','?','?']
    if (hasTracking)        { tmplCols << 'tracking';                    tmplVals << '?'      }
    if (hasServiceTracking) { tmplCols << 'service_tracking';            tmplVals << "'no'"   }
    if (hasConfigAttribs)   { tmplCols << 'has_configurable_attributes'; tmplVals << 'false'  }
    if (hasDetailedType)    { tmplCols << 'detailed_type';               tmplVals << '?'      }
    if (hasIsStorable)      { tmplCols << 'is_storable';                 tmplVals << '?'      }
    if (hasHsn)             { tmplCols << 'l10n_in_hsn_code';            tmplVals << '?'      }
    if (hasUomPo)           { tmplCols << 'uom_po_id';                   tmplVals << '?'      }
    if (hasInvoicePolicy)   { tmplCols << 'invoice_policy';              tmplVals << "'order'"}
                              tmplCols << 'color';                       tmplVals << '0'
                              tmplCols << 'sequence';                    tmplVals << '1'
                              tmplCols << 'create_date';                 tmplVals << 'NOW()'
                              tmplCols << 'write_date';                  tmplVals << 'NOW()'
    def tmplSql = "INSERT INTO product_template (${tmplCols.join(',')}) VALUES (${tmplVals.join(',')}) RETURNING id"

    // product_product — one default variant per template
    def ppCols = ['product_tmpl_id','default_code','barcode','active','standard_price',
                  'create_uid','write_uid']
    def ppVals = ['?','?','?','true','?::jsonb',
                  '?','?']
    if (hasCombIdx) { ppCols << 'combination_indices'; ppVals << "''" }  // MUST be '' not NULL
                      ppCols << 'create_date';         ppVals << 'NOW()'
                      ppCols << 'write_date';          ppVals << 'NOW()'
    def ppSql = "INSERT INTO product_product (${ppCols.join(',')}) VALUES (${ppVals.join(',')}) RETURNING id"

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — single transaction via withTransaction { conn -> }
    // ════════════════════════════════════════════════════════════════════════
    int written = 0, skipped = 0
    def xidBatch     = []
    def custTaxBatch = []
    def vendTaxBatch = []

    SQL.myPool.withTransaction { conn ->
        def tmplPs = conn.prepareStatement(tmplSql)
        def ppPs   = conn.prepareStatement(ppSql)

        def tmplExistsInDb = { Long id ->
            def found = false
            SQL.myPool.eachRow('SELECT 1 FROM product_template WHERE id=? LIMIT 1', [id]) { found = true }
            return found
        }

        rows.each { row ->
            def srcId       = nvl(row['id'])
            def rawName     = nvl(row['Name'])
            def defCode     = nvl(row['Internal Reference'])?.take(64)
            def catName     = nvl(row['Product category'])
            def hsnCode     = nvl(row['HSN/SAC Code'])
            def listPrice   = safeBD(row['Sales Price'])
            def rawUom      = nvl(row['Unit of Measure']) ?: 'Units'
            def rawType     = nvl(row['Product Type']) ?: ''
            def trackingStr = nvl(row['Tracking']) ?: 'False'
            def custTaxPct  = nvl(row['Customer Taxes'])
            def vendTaxPct  = nvl(row['Vendor Taxes'])
            def barcode     = nvl(row['barcode'])

            if (!rawName) { skipped++; return }

            // ── Derive product type / tracking / is_storable ──────────────────
            def typeInfo        = deriveProductType(rawType, trackingStr)
            def finalType       = typeInfo.type == 'product' ? 'consu' : typeInfo.type  // Odoo 17: 'product' → 'consu'
            def finalTracking   = typeInfo.tracking
            def finalIsStorable = typeInfo.isStorable
            // detailed_type: 'storable' when consu+is_storable, else mirrors type
            def detailedType = (finalIsStorable && hasIsStorable) ? 'storable' : finalType

            // ── UoM lookup ────────────────────────────────────────────────────
            def normUom = normalizeUom(rawUom)
            Long uomId  = uomIdMap[normUom] ?: uomIdMap['Units']
            if (!uomId) {
                log.warn("[ProductsBatch] No UoM for '${rawUom}' (normalized='${normUom}') — skipping: ${rawName}")
                skipped++
                return
            }

            def categId   = catName ? categoryIdMap[catName] : null
            def custTaxId = custTaxPct ? custTaxIdMap[custTaxPct] : null
            def vendTaxId = vendTaxPct ? vendTaxIdMap[vendTaxPct] : null

            // ── Build XID keys ────────────────────────────────────────────────
            def xidBase      = srcId ?: (defCode ? slugify(defCode) : slugify(rawName))
            def tmplXid      = tmplXidPfx + slugify(xidBase)
            def prodXid      = prodXidPfx + slugify(xidBase)
            def tmplCacheKey = 'xid.product_template.' + tmplXid

            // ── Idempotency check ─────────────────────────────────────────────
            Long tmplId = null

            def cachedTmpl = cacheGet(tmplCacheKey)
            if (cachedTmpl) {
                def cid = safeLong(cachedTmpl)
                if (cid && tmplExistsInDb(cid)) tmplId = cid
                else cacheSet(tmplCacheKey, 'CLEARED')
            }

            if (!tmplId) {
                SQL.myPool.eachRow('SELECT res_id FROM ir_model_data WHERE module=? AND name=?', [module, tmplXid]) { r ->
                    tmplId = r.getLong('res_id') ?: null
                }
                if (tmplId && !tmplExistsInDb(tmplId)) {
                    SQL.myPool.execute('DELETE FROM ir_model_data WHERE module=? AND name=?', [module, tmplXid])
                    tmplId = null
                }
            }

            // ── Insert product_template + product_product ─────────────────────
            if (!tmplId) {
                def nameJson = '{"en_US":"' + rawName.replace('\\', '\\\\').replace('"', '\\"') + '"}'
                // standard_price JSONB: {str(company_id): list_price}
                def stdPrice = JsonOutput.toJson([(compId.toString()): listPrice.toDouble()])

                // Params match only the '?' placeholders in tmplSql (in order)
                def params = [nameJson, finalType, uomId, listPrice, categId, defCode,
                              adminUid, adminUid] as List
                if (hasTracking)     params << finalTracking
                if (hasDetailedType) params << detailedType
                if (hasIsStorable)   params << finalIsStorable
                if (hasHsn)          params << hsnCode
                if (hasUomPo)        params << uomId

                tmplPs.clearParameters()
                bindParams(tmplPs, params)
                def tmplRs = tmplPs.executeQuery()
                tmplRs.next()
                tmplId = tmplRs.getLong(1)
                tmplRs.close()

                // Insert matching product_product variant
                def ppParams = [tmplId, defCode, barcode, stdPrice, adminUid, adminUid] as List
                ppPs.clearParameters()
                bindParams(ppPs, ppParams)
                def ppRs = ppPs.executeQuery()
                ppRs.next()
                Long prodId = ppRs.getLong(1)
                ppRs.close()

                xidBatch << [module, tmplXid, 'product.template', tmplId]
                xidBatch << [module, prodXid,  'product.product',  prodId]

                cacheSet('cust.prodid.' + (srcId ?: slugify(rawName)), prodId.toString())
                log.info("[ProductsBatch] INSERTED: '${rawName}' → tmpl=${tmplId} prod=${prodId}")
            }

            // Populate cache
            cacheSet(tmplCacheKey, tmplId.toString())
            cacheSet('product.' + rawName, tmplId.toString())
            if (defCode) cacheSet('product.code.' + defCode, tmplId.toString())

            if (custTaxId) custTaxBatch << [tmplId, custTaxId]
            if (vendTaxId) vendTaxBatch << [tmplId, vendTaxId]

            written++
        }

        tmplPs.close()
        ppPs.close()

        // ── Batch: ir_model_data XIDs ──────────────────────────────────────────
        // Sort by XID name — concurrent batches must acquire index locks in the
        // same alphabetical order to prevent deadlocks on ir_model_data.
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m2, n2, mdl, rid ->
                xidPs.setString(1, m2); xidPs.setString(2, n2)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try {
                xidPs.executeBatch()
            } catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.error("[ProductsBatch] XID batch failed — ${bue.message} | PG: ${pg?.getMessage()}")
                throw bue
            }
            xidPs.close()
            log.info("[ProductsBatch] XID batch: ${xidBatch.size()} rows")
        }

        // ── Batch: customer tax rels ──────────────────────────────────────────
        if (custTaxBatch) {
            def ctPs = conn.prepareStatement(
                'INSERT INTO product_taxes_rel (prod_id, tax_id) VALUES (?,?) ON CONFLICT DO NOTHING'
            )
            custTaxBatch.each { pid, tid ->
                ctPs.setLong(1, pid); ctPs.setLong(2, tid)
                ctPs.addBatch()
            }
            try {
                ctPs.executeBatch()
            } catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.error("[ProductsBatch] Cust-tax batch failed — ${bue.message} | PG: ${pg?.getMessage()}")
                throw bue
            }
            ctPs.close()
            log.info("[ProductsBatch] Customer tax rels: ${custTaxBatch.size()} rows")
        }

        // ── Batch: vendor tax rels ────────────────────────────────────────────
        if (vendTaxBatch) {
            def vtPs = conn.prepareStatement(
                'INSERT INTO product_supplier_taxes_rel (prod_id, tax_id) VALUES (?,?) ON CONFLICT DO NOTHING'
            )
            vendTaxBatch.each { pid, tid ->
                vtPs.setLong(1, pid); vtPs.setLong(2, tid)
                vtPs.addBatch()
            }
            try {
                vtPs.executeBatch()
            } catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.error("[ProductsBatch] Vend-tax batch failed — ${bue.message} | PG: ${pg?.getMessage()}")
                throw bue
            }
            vtPs.close()
            log.info("[ProductsBatch] Vendor tax rels: ${vendTaxBatch.size()} rows")
        }

        log.info("[ProductsBatch] Transaction committed — written:${written} skipped:${skipped} " +
                 "xids:${xidBatch.size()} custTaxRels:${custTaxBatch.size()} vendTaxRels:${vendTaxBatch.size()}")

    }   // end withTransaction — auto-commits and returns connection to pool

    // ── Output ────────────────────────────────────────────────────────────────
    ff = session.putAllAttributes(ff, [
        'row.count'    : written.toString(),
        'skipped.count': skipped.toString(),
        'batch.size'   : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[ProductsBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error', e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// LoadSOSerialCache_Custom.groovy
// One-time loader: reads ImportSOTRansferSerial data and stores each row in DMAP.
//
// DMAP key:   so.serial.{id}
// DMAP value: raw SerialNumber string (may be comma-separated for multiple serials,
//             empty/NA/0 for items with no serial tracking)
//
// Run this processor BEFORE insert_so_transfer_custom. The insert script looks up
// 'so.serial.{id}' for each transfer row to create the correct stock_move_line(s).
// Re-running overwrites existing cache entries (safe to re-run).
//
// Input: ImportSOTRansferSerial exported as CSV/TSV (2 columns: id, SerialNumber)
// NiFi flow: GetFile(ImportSOTRansferSerial.csv) → LoadSOSerialCache_Custom → log/discard

import org.apache.nifi.processor.io.InputStreamCallback
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : ''
}

try {
    // ── 1. Read file ──────────────────────────────────────────────────────────
    String rawText = ''
    session.read(flowFile, { is ->
        rawText = new String(is.bytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
    } as InputStreamCallback)

    def allLines = rawText.readLines().findAll { it.trim() }
    if (allLines.size() < 2) {
        log.warn('[LoadSOSerialCache] Empty serial file — nothing to cache')
        session.transfer(flowFile, REL_SUCCESS)
        return
    }

    // ── 2. Detect delimiter ───────────────────────────────────────────────────
    def firstLine = allLines[0]
    def useTab    = firstLine.contains('\t')

    def splitLine = { String line ->
        if (useTab) return line.split('\t', -1).collect { it.trim() }
        // Simple CSV parser (serial file has only 2 columns, minimal quoting)
        def parts = []; def sb2 = new StringBuilder(); boolean inQ = false
        for (int ci = 0; ci < line.length(); ci++) {
            char c = line.charAt(ci)
            if      (c == (char)'"')          { inQ = !inQ }
            else if (c == (char)',' && !inQ)  { parts << sb2.toString().trim(); sb2.setLength(0) }
            else                              { sb2.append(c) }
        }
        parts << sb2.toString().trim()
        return parts
    }

    // ── 3. Resolve column indices ─────────────────────────────────────────────
    def headers = splitLine(allLines[0]).collect { it.toLowerCase().trim() }
    int idCol = headers.indexOf('id')
    int snCol = headers.indexOf('serialnumber')
    if (snCol < 0) snCol = headers.findIndexOf { it.contains('serial') }

    if (idCol < 0 || snCol < 0) {
        log.error("[LoadSOSerialCache] Cannot find 'id' or 'serialnumber' in header: ${headers}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    log.info("[LoadSOSerialCache] id col=${idCol} serial col=${snCol}")

    // ── 4. Load each row into DMAP ────────────────────────────────────────────
    int loaded = 0, skipped = 0

    for (int i = 1; i < allLines.size(); i++) {
        def cells = splitLine(allLines[i])
        def rowId = idCol < cells.size() ? nvl(cells[idCol]).replaceAll(/\.0$/, '') : ''
        def sn    = snCol < cells.size() ? nvl(cells[snCol]) : ''

        if (!rowId) { skipped++; continue }

        // Store even if blank — insert script distinguishes null cache (not loaded)
        // from blank cache (loaded but no serial).
        try {
            CTL.cacheClient.put('so.serial.' + rowId, sn, ser, ser)
            loaded++
        } catch (Exception ex) {
            log.warn("[LoadSOSerialCache] Cache write failed for id=${rowId}: ${ex.message}")
            skipped++
        }
    }

    log.info("[LoadSOSerialCache] Done — ${loaded} entries cached, ${skipped} skipped")
    session.putAttribute(flowFile, 'serial.cache.loaded', loaded.toString())
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[LoadSOSerialCache] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// bootstrap_pre_load_cache_custom.groovy
// Pre-loads all lookup IDs into the distributed cache for the CUSTOM data pipeline.
// Extends the Tally bootstrap with:
//   - All countries by name  (custom data has 15 countries, not just India)
//   - States for all countries (not just India)
//   - Payment terms cache    (invoices + SOs reference payment terms)
//
// FIX: All SQL queries use string concatenation (+) instead of GString interpolation (${}),
// because Groovy SQL treats GString ${} as parameterized placeholders — column names and
// literal integers passed via ${} become '?' parameters and are sent as string values,
// causing every row to return the variable name as a literal instead of the column data.

import groovy.json.JsonOutput

def ff           = session.get() ?: session.create()
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new groovy.json.JsonSlurper().parse(new File(mappingsPath))
def odoo         = mappings.odoo_settings  ?: [:]
def customCfg    = mappings.custom_settings ?: [:]

def ser   = { v, o -> o.write(v.bytes) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b) }       as org.apache.nifi.distributed.cache.client.Deserializer

def cache = CTL.cacheClient

try {

    // ── 1. company_id ─────────────────────────────────────────────────────
    def cfgCompanyId   = (odoo.company_id   as Long)   ?: 0L
    def cfgCompanyName = (odoo.company_name as String)?.trim() ?: ''
    Long compId = null

    if (cfgCompanyId) {
        SQL.myPool.eachRow(
            "SELECT id FROM res_company WHERE id = ?", [cfgCompanyId]
        ) { row -> compId = row.getLong('id') }
        if (compId) log.info("Company resolved by company_id=${compId}")
    }

    if (!compId && cfgCompanyName) {
        SQL.myPool.eachRow(
            "SELECT id FROM res_company WHERE lower(name::text) = lower(?) LIMIT 1", [cfgCompanyName]
        ) { row -> compId = row.getLong('id') }
        if (compId) log.info("Company resolved by company_name='${cfgCompanyName}' → id=${compId}")
    }

    if (!compId) {
        def allCompanies = []
        SQL.myPool.eachRow("SELECT id, name FROM res_company ORDER BY id") { row ->
            allCompanies << "  id=${row.getLong('id')}  name=${row.getString('name')}"
        }
        throw new Exception(
            "res_company not found: company_id=${cfgCompanyId}, company_name='${cfgCompanyName}'.\n" +
            "Available:\n${allCompanies.join('\n')}\nFix odoo_settings in mapping.json."
        )
    }

    cache.put('lookup.company_id', compId.toString(), ser, ser)
    cache.put('lookup.admin_uid',  '1', ser, ser)
    log.info("Cached company_id=${compId}")

    // ── 2. Tax activation ─────────────────────────────────────────────────
    def taxPs = SQL.myPool.connection.prepareStatement(
        "UPDATE account_tax SET active = true WHERE company_id = ? AND active = false"
    )
    taxPs.setLong(1, compId)
    def activatedCount = taxPs.executeUpdate()
    taxPs.close()
    log.info("Activated ${activatedCount} inactive taxes for company_id=${compId}")

    // ── 3. currency_id (INR) ──────────────────────────────────────────────
    def currencyId
    SQL.myPool.eachRow(
        "SELECT id FROM res_currency WHERE name = 'INR' ORDER BY active DESC LIMIT 1"
    ) { row -> currencyId = row.getLong(1) }
    if (!currencyId) throw new Exception("res_currency 'INR' not found")
    cache.put('lookup.currency_id',     currencyId.toString(), ser, ser)
    cache.put('lookup.currency_id_inr', currencyId.toString(), ser, ser)
    log.info("Cached currency_id=${currencyId}")

    // ── Helper: detect if a table's name column is jsonb ──────────────────
    // Uses plain string concatenation — NOT GString — so the table name is
    // embedded as a literal SQL identifier, not sent as a '?' parameter.
    def getNameColType = { String tableName ->
        def colType = ''
        SQL.myPool.eachRow(
            "SELECT data_type FROM information_schema.columns" +
            " WHERE table_name = '" + tableName + "' AND column_name = 'name'"
        ) { row -> colType = row.getString(1) }
        return colType
    }

    // ── 4. All countries by name ──────────────────────────────────────────
    def countryAliases = customCfg.country_aliases ?: [
        'UK'  : 'United Kingdom',
        'UAE' : 'United Arab Emirates',
        'USA' : 'United States',
        'US'  : 'United States',
    ]

    def countryNameCol = getNameColType('res_country') == 'jsonb'
        ? "name->>'en_US'"
        : "name"

    def countries = [:]
    Long indiaId = null

    // String concatenation produces a plain String — Groovy SQL will NOT
    // treat countryNameCol as a parameter, so it is embedded as SQL text.
    SQL.myPool.eachRow(
        "SELECT id, code, " + countryNameCol + " AS cname FROM res_country ORDER BY id"
    ) { row ->
        def cname = row.getString('cname')
        def cid   = row.getLong('id')
        def code  = row.getString('code')
        if (cname) {
            countries[cname] = cid
            cache.put("lookup.country." + cname, cid.toString(), ser, ser)
        }
        if (code == 'IN') {
            indiaId = cid
            cache.put('lookup.country_id',    cid.toString(), ser, ser)
            cache.put('lookup.country_id_in', cid.toString(), ser, ser)
        }
    }

    countryAliases.each { alias, canonical ->
        if (canonical && countries[canonical]) {
            cache.put("lookup.country." + alias, countries[canonical].toString(), ser, ser)
            log.info("Country alias '${alias}' → '${canonical}' id=${countries[canonical]}")
        } else {
            cache.put("lookup.country." + alias, '0', ser, ser)
            log.info("Country alias '${alias}' has no Odoo mapping — cached as 0")
        }
    }

    if (!indiaId) throw new Exception("res_country code='IN' not found")
    log.info("Cached ${countries.size()} countries")

    // ── 5. States for ALL countries ───────────────────────────────────────
    def stateNameCol = getNameColType('res_country_state') == 'jsonb'
        ? "name->>'en_US'"
        : "name"

    def states = [:]
    SQL.myPool.eachRow(
        "SELECT id, country_id, " + stateNameCol + " AS sname FROM res_country_state"
    ) { row ->
        def sname = row.getString('sname')
        def sid   = row.getLong('id')
        def cid   = row.getLong('country_id')
        if (sname) {
            states[sname] = sid
            cache.put("lookup.state." + sname, sid.toString(), ser, ser)
            cache.put("lookup.state." + cid + "." + sname, sid.toString(), ser, ser)
        }
    }
    log.info("Cached ${states.size()} states (all countries)")

    // ── 6. UOMs ───────────────────────────────────────────────────────────
    def uomNameCol = getNameColType('uom_uom') == 'jsonb'
        ? "name->>'en_US'"
        : "name"

    def uoms = [:]
    SQL.myPool.eachRow(
        "SELECT id, " + uomNameCol + " AS uname FROM uom_uom WHERE active = true"
    ) { row ->
        def uname = row.getString('uname')
        if (uname) {
            uoms[uname] = row.getLong('id')
            cache.put("lookup.uom." + uname, row.getLong('id').toString(), ser, ser)
        }
    }
    def uomAliases = customCfg.uom_aliases ?: ['Nos.': 'Units', 'Nos': 'Units', 'NOS': 'Units',
                                                'Mtr.': 'm',     'Mtr': 'm',     'MTR': 'm']
    uomAliases.each { alias, canonical ->
        def canonId = uoms[canonical]
        if (canonId) cache.put("lookup.uom." + alias, canonId.toString(), ser, ser)
    }
    log.info("Cached UOMs: ${uoms.size()} entries")

    // ── 7. Journals ───────────────────────────────────────────────────────
    def journalNameCol = getNameColType('account_journal') == 'jsonb'
        ? "name->>'en_US'"
        : "name"

    def journals = [:]
    SQL.myPool.eachRow(
        "SELECT id, type, " + journalNameCol + " AS jname" +
        " FROM account_journal WHERE company_id = " + compId + " AND active = true"
    ) { row ->
        def jname = row.getString('jname')
        def jtype = row.getString('type')
        if (jname) {
            journals[jname] = row.getLong('id')
            cache.put("lookup.journal." + jname, row.getLong('id').toString(), ser, ser)
        }
        if (jtype && !journals.containsKey("__type." + jtype)) {
            cache.put("lookup.journal.type." + jtype, row.getLong('id').toString(), ser, ser)
            journals["__type." + jtype] = row.getLong('id')
        }
    }
    log.info("Cached journals: ${journals.size()} entries")

    // ── 8. Payment terms ──────────────────────────────────────────────────
    def ptNameCol = getNameColType('account_payment_term') == 'jsonb'
        ? "name->>'en_US'"
        : "name"

    def payterms = [:]
    SQL.myPool.eachRow(
        "SELECT id, " + ptNameCol + " AS ptname FROM account_payment_term WHERE active = true"
    ) { row ->
        def ptname = row.getString('ptname')
        if (ptname) {
            payterms[ptname] = row.getLong('id')
            cache.put("lookup.payterm." + ptname, row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached payment terms: ${payterms.size()} entries")

    // ── 9. Product categories ─────────────────────────────────────────────
    def categ = [:]
    SQL.myPool.eachRow(
        "SELECT id, name FROM product_category ORDER BY id"
    ) { row ->
        def cname = row.getString('name')
        if (cname) {
            categ[cname] = row.getLong('id')
            cache.put("lookup.product_category." + cname, row.getLong('id').toString(), ser, ser)
            cache.put("category." + cname, row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached product categories: ${categ.size()} entries")

    // ── 10. Tax lookup by amount ──────────────────────────────────────────
    SQL.myPool.eachRow(
        "SELECT id, amount::int AS pct, type_tax_use" +
        " FROM account_tax" +
        " WHERE active = true" +
        " AND company_id = " + compId +
        " AND amount_type = 'percent'" +
        " AND amount > 0" +
        " ORDER BY (company_id = " + compId + ") DESC, id"
    ) { row ->
        def pct = row.getInt('pct')
        def use = row.getString('type_tax_use')
        def key = "lookup.tax." + use + "." + pct
        try {
            def existing = cache.get(key, ser, deser)
            if (!existing) cache.put(key, row.getLong('id').toString(), ser, ser)
        } catch(ignored) {
            cache.put(key, row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Tax lookup by amount cached")

    // ── 11. Summary FlowFile ──────────────────────────────────────────────
    def payload = [
        company_id   : compId,
        currency_id  : currencyId,
        country_id   : indiaId,
        country_count: countries.size(),
        state_count  : states.size(),
        uom_count    : uoms.size(),
        journal_count: journals.size(),
        payterm_count: payterms.size(),
        categ_count  : categ.size(),
    ]

    def jsonOutput = JsonOutput.prettyPrint(JsonOutput.toJson(payload))
    log.info("Bootstrap (custom) complete: all lookup IDs cached")

    ff = session.write(ff, { outputStream ->
        outputStream.write(jsonOutput.getBytes('UTF-8'))
    } as org.apache.nifi.processor.io.OutputStreamCallback)

    session.putAttribute(ff, 'mime.type', 'application/json')
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error("Bootstrap error: ${e.message}", e)
    session.transfer(ff ?: (session.get() ?: session.create()), REL_FAILURE)
}

// TransformBOM_Custom.groovy
// Full-file BOM CSV transformer for Nevco custom BOM data.
// Each source row = one BOM header + one BOM line (product-level BOM).
//
// NiFi flow:
//   TransformBOM_Custom → SplitRecord → insert_bom_custom
//
// Source columns (case-insensitive lookup):
//   id, Pid, bomid, RefSOid, ProductName, Code, Description, HSN, Model, Brand,
//   Sno, CustomerNameId, CustomerAddressID, ContactPersonID, FyName, TotalPrice,
//   CompanyName, Address, Name, Email, Mobile, CustomerGSTNo, GSTTYpe, State,
//   UniqueSno, Price, Quantity, Totalamount, Discount, AfterDiscount, Tax,
//   Taxamount, GrandTotal, StatusName, BranchName, Branchid, Currency, Rate,
//   UserName, HeadName, Formats, DecimalPlace, Approved, ApprovalDate,
//   ApprovalTime, bid, BranchHeadName, QuotationStatus, SONo, ProjectNo,
//   fileNo, Unit, UnitName, SubUnitName
//
// Output columns (subset needed by insert_bom_custom):
//   id, bomid, Pid, RefSOid, Code, ProductName, Description, HSN,
//   Sno, CustomerNameId, CustomerAddressID, ContactPersonID,
//   Quantity, UnitName, Unit, Price, Tax, BranchName, Branchid, StatusName, SONo

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

// ── Helpers ───────────────────────────────────────────────────────────────────

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : ''
}

def escCsv = { String v ->
    // NiFi CSVReader: Escape Character = \
    // Quote empty fields as "" to prevent trailing-field drop.
    // Double-backslash inside quoted fields so NiFi reads literal \.
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def cleanNum = { String raw ->
    if (!raw) return '0'
    def s = raw.trim().replaceAll(/[,\s]/, '')
    // Handle scientific notation (e.g. 9.19E+11 for mobile numbers)
    if (s =~ /^[\d.]+[Ee][+\-]?\d+$/) {
        try {
            // Convert scientific notation to plain decimal string
            def bd = new BigDecimal(s)
            return bd.toPlainString().replaceAll(/\.0+$/, '')
        } catch (ignored) { return '0' }
    }
    if (s =~ /^\([\d.]+\)$/) s = '-' + s.replaceAll(/[()]/, '')
    if (!s || s == '-' || s == '.') return '0'
    try { Double.parseDouble(s); return s } catch (ignored) { return '0' }
}

// Robust CSV row assembler — handles multi-line quoted fields.
// Returns list of complete logical rows (each a raw line string that may span
// multiple physical lines when a field contains embedded newlines).
def assembleRows = { String text ->
    def rows = []
    def sb   = new StringBuilder()
    int qCount = 0
    text.eachLine { line ->
        if (sb.length() > 0) sb.append('\n')
        sb.append(line)
        // Count quote chars in this line to track open/close state.
        // Paired "" inside quoted fields add 2 (even), so parity is preserved.
        qCount += line.count('"')
        if (qCount % 2 == 0) {
            // Even count → no open quoted field → row is complete
            rows << sb.toString()
            sb.setLength(0)
            qCount = 0
        }
    }
    if (sb.length() > 0) rows << sb.toString()
    return rows
}

// Parse one logical CSV row into cells (handles quoted fields with embedded
// commas and doubled-quote escapes inside quoted strings).
def parseCsvRow = { String line ->
    def cells = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)'"') {
                sb.append('"'); ci++  // "" → literal quote inside field
            } else {
                inQ = !inQ
            }
        } else if (c == (char)',' && !inQ) {
            cells << sb.toString(); sb.setLength(0)
        } else {
            sb.append(c)
        }
    }
    cells << sb.toString()
    return cells
}

try {
    // ── 1. Read file ──────────────────────────────────────────────────────────
    String rawText = ''
    session.read(flowFile, { is ->
        rawText = new String(is.bytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
    } as InputStreamCallback)

    if (!rawText.trim()) {
        log.warn('[TransformBOM_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Detect delimiter (tab or comma) ────────────────────────────────────
    // Check header line for tabs; fall back to comma-based parser if tabs found.
    def firstLine = rawText.readLines().find { it.trim() } ?: ''
    def useTab    = firstLine.contains('\t')

    List<String> logicalRows
    List<String> headerCells

    if (useTab) {
        // Tab-delimited: no multi-line quoting in tab files; simple split per line
        def lines = rawText.readLines().findAll { it.trim() }
        logicalRows = lines
        headerCells = lines[0].split('\t', -1).collect { it.trim() }
    } else {
        logicalRows = assembleRows(rawText).findAll { it.trim() }
        headerCells = parseCsvRow(logicalRows[0]).collect { it.trim() }
    }

    if (logicalRows.size() < 2) {
        log.warn('[TransformBOM_Custom] No data rows found')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Build header index (case-insensitive) ──────────────────────────────
    def hdrIdx = [:]
    headerCells.eachWithIndex { h, i -> def k = h?.toLowerCase()?.trim() ?: ''; if (k) hdrIdx[k] = i }

    def get = { List cells, int idx ->
        idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx])
    }

    def mappingsPath  = flowFile.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
    def tableFields   = new JsonSlurper().parse(new File(mappingsPath)).tables?.bom_custom?.fields ?: [:]
    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) return -1
        def aliases = []
        if (fDef.source_col) aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        for (String alias in aliases) { def k = alias.toLowerCase(); if (hdrIdx.containsKey(k)) return hdrIdx[k] }
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            def found = hdrIdx.find { hk, hv -> hk && (hk.contains(k) || k.contains(hk)) }
            if (found) return found.value
        }
        return -1
    }

    // ── 4. Locate each column ─────────────────────────────────────────────────
    def idIdx       = resolveColIdx('id')
    def bomIdIdx    = resolveColIdx('bomid')
    def pidIdx      = resolveColIdx('Pid')
    def refSoIdx    = resolveColIdx('RefSOid')
    def codeIdx     = resolveColIdx('Code')
    def nameIdx     = resolveColIdx('ProductName')
    def descIdx     = resolveColIdx('Description')
    def hsnIdx      = resolveColIdx('HSN')
    def snoIdx      = resolveColIdx('Sno')
    def custNmIdx   = resolveColIdx('CustomerNameId')
    def custAdIdx   = resolveColIdx('CustomerAddressID')
    def contactIdx  = resolveColIdx('ContactPersonID')
    def qtyIdx      = resolveColIdx('Quantity')
    def unitNmIdx   = resolveColIdx('UnitName')
    def unitIdx     = resolveColIdx('Unit')
    def priceIdx    = resolveColIdx('Price')
    def taxIdx      = resolveColIdx('Tax')
    def branchNmIdx = resolveColIdx('BranchName')
    def branchIdIdx = resolveColIdx('Branchid')
    def statusIdx   = resolveColIdx('StatusName')
    def soNoIdx     = resolveColIdx('SONo')

    if (idIdx < 0 || bomIdIdx < 0) {
        log.error("[TransformBOM_Custom] Cannot find 'id' or 'bomid' columns. hdrIdx=${hdrIdx}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    log.info("[TransformBOM_Custom] id:${idIdx} bomid:${bomIdIdx} code:${codeIdx} " +
             "qty:${qtyIdx} unitName:${unitNmIdx} custNameId:${custNmIdx}")

    // ── 5. Fixed output columns ───────────────────────────────────────────────
    def COLS = ['id', 'bomid', 'Pid', 'RefSOid', 'Code', 'ProductName', 'Description',
                'HSN', 'Sno', 'CustomerNameId', 'CustomerAddressID', 'ContactPersonID',
                'Quantity', 'UnitName', 'Unit', 'Price', 'Tax',
                'BranchName', 'Branchid', 'StatusName', 'SONo']

    def sb = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0

    // ── 6. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < logicalRows.size(); i++) {
        def cells = useTab
            ? logicalRows[i].split('\t', -1).collect { nvl(it) }
            : parseCsvRow(logicalRows[i])

        def rowId = get(cells, idIdx).replaceAll(/\.0$/, '')
        if (!rowId || rowId.toLowerCase() in ['id', 'row id', 'rowid']) { skipped++; continue }

        def bomId = get(cells, bomIdIdx).replaceAll(/\.0$/, '')
        if (!bomId) { skipped++; continue }

        def qty = cleanNum(get(cells, qtyIdx))
        // Skip rows where quantity is 0 — likely totals/summary lines
        if (qty == '0') { skipped++; continue }

        def pid      = get(cells, pidIdx).replaceAll(/\.0$/, '')
        def refSoId  = get(cells, refSoIdx).replaceAll(/\.0$/, '')
        def code     = get(cells, codeIdx)
        def prodName = get(cells, nameIdx)

        // Description: already multi-line merged by assembleRows; replace embedded newlines with space
        def desc     = get(cells, descIdx).replaceAll(/\s*[\r\n]+\s*/, ' ').trim()

        def hsn      = get(cells, hsnIdx)
        def sno      = get(cells, snoIdx).replaceAll(/\.0$/, '')
        def custNmId = get(cells, custNmIdx).replaceAll(/\.0$/, '')
        def custAdId = get(cells, custAdIdx).replaceAll(/\.0$/, '')
        def contactId= get(cells, contactIdx).replaceAll(/\.0$/, '')
        def unitNm   = get(cells, unitNmIdx)
        def unit     = get(cells, unitIdx).replaceAll(/\.0$/, '')
        def price    = cleanNum(get(cells, priceIdx))
        def tax      = cleanNum(get(cells, taxIdx))
        def branch   = get(cells, branchNmIdx)
        def branchId = get(cells, branchIdIdx).replaceAll(/\.0$/, '')
        def status   = get(cells, statusIdx)
        def soNo     = get(cells, soNoIdx)

        def row = [rowId, bomId, pid, refSoId, code, prodName, desc,
                   hsn, sno, custNmId, custAdId, contactId,
                   qty, unitNm, unit, price, tax,
                   branch, branchId, status, soNo]

        sb.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[TransformBOM_Custom] No valid rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 7. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformBOM_Custom] Done — ${written} rows, ${skipped} skipped")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformBOM_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// insert_bom_batch.groovy  (NiFi 2.x — BOM batch)
//
// NiFi flow: TransformBOM_Custom → SplitRecord(500/split, JSON array writer) → [THIS]
//
// Input:  JSON array — multiple rows can share the same bomid
// Action: For each unique bomid INSERT one mrp_bom header;
//         For each row INSERT one mrp_bom_line referencing that header
// Output: Pass-through with bom.written / bom_line.written / bom.skipped attributes
//
// Idempotency:
//   BOM header — XID: {bomXidPfx}{bomid}         → mrp.bom
//   BOM line   — XID: {bomLineXidPfx}{rowId}      → mrp.bom.line
//
// IMPORTANT: All SQL.myPool.eachRow calls MUST stay outside withTransaction.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]
def uomAliases   = customCfg.uom_aliases     ?: [:]

def bomXidPfx     = xidPfx.bom          ?: 'cust_bom_'
def bomLineXidPfx = xidPfx.bom_line     ?: 'cust_bom_line_'
def tmplXidPfx    = xidPfx.product_tmpl ?: 'cust_tmpl_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == '\\N' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) {}
    try { return (long) s.toDouble() } catch (ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def sl = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
              .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(60)
    sl ?: 'unknown'
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[BOMBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // ── 3. Product resolution helper (6-level, defined here to access module) ─
    def resolveProduct = { String code, String pid, String prodName ->
        Long tmplId = null
        Long varId  = null

        // 1. Cache by internal reference code
        if (code) tmplId = safeLong(cacheGet('product.code.' + code))

        // 2. Cache by source pid → variant → template
        if (pid) varId = safeLong(cacheGet('cust.prodid.' + pid))
        if (!tmplId && varId) {
            SQL.myPool.eachRow('SELECT product_tmpl_id FROM product_product WHERE id=? LIMIT 1', [varId]) { r ->
                tmplId = safeLong(r['product_tmpl_id'])
            }
        }

        // 3. XID: cust_tmpl_{slug(code)}
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='product.template' LIMIT 1",
                [module, tmplXidPfx + slugify(code)]
            ) { r -> tmplId = safeLong(r['res_id']) }
        }

        // 4. XID: tally product format TALLY_PRODUCT_RC_{slug}
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='product.template' LIMIT 1",
                [module, 'tally_product_template_TALLY_PRODUCT_RC_' + slugify(code)]
            ) { r -> tmplId = safeLong(r['res_id']) }
        }

        // 5. Direct default_code match
        if (!tmplId && code) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_template WHERE default_code=? AND active=true LIMIT 1", [code]
            ) { r -> tmplId = safeLong(r['id']) }
        }

        // 6. Name ILIKE fallback
        if (!tmplId && prodName) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_template WHERE name::text ILIKE ? AND active=true LIMIT 1", [prodName]
            ) { r -> tmplId = safeLong(r['id']) }
        }

        // Resolve variant from template
        if (tmplId && !varId) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_product WHERE product_tmpl_id=? AND active=true LIMIT 1", [tmplId]
            ) { r -> varId = safeLong(r['id']) }
        }
        if (!varId && tmplId) varId = tmplId  // single-variant fallback

        return [tmplId: tmplId, varId: varId]
    }

    // ── 4. UOM resolution helper ──────────────────────────────────────────────
    def resolveUom = { String unitName ->
        def resolvedName = unitName
            ? (uomAliases[unitName] ?: uomAliases[unitName.replaceAll(/\.$/, '')] ?: unitName)
            : 'Units'
        Long uomId = safeLong(cacheGet('lookup.uom.' + resolvedName))
        if (!uomId && resolvedName) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE ? AND active=true LIMIT 1", [resolvedName]
            ) { r ->
                uomId = safeLong(r['id'])
                if (uomId) cacheSet('lookup.uom.' + resolvedName, uomId.toString())
            }
        }
        if (!uomId && unitName && unitName != resolvedName) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE ? AND active=true LIMIT 1", [unitName]
            ) { r -> uomId = safeLong(r['id']) }
        }
        if (!uomId) {
            SQL.myPool.eachRow(
                "SELECT id FROM uom_uom WHERE name::text ILIKE 'Units' AND active=true LIMIT 1"
            ) { r -> uomId = safeLong(r['id']) }
            if (!uomId) uomId = 1L
        }
        return uomId
    }

    // ── 5. Group rows by bomid — first row per bomid = header data ─────────────
    def bomGroups = [:]  // bomid → first row
    rows.each { row ->
        def bomIdRaw = nvl(row['bomid'])
        if (!bomIdRaw) return
        def bomId = bomIdRaw.replaceAll(/\.0$/, '')
        if (!bomGroups.containsKey(bomId)) bomGroups[bomId] = row
    }
    log.info("[BOMBatch] Unique bomids: ${bomGroups.size()}")

    // ── 6. Phase 1: BOM header idempotency + product resolution ───────────────
    def existingBomDbIds = [:]  // bomid → Long dbId (pre-existing)
    def bomItemsToInsert = []   // headers that need INSERT
    def cacheUpdates     = []
    int skipCount        = 0

    bomGroups.each { bomId, row ->
        def bomXid = bomXidPfx + bomId
        def bomCk  = 'xid.bom.' + bomXid

        // Idempotency: cache
        Long dbId = safeLong(cacheGet(bomCk))
        if (dbId) {
            def found = false
            SQL.myPool.eachRow('SELECT id FROM mrp_bom WHERE id=? LIMIT 1', [dbId]) { found = true }
            if (!found) { cacheSet(bomCk, 'CLEARED'); dbId = null }
        }
        // Idempotency: ir_model_data
        if (!dbId) {
            SQL.myPool.eachRow(
                'SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model=? LIMIT 1',
                [module, bomXid, 'mrp.bom']
            ) { r ->
                def rid = safeLong(r['res_id'])
                if (rid) {
                    def found = false
                    SQL.myPool.eachRow('SELECT id FROM mrp_bom WHERE id=? LIMIT 1', [rid]) { found = true }
                    if (found) dbId = rid
                    // stale ir_model_data row cleaned in Phase 2
                }
            }
        }

        if (dbId) {
            existingBomDbIds[bomId] = dbId
            cacheUpdates << [bomCk, dbId.toString()]
            log.info("[BOMBatch] BOM already exists: ${bomXid} → ${dbId}")
            return
        }

        // Product resolution for this BOM header
        def code     = nvl(row['Code'])
        def pid      = nvl(row['Pid'])
        def prodName = nvl(row['ProductName'])
        def unitName = nvl(row['UnitName'])
        def snoRaw   = nvl(row['Sno'])

        if (!code && !prodName) {
            log.warn("[BOMBatch] No Code/ProductName for bomid=${bomId} — skipping BOM")
            skipCount++; return
        }

        def prod = resolveProduct(code, pid, prodName)
        if (!prod.tmplId) {
            log.warn("[BOMBatch] Product not resolved: bomid=${bomId} code=${code} name=${prodName} — skipping BOM")
            skipCount++; return
        }

        Long uomId = resolveUom(unitName)
        int sno    = safeLong(snoRaw)?.intValue() ?: 1

        bomItemsToInsert << [
            bomId  : bomId,
            bomXid : bomXid,
            bomCk  : bomCk,
            tmplId : prod.tmplId,
            varId  : prod.varId,
            uomId  : uomId,
            sno    : sno,
        ]
    }

    // Set of bomids with no header (neither existing nor insertable) — lines skipped
    def resolvedBomIds = new HashSet(existingBomDbIds.keySet())
    bomItemsToInsert.each { resolvedBomIds.add(it.bomId) }
    def failedBomIds = bomGroups.keySet().findAll { !resolvedBomIds.contains(it) } as Set

    // ── 7. Phase 1: BOM line idempotency + product resolution ─────────────────
    def lineItems = []

    rows.each { row ->
        def rowId    = nvl(row['id'])
        def bomIdRaw = nvl(row['bomid'])
        if (!rowId || !bomIdRaw) { skipCount++; return }
        def bomId = bomIdRaw.replaceAll(/\.0$/, '')

        if (failedBomIds.contains(bomId)) {
            skipCount++; return  // parent BOM couldn't be resolved
        }

        def qty = safeBD(row['Quantity'])
        if (qty <= BigDecimal.ZERO) {
            log.warn("[BOMBatch] Zero qty: bomid=${bomId} rowId=${rowId} — skipping")
            skipCount++; return
        }

        def code     = nvl(row['Code'])
        def prodName = nvl(row['ProductName'])
        if (!code && !prodName) {
            log.warn("[BOMBatch] No Code/ProductName for rowId=${rowId} — skipping line")
            skipCount++; return
        }

        // Line idempotency
        def lineXid = bomLineXidPfx + rowId
        Long existingLineId = null
        SQL.myPool.eachRow(
            'SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model=? LIMIT 1',
            [module, lineXid, 'mrp.bom.line']
        ) { r ->
            def rid = safeLong(r['res_id'])
            if (rid) {
                def found = false
                SQL.myPool.eachRow('SELECT id FROM mrp_bom_line WHERE id=? LIMIT 1', [rid]) { found = true }
                if (found) existingLineId = rid
            }
        }
        if (existingLineId) { skipCount++; return }

        // Component product resolution
        def pid      = nvl(row['Pid'])
        def unitName = nvl(row['UnitName'])
        def snoRaw   = nvl(row['Sno'])

        def prod = resolveProduct(code, pid, prodName)
        if (!prod.tmplId) {
            log.warn("[BOMBatch] Component product not resolved: bomid=${bomId} rowId=${rowId} code=${code} — skipping line")
            skipCount++; return
        }

        Long uomId = resolveUom(unitName)
        int sno    = safeLong(snoRaw)?.intValue() ?: 1

        lineItems << [
            rowId  : rowId,
            bomId  : bomId,
            lineXid: lineXid,
            tmplId : prod.tmplId,
            varId  : prod.varId,
            uomId  : uomId,
            qty    : qty,
            sno    : sno,
        ]
    }

    log.info("[BOMBatch] BOM headers to insert: ${bomItemsToInsert.size()}, lines to insert: ${lineItems.size()}, skip: ${skipCount}")

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: only conn.prepareStatement inside
    // ════════════════════════════════════════════════════════════════════════
    int bomWritten  = 0
    int lineWritten = 0
    def xidBatch    = []

    SQL.myPool.withTransaction { conn ->
        // Working map: bomid → dbId (pre-existing + newly inserted)
        def bomIdMap = new HashMap(existingBomDbIds)

        // ── INSERT mrp_bom headers ────────────────────────────────────────────
        bomItemsToInsert.each { item ->
            // Clean stale XID
            def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
            delPs.setString(1, module); delPs.setString(2, item.bomXid)
            delPs.executeUpdate(); delPs.close()

            def bomPs = conn.prepareStatement("""
                INSERT INTO mrp_bom
                  (product_tmpl_id, product_id, product_uom_id, product_qty,
                   type, code, sequence,
                   ready_to_produce, consumption, active,
                   company_id, create_uid, write_uid, create_date, write_date)
                VALUES (?,?,?,1.0,'normal',?,?,'all','allowed',true,?,?,?,NOW(),NOW())
                RETURNING id
            """)
            int p = 1
            bomPs.setLong(p++, item.tmplId)
            bomPs.setLong(p++, item.varId)
            bomPs.setLong(p++, item.uomId)
            bomPs.setString(p++, item.bomId)   // code = bomid as human-readable reference
            bomPs.setInt(p++,    item.sno)
            bomPs.setLong(p++, compId)
            bomPs.setLong(p++, adminUid)
            bomPs.setLong(p++, adminUid)
            def rs = bomPs.executeQuery()
            rs.next(); long bomDbId = rs.getLong(1); rs.close(); bomPs.close()

            bomIdMap[item.bomId] = bomDbId
            xidBatch     << [module, item.bomXid, 'mrp.bom', bomDbId]
            cacheUpdates << [item.bomCk, bomDbId.toString()]
            log.info("[BOMBatch] mrp_bom INSERTED: ${item.bomXid} → ${bomDbId}")
            bomWritten++
        }

        // ── INSERT mrp_bom_line rows ──────────────────────────────────────────
        lineItems.each { item ->
            Long bomDbId = bomIdMap[item.bomId]
            if (!bomDbId) {
                log.warn("[BOMBatch] No bom_id for bomId=${item.bomId} lineXid=${item.lineXid} — skipping")
                return
            }

            def lnPs = conn.prepareStatement("""
                INSERT INTO mrp_bom_line
                  (bom_id, product_id, product_tmpl_id, product_uom_id, product_qty,
                   sequence, company_id, create_uid, write_uid, create_date, write_date)
                VALUES (?,?,?,?,?,?,?,?,?,NOW(),NOW())
                RETURNING id
            """)
            int lp = 1
            lnPs.setLong(lp++, bomDbId)
            lnPs.setLong(lp++, item.varId)
            lnPs.setLong(lp++, item.tmplId)
            lnPs.setLong(lp++, item.uomId)
            lnPs.setBigDecimal(lp++, item.qty)
            lnPs.setInt(lp++, item.sno)
            lnPs.setLong(lp++, compId)
            lnPs.setLong(lp++, adminUid)
            lnPs.setLong(lp++, adminUid)
            def lnRs = lnPs.executeQuery()
            lnRs.next(); long lineDbId = lnRs.getLong(1); lnRs.close(); lnPs.close()

            xidBatch << [module, item.lineXid, 'mrp.bom.line', lineDbId]
            log.info("[BOMBatch] mrp_bom_line INSERTED: ${item.lineXid} → ${lineDbId} (bom=${bomDbId} qty=${item.qty})")
            lineWritten++
        }

        // ── Batch XID inserts (sorted to prevent deadlocks) ───────────────────
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m, n, mdl, rid ->
                xidPs.setString(1, m); xidPs.setString(2, n)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try { xidPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                log.error("[BOMBatch] XID batch failed: ${bue.message}")
                throw bue
            }
            xidPs.close()
        }

        log.info("[BOMBatch] Committed — bom:${bomWritten} lines:${lineWritten}")
    }

    // Post-commit cache
    cacheUpdates.each { ck, v -> cacheSet(ck, v) }

    ff = session.putAllAttributes(ff, [
        'bom.written'     : bomWritten.toString(),
        'bom_line.written': lineWritten.toString(),
        'bom.skipped'     : skipCount.toString(),
        'batch.size'      : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[BOMBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// insert_payment_batch.groovy  (NiFi 2.x — payment batch)
//
// NiFi flow: TransformPayment → SplitRecord(500/split, JSON array writer) → [THIS]
//
// Input:  JSON array of payment rows from TransformPayment
// Action: For each row:
//   1. INSERT account_move      (journal entry header, state='posted')
//   2. INSERT account_move_line (two legs: debit + credit)
//   3. INSERT account_payment   (with move_id → journal entry)
//   4. Backfill origin_payment_id on account_move
//   5. Register XID in ir_model_data
//
// INBOUND  (received): DR bank account,      CR AR (asset_receivable)
// OUTBOUND (paid):     DR AP (liability_payable), CR bank account
//
// IMPORTANT: All SQL.myPool.eachRow calls MUST stay outside withTransaction.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings   ?: [:]
def xidPfx       = customCfg.xid_prefixes    ?: [:]
def payDefaults  = customCfg.payment_defaults ?: [:]

def compXidPfx = xidPfx.company ?: 'cust_company_'
def persXidPfx = xidPfx.person  ?: 'cust_person_'
def payXidPfx  = xidPfx.payment ?: 'cust_pay_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED' || s == '\\N') return null
    try { return s.toLong() } catch (ignored) {}
    try { return (long) s.toDouble() } catch (ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def toDateStr = { def v ->
    if (!v) return null
    def s = v.toString().trim()
    if (!s || s == 'null' || s == '\\N') return null
    if (s =~ /^\d{4}-\d{2}-\d{2}/) return s.take(10)
    if (s ==~ /\d{13}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong())) }
        catch(ignored) {}
    }
    if (s ==~ /\d{10}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong() * 1000L)) }
        catch(ignored) {}
    }
    def m = s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())
    return null
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(80)
    slug ?: 'unknown'
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[PaymentBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
    def currId   = safeLong(cacheGet('lookup.currency_id_inr')) ?: safeLong(cacheGet('lookup.currency_id'))
    if (!currId) throw new Exception('currency_id not in cache — run bootstrap first')

    // ── 3. Schema probes (Phase 1) ────────────────────────────────────────────
    def amColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_move' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def apColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='account_payment' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def hasOriginPaymentId         = amColExists('origin_payment_id')
    def hasAmtCompCurrSigned       = apColExists('amount_company_currency_signed')
    def hasIsReconciled            = apColExists('is_reconciled')
    def hasIsMatched               = apColExists('is_matched')
    def hasPmLineId                = apColExists('payment_method_line_id')
    def hasApName                  = apColExists('name')
    def hasApMemo                  = apColExists('memo')
    def hasApRef                   = apColExists('ref')
    log.info("[PaymentBatch] Schema: originPayId=${hasOriginPaymentId} pmLine=${hasPmLineId} apName=${hasApName} memo=${hasApMemo} ref=${hasApRef}")

    // ── 4. Resolve AR / AP accounts (Phase 1) ─────────────────────────────────
    Long arAccId = safeLong(cacheGet('lookup.account.asset_receivable'))
    if (!arAccId) {
        SQL.myPool.eachRow(
            "SELECT id FROM account_account WHERE account_type='asset_receivable' AND active=true ORDER BY id LIMIT 1", []
        ) { r -> arAccId = safeLong(r['id']) }
        if (arAccId) cacheSet('lookup.account.asset_receivable', arAccId.toString())
    }
    Long apAccId2 = safeLong(cacheGet('lookup.account.liability_payable'))
    if (!apAccId2) {
        SQL.myPool.eachRow(
            "SELECT id FROM account_account WHERE account_type='liability_payable' AND active=true ORDER BY id LIMIT 1", []
        ) { r -> apAccId2 = safeLong(r['id']) }
        if (apAccId2) cacheSet('lookup.account.liability_payable', apAccId2.toString())
    }
    if (!arAccId)  throw new Exception('No asset_receivable account found')
    if (!apAccId2) throw new Exception('No liability_payable account found')

    // ── 5. Resolve payment method lines (Phase 1) ─────────────────────────────
    def pmLineIdMap = [:]  // paymentType → Long pmLineId
    ['inbound', 'outbound'].each { pType ->
        Long pmId = safeLong(cacheGet('lookup.payment_method_line.' + pType))
        if (!pmId) {
            SQL.myPool.eachRow("""
                SELECT apml.id FROM account_payment_method_line apml
                JOIN account_payment_method apm ON apm.id = apml.payment_method_id
                JOIN account_journal aj ON aj.id = apml.journal_id
                WHERE aj.company_id=? AND apm.payment_type=? AND apm.code='manual'
                ORDER BY apml.id LIMIT 1
            """, [compId, pType]) { r -> pmId = safeLong(r['id']) }
            if (!pmId) {
                SQL.myPool.eachRow("""
                    SELECT apml.id FROM account_payment_method_line apml
                    JOIN account_payment_method apm ON apm.id = apml.payment_method_id
                    WHERE apm.payment_type=? AND apm.code='manual'
                    ORDER BY apml.id LIMIT 1
                """, [pType]) { r -> pmId = safeLong(r['id']) }
            }
            if (pmId) cacheSet('lookup.payment_method_line.' + pType, pmId.toString())
        }
        pmLineIdMap[pType] = pmId
        log.info("[PaymentBatch] payment_method_line[${pType}]=${pmId}")
    }

    // ── 6. Journal + bank account helpers (Phase 1) ───────────────────────────
    def bankAccCache = [:]  // jrnlId → bankAccId

    def resolveJournal = { String bankNameRaw, Long bankIdRaw, String fallbackType ->
        Long jid = null
        if (bankIdRaw)   jid = safeLong(cacheGet('lookup.journal.' + bankIdRaw))
        if (!jid && bankNameRaw) {
            jid = safeLong(cacheGet('lookup.journal.' + bankNameRaw))
            if (!jid) {
                SQL.myPool.eachRow(
                    "SELECT id FROM account_journal WHERE company_id=? AND active=true AND name->>'en_US' ILIKE ? ORDER BY id LIMIT 1",
                    [compId, bankNameRaw]
                ) { r -> jid = safeLong(r['id']) }
                if (jid) cacheSet('lookup.journal.' + bankNameRaw, jid.toString())
            }
        }
        if (!jid) {
            jid = safeLong(cacheGet('lookup.journal.type.' + fallbackType))
            if (!jid) {
                SQL.myPool.eachRow(
                    "SELECT id FROM account_journal WHERE company_id=? AND active=true AND type=? ORDER BY id LIMIT 1",
                    [compId, fallbackType]
                ) { r -> jid = safeLong(r['id']) }
                if (jid) cacheSet('lookup.journal.type.' + fallbackType, jid.toString())
            }
        }
        if (!jid && fallbackType == 'cash') {
            SQL.myPool.eachRow(
                "SELECT id FROM account_journal WHERE company_id=? AND active=true AND type='bank' ORDER BY id LIMIT 1",
                [compId]
            ) { r -> jid = safeLong(r['id']) }
            if (jid) {
                log.warn("[PaymentBatch] No cash journal — fell back to bank journal id=${jid}")
                cacheSet('lookup.journal.type.cash', jid.toString())
            }
        }
        return jid
    }

    def resolveBankAcc = { Long jid ->
        if (bankAccCache.containsKey(jid)) return bankAccCache[jid]
        Long baId = safeLong(cacheGet('journal.default_account.' + jid))
        if (!baId) {
            SQL.myPool.eachRow("SELECT default_account_id FROM account_journal WHERE id=?", [jid]) { r ->
                baId = safeLong(r['default_account_id'])
            }
            if (baId) cacheSet('journal.default_account.' + jid, baId.toString())
        }
        bankAccCache[jid] = baId
        return baId
    }

    // ── 7. Parse rows + per-row Phase 1 resolution ────────────────────────────
    def payItems   = []   // rows ready to insert
    def cacheUpdates = [] // [key, val] applied post-commit

    rows.each { row ->
        def rowId = nvl(row['id'])
        if (!rowId) { log.warn("[PaymentBatch] Row with empty id — skipping"); return }

        def payDate     = toDateStr(row['Date'])
        def custNameId  = nvl(row['CustomerNameid']) ?: nvl(row['CustomerNameId'])
        def custAddrId  = nvl(row['CustomerAddressID'])
        def invoiceNo   = nvl(row['InvoiceNo'])
        def drAmt       = safeBD(row['Dr'])
        def crAmt       = safeBD(row['Cr'])
        def modeStr     = nvl(row['Mode'])
        def bankNameRaw = nvl(row['BankName'])
        def bankIdRaw   = safeLong(row['BankId'])
        def remarks     = nvl(row['Remarks'])
        def companyName = nvl(row['CompanyName'])
        def sourceStr   = nvl(row['Source'])?.toLowerCase()?.trim() ?: ''
        def modeNorm    = modeStr?.toLowerCase()?.trim() ?: ''

        // Date fallback: infer from InvoiceNo FY suffix (e.g. 1798/22-23 → 2023-03-31)
        if (!payDate && invoiceNo) {
            def fyM = invoiceNo =~ /(\d{2})-(\d{2})$/
            if (fyM) {
                try { payDate = "20${fyM[0][2]}-03-31" }
                catch(ignored) {}
            }
        }
        if (!payDate) {
            payDate = '2025-03-31'
            log.warn("[PaymentBatch] id=${rowId} null date, defaulted to ${payDate}")
        }

        // Payment direction
        boolean isInbound
        if      (modeNorm in ['received', 'receipt'])                     { isInbound = true  }
        else if (modeNorm in ['paid', 'payment', 'purchase'])             { isInbound = false }
        else if (sourceStr.contains('receipt') || sourceStr == 'sale')    { isInbound = true  }
        else if (sourceStr.contains('payment') || sourceStr == 'purchase'){ isInbound = false }
        else                                                               { isInbound = !(crAmt > BigDecimal.ZERO) }

        def paymentType = isInbound ? 'inbound'  : 'outbound'
        def partnerType = isInbound ? 'customer' : 'supplier'
        BigDecimal amount = isInbound ? drAmt : crAmt
        if (amount <= BigDecimal.ZERO) {
            def alt = isInbound ? crAmt : drAmt
            if (alt > BigDecimal.ZERO) {
                log.warn("[PaymentBatch] id=${rowId} amount in unexpected column (Dr=${drAmt} Cr=${crAmt}) — using ${alt}")
                amount = alt
            }
        }
        if (amount <= BigDecimal.ZERO) {
            log.warn("[PaymentBatch] id=${rowId} zero amount (Dr=${drAmt} Cr=${crAmt}) — skipping")
            return
        }

        def extId    = payXidPfx + rowId
        def cacheKey = 'xid.payment.' + extId

        // Idempotency: cache → ir_model_data
        Long existingPayId = null
        def cachedId = safeLong(cacheGet(cacheKey))
        if (cachedId) {
            def found = false
            SQL.myPool.eachRow('SELECT id FROM account_payment WHERE id=? LIMIT 1', [cachedId]) { found = true }
            if (found) { existingPayId = cachedId }
            else       { cacheSet(cacheKey, 'CLEARED') }
        }
        if (!existingPayId) {
            Long xidPayId = null
            SQL.myPool.eachRow('SELECT res_id FROM ir_model_data WHERE module=? AND name=? LIMIT 1', [module, extId]) { r ->
                xidPayId = safeLong(r['res_id'])
            }
            if (xidPayId) {
                def found = false
                SQL.myPool.eachRow('SELECT id FROM account_payment WHERE id=? LIMIT 1', [xidPayId]) { found = true }
                if (found) existingPayId = xidPayId
                // stale XID (xidPayId exists in ir_model_data but payment deleted) will be cleaned in Phase 2
            }
        }
        if (existingPayId) {
            cacheUpdates << [cacheKey, existingPayId.toString()]
            log.info("[PaymentBatch] Already exists: ${extId} → ${existingPayId} — skipping")
            return
        }

        // Partner resolution (5 levels, slugify-corrected to match insert_res_partner_batch)
        Long partnerId  = null
        def nameSlug    = custNameId ? slugify(custNameId) : null
        def addrSlug    = custAddrId ? slugify(custAddrId) : null

        if (custNameId)  partnerId = safeLong(cacheGet('cust.nameid.'   + custNameId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.personid.' + custAddrId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.addrid.'   + custAddrId))
        if (!partnerId && nameSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, compXidPfx + nameSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && addrSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, persXidPfx + addrSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE name ILIKE ? AND active=true ORDER BY is_company DESC, id LIMIT 1",
                [companyName]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE (commercial_company_name ILIKE ? OR complete_name ILIKE ?) AND active=true ORDER BY is_company DESC, id LIMIT 1",
                ["%${companyName}%", "%${companyName}%"]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId) log.warn("[PaymentBatch] Partner not resolved: id=${rowId} custNameId=${custNameId} companyName=${companyName}")

        // Journal resolution
        def fallbackType = bankNameRaw ? (payDefaults.journal_type_bank ?: 'bank') : (payDefaults.journal_type_cash ?: 'cash')
        Long jrnlId = resolveJournal(bankNameRaw, bankIdRaw, fallbackType)
        if (!jrnlId) {
            log.warn("[PaymentBatch] No journal for id=${rowId} bankName=${bankNameRaw} — skipping")
            return
        }

        Long bankAccId = resolveBankAcc(jrnlId)
        if (!bankAccId) {
            log.warn("[PaymentBatch] Journal ${jrnlId} has no default_account_id for id=${rowId} — skipping")
            return
        }

        payItems << [
            rowId      : rowId,
            extId      : extId,
            cacheKey   : cacheKey,
            payDate    : payDate,
            isInbound  : isInbound,
            paymentType: paymentType,
            partnerType: partnerType,
            amount     : amount,
            partnerId  : partnerId,
            jrnlId     : jrnlId,
            bankAccId  : bankAccId,
            moveName   : (payDefaults.ref_prefix ?: 'MIGO-PAY-') + rowId,
            payMemo    : remarks ?: invoiceNo ?: ''
        ]
    }

    log.info("[PaymentBatch] Items to insert: ${payItems.size()} / ${rows.size()}")

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: insert account_move + lines + account_payment
    // Only conn.prepareStatement inside this block — no SQL.myPool.* calls
    // ════════════════════════════════════════════════════════════════════════
    int written = 0
    def xidBatch = []

    SQL.myPool.withTransaction { conn ->
        payItems.each { item ->
            // Remove any stale XID (idempotent — safe even if nothing to delete)
            def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
            delPs.setString(1, module); delPs.setString(2, item.extId)
            delPs.executeUpdate(); delPs.close()

            def debitAccId  = item.isInbound ? item.bankAccId : apAccId2
            def creditAccId = item.isInbound ? arAccId        : item.bankAccId
            def amtSigned   = item.isInbound ? item.amount    : item.amount.negate()

            // ── INSERT account_move ─────────────────────────────────────────
            def mvPs = conn.prepareStatement("""
                INSERT INTO account_move
                  (journal_id, company_id, currency_id, date, state, move_type,
                   posted_before, auto_post, partner_id, name, ref,
                   amount_untaxed, amount_total,
                   create_uid, write_uid, create_date, write_date)
                VALUES (?,?,?,?::date,'posted','entry',true,'no',?,?,?,?,?,?,?,NOW(),NOW())
                RETURNING id
            """)
            int mp = 1
            mvPs.setLong(mp++, item.jrnlId)
            mvPs.setLong(mp++, compId)
            mvPs.setLong(mp++, currId)
            mvPs.setString(mp++, item.payDate)
            if (item.partnerId) mvPs.setLong(mp++, item.partnerId) else mvPs.setObject(mp++, null)
            mvPs.setString(mp++, item.moveName)
            mvPs.setObject(mp++, item.payMemo ?: null)
            mvPs.setBigDecimal(mp++, item.amount)
            mvPs.setBigDecimal(mp++, item.amount)
            mvPs.setLong(mp++, adminUid)
            mvPs.setLong(mp++, adminUid)
            def mvRs = mvPs.executeQuery()
            mvRs.next(); long moveId = mvRs.getLong(1); mvRs.close(); mvPs.close()

            // ── INSERT account_move_line × 2 (debit leg + credit leg) ───────
            def lineName = item.payMemo ?: item.moveName
            [[debitAccId,  item.amount,          BigDecimal.ZERO, item.amount         ],
             [creditAccId, BigDecimal.ZERO, item.amount,          item.amount.negate()]
            ].each { accId, dbt, crd, bal ->
                def lnPs = conn.prepareStatement("""
                    INSERT INTO account_move_line
                      (move_id, journal_id, company_id, company_currency_id, currency_id,
                       account_id, partner_id, name, date,
                       debit, credit, balance,
                       display_type, parent_state,
                       create_uid, write_uid, create_date, write_date)
                    VALUES (?,?,?,?,?,?,?,?,?::date,?,?,?,'product','posted',?,?,NOW(),NOW())
                """)
                int lp = 1
                lnPs.setLong(lp++, moveId);      lnPs.setLong(lp++, item.jrnlId)
                lnPs.setLong(lp++, compId);      lnPs.setLong(lp++, currId)
                lnPs.setLong(lp++, currId);      lnPs.setLong(lp++, accId)
                if (item.partnerId) lnPs.setLong(lp++, item.partnerId) else lnPs.setObject(lp++, null)
                lnPs.setString(lp++, lineName);  lnPs.setString(lp++, item.payDate)
                lnPs.setBigDecimal(lp++, dbt);   lnPs.setBigDecimal(lp++, crd)
                lnPs.setBigDecimal(lp++, bal);   lnPs.setLong(lp++, adminUid)
                lnPs.setLong(lp++, adminUid)
                lnPs.execute(); lnPs.close()
            }

            // ── INSERT account_payment (dynamic columns) ────────────────────
            def pyCols = ['move_id','journal_id','company_id','currency_id','date',
                          'amount','payment_type','partner_type','state','partner_id']
            def pyVals = ['?','?','?','?','?::date','?','?','?',"'paid'",'?']
            if (hasAmtCompCurrSigned) { pyCols << 'amount_company_currency_signed'; pyVals << '?' }
            if (hasIsReconciled)      { pyCols << 'is_reconciled';                  pyVals << 'false' }
            if (hasIsMatched)         { pyCols << 'is_matched';                     pyVals << 'false' }
            if (hasPmLineId)          { pyCols << 'payment_method_line_id';         pyVals << '?' }
            if (hasApName)            { pyCols << 'name';                           pyVals << '?' }
            if (hasApMemo)            { pyCols << 'memo';                           pyVals << '?' }
            else if (hasApRef)        { pyCols << 'ref';                            pyVals << '?' }
            pyCols << 'create_uid'; pyVals << '?'
            pyCols << 'write_uid';  pyVals << '?'
            pyCols << 'create_date'; pyVals << 'NOW()'
            pyCols << 'write_date';  pyVals << 'NOW()'

            def pyPs = conn.prepareStatement(
                "INSERT INTO account_payment (${pyCols.join(',')}) VALUES (${pyVals.join(',')}) RETURNING id"
            )
            int pp = 1
            pyPs.setLong(pp++, moveId);          pyPs.setLong(pp++, item.jrnlId)
            pyPs.setLong(pp++, compId);          pyPs.setLong(pp++, currId)
            pyPs.setString(pp++, item.payDate);  pyPs.setBigDecimal(pp++, item.amount)
            pyPs.setString(pp++, item.paymentType); pyPs.setString(pp++, item.partnerType)
            if (item.partnerId) pyPs.setLong(pp++, item.partnerId) else pyPs.setObject(pp++, null)
            if (hasAmtCompCurrSigned) pyPs.setBigDecimal(pp++, amtSigned)
            if (hasPmLineId) {
                def pmId = pmLineIdMap[item.paymentType]
                if (pmId) pyPs.setLong(pp++, pmId) else pyPs.setObject(pp++, null)
            }
            if (hasApName)            pyPs.setString(pp++, item.moveName)
            if (hasApMemo || hasApRef) pyPs.setObject(pp++, item.payMemo ?: null)
            pyPs.setLong(pp++, adminUid); pyPs.setLong(pp++, adminUid)

            def pyRs = pyPs.executeQuery()
            pyRs.next(); long payId = pyRs.getLong(1); pyRs.close(); pyPs.close()

            // ── Backfill origin_payment_id + payment_state on account_move ──
            if (hasOriginPaymentId) {
                def bfPs = conn.prepareStatement(
                    "UPDATE account_move SET origin_payment_id=?, payment_state='paid' WHERE id=?"
                )
                bfPs.setLong(1, payId); bfPs.setLong(2, moveId)
                bfPs.executeUpdate(); bfPs.close()
            } else {
                def bfPs = conn.prepareStatement("UPDATE account_move SET payment_state='paid' WHERE id=?")
                bfPs.setLong(1, moveId); bfPs.executeUpdate(); bfPs.close()
            }

            xidBatch  << [module, item.extId, 'account.payment', payId]
            cacheUpdates << [item.cacheKey, payId.toString()]
            log.info("[PaymentBatch] INSERTED: ${item.extId} → pay=${payId} move=${moveId} amount=${item.amount} type=${item.paymentType}")
            written++
        }

        // ── Batch XID inserts (sorted to prevent deadlocks) ──────────────────
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m, n, mdl, rid ->
                xidPs.setString(1, m); xidPs.setString(2, n)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try { xidPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                def pg = bue.getNextException()
                log.error("[PaymentBatch] XID batch failed: ${bue.message} | PG: ${pg?.getMessage()}")
                throw bue
            }
            xidPs.close()
        }

        log.info("[PaymentBatch] Committed — written:${written}")
    }

    // Post-commit: update cache (only after transaction succeeded)
    cacheUpdates.each { ck, v -> cacheSet(ck, v) }

    ff = session.putAllAttributes(ff, [
        'payment.written': written.toString(),
        'payment.skipped': (rows.size() - written).toString(),
        'batch.size'     : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[PaymentBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// TransformPayment_Custom.groovy
// Full-file payment CSV/XLSX transformer. Each row = one payment.
// Cleans data and normalizes dates/amounts. Output column names match insert_payment_custom.
//
// NiFi flow:
//   TransformPayment_Custom → SplitRecord → insert_payment_custom
//
// Input (Nevco payment data — column names may vary in case/spacing):
//   id, Date, CustomerNameid, CustomerAddressID, CompanyName,
//   InvoiceNo, Dr, Cr, Mode, Source, BankName, BankId, Remarks
//
//   Mode: 'Received' → inbound (customer receipt); 'Purchase'/'Paid' → outbound (vendor payment)
//   Cr (credit) = amount in this Tally export for BOTH inbound and outbound rows
//
// All output columns are ALWAYS present (even empty) — prevents SplitRecord column count errors.
// XLSX detected via ZIP magic bytes (PK\x03\x04); requires Apache POI on NiFi classpath.

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets
import java.time.LocalDate
import java.time.format.DateTimeFormatter

def flowFile = session.get()
if (!flowFile) return

// ── Helpers ───────────────────────────────────────────────────────────────────

def escCsv = { String v ->
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '\\\\N' && s != '') ? s : ''
}

def MONTH_MAP = [
    jan:1, feb:2, mar:3, apr:4, may:5,  jun:6,
    jul:7, aug:8, sep:9, oct:10, nov:11, dec:12
]

def toDateStr = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    if (!s || s == 'null' || s == '\\N' || s == '\\\\N') return ''

    if (s =~ /^\d{4}-\d{2}-\d{2}$/) return s

    if (s =~ /^\d{8}$/) return "${s[0..3]}-${s[4..5]}-${s[6..7]}"

    def m = (s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/)
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())

    def m2 = (s =~ /^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/)
    if (m2) return String.format('%s-%02d-%02d', m2[0][3], m2[0][2].toInteger(), m2[0][1].toInteger())

    def m3 = (s =~ /^(\d{1,2})[-\/]([A-Za-z]{3,9})[-\/](\d{4})$/)
    if (m3) {
        def mon = MONTH_MAP[m3[0][2].toLowerCase().take(3)]
        if (mon) return String.format('%s-%02d-%02d', m3[0][3], mon, m3[0][1].toInteger())
    }

    // Unix timestamp in milliseconds (Tally exports dates as epoch-ms, e.g. 1725321600000 = 2024-09-03)
    // 11+ digits distinguishes from Excel serials (~5 digits). Negative values are Tally null markers.
    // Use Instant.ofEpochMilli to avoid Groovy BigDecimal division ambiguity with ofEpochDay.
    if (s =~ /^\d{11,}$/) {
        try {
            long ms = s.toLong()
            if (ms > 0L && ms < 4102444800000L) {
                return java.time.Instant.ofEpochMilli(ms)
                    .atZone(java.time.ZoneOffset.UTC)
                    .toLocalDate()
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
        } catch (ignored) {}
    }

    // Excel date serial (epoch 1899-12-30)
    if (s =~ /^\d+\.?\d*$/) {
        try {
            long serial = Math.round(s.toDouble())
            if (serial > 25569 && serial < 100000) {
                return LocalDate.of(1899, 12, 30).plusDays(serial)
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
        } catch (ignored) {}
    }

    return ''
}

def cleanNum = { String raw ->
    if (!raw) return '0'
    def s = raw.trim().replaceAll(/[,\s]/, '')
    if (s =~ /^\([\d.]+\)$/) s = '-' + s.replaceAll(/[()]/, '')
    if (!s || s == '-' || s == '.') return '0'
    try { Double.parseDouble(s); return s } catch (ignored) { return '0' }
}

// ── CSV row parsers ───────────────────────────────────────────────────────────

def splitCsvLine = { String line ->
    // Handles \, escape for embedded commas (Tally export quirk) and standard quoting.
    def result = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)'"') {
                sb.append('"'); ci++
            } else { inQ = !inQ }
        } else if (c == (char)'\\' && !inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)',') {
            sb.append(','); ci++
        } else if (c == (char)',' && !inQ) {
            result << sb.toString(); sb.setLength(0)
        } else {
            sb.append(c)
        }
    }
    result << sb.toString()
    return result
}

def assembleRows = { String text ->
    // State-machine: newline inside a quoted field does NOT end the logical row.
    def rows = []; def sb = new StringBuilder(); boolean inQ = false
    for (int ci = 0; ci < text.length(); ci++) {
        char c = text.charAt(ci)
        if (c == (char)'"') {
            if (inQ && ci + 1 < text.length() && text.charAt(ci + 1) == (char)'"') {
                sb.append('"'); sb.append('"'); ci++
            } else { inQ = !inQ; sb.append(c) }
        } else if ((c == (char)'\n' || c == (char)'\r') && !inQ) {
            if (c == (char)'\r' && ci + 1 < text.length() && text.charAt(ci + 1) == (char)'\n') ci++
            if (sb.length() > 0 && sb.toString().trim()) { rows << sb.toString(); sb.setLength(0) }
        } else {
            sb.append(c)
        }
    }
    if (sb.length() > 0 && sb.toString().trim()) rows << sb.toString()
    return rows
}

// ── XLSX cell reader ──────────────────────────────────────────────────────────

def getCellValue = { cell ->
    if (!cell) return ''
    try {
        def ct = cell.cellType
        if (ct.name() == 'FORMULA') {
            try { ct = cell.cachedFormulaResultType } catch (ignored) {}
        }
        switch (ct.name()) {
            case 'NUMERIC':
                try {
                    if (org.apache.poi.ss.usermodel.DateUtil.isCellDateFormatted(cell)) {
                        def dt = cell.dateCellValue
                        return dt ? String.format('%tY-%<tm-%<td', dt) : ''
                    }
                } catch (ignored) {}
                def bd = new BigDecimal(cell.numericCellValue.toString())
                return bd.toPlainString().replaceAll(/\.0+$/, '')
            case 'STRING':  return cell.stringCellValue?.trim() ?: ''
            case 'BOOLEAN': return cell.booleanCellValue.toString()
            case 'BLANK':   return ''
            default:        return cell.toString()?.trim() ?: ''
        }
    } catch (ignored) { return '' }
}

try {
    // ── 1. Read bytes and detect format ──────────────────────────────────────
    byte[] rawBytes = null
    session.read(flowFile, { is -> rawBytes = is.bytes } as InputStreamCallback)

    if (!rawBytes || rawBytes.length == 0) {
        log.warn('[TransformPayment_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    boolean isXlsx = rawBytes.length >= 4 &&
                     rawBytes[0] == (byte)0x50 && rawBytes[1] == (byte)0x4B &&
                     rawBytes[2] == (byte)0x03 && rawBytes[3] == (byte)0x04

    List<List<String>> allRows = []

    if (isXlsx) {
        log.info('[TransformPayment_Custom] Detected XLSX — parsing with Apache POI')
        try {
            def wb = org.apache.poi.ss.usermodel.WorkbookFactory.create(
                         new java.io.ByteArrayInputStream(rawBytes))
            def sheet = wb.getSheetAt(0)
            sheet.each { row ->
                int last = row.lastCellNum > 0 ? row.lastCellNum : 0
                def cells = (0..<last).collect { i ->
                    nvl(getCellValue(row.getCell(i,
                        org.apache.poi.ss.usermodel.Row.MissingCellPolicy.RETURN_BLANK_AS_NULL)))
                }
                if (cells.any { it }) allRows << cells
            }
            wb.close()
        } catch (ClassNotFoundException cnfe) {
            log.error('[TransformPayment_Custom] Apache POI not on NiFi classpath: ' + cnfe.message)
            session.transfer(flowFile, REL_FAILURE)
            return
        }
    } else {
        log.info('[TransformPayment_Custom] Detected CSV — parsing as text')
        String csvText
        try {
            csvText = new String(rawBytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
        } catch (ignored) {
            csvText = new String(rawBytes, 'ISO-8859-1')
        }
        assembleRows(csvText).each { line ->
            allRows << splitCsvLine(line).collect { nvl(it) }
        }
    }

    if (allRows.size() < 2) {
        log.warn('[TransformPayment_Custom] No data rows found')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Find header row (scan first 10 rows) ───────────────────────────────
    def knownHdrWords = ['id', 'date', 'mode', 'source', 'customernameid', 'dr', 'cr'] as Set
    int headerIdx = -1
    for (int i = 0; i < Math.min(10, allRows.size()); i++) {
        def lower = allRows[i].collect { it?.trim()?.toLowerCase() ?: '' }
        int hits = lower.count { it in knownHdrWords }
        if (hits >= 3 || 'customernameid' in lower || ('mode' in lower && 'source' in lower)) {
            headerIdx = i; break
        }
    }
    if (headerIdx < 0) {
        log.error("[TransformPayment_Custom] Cannot detect header row — row[0]: ${allRows[0]}")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (headerIdx > 0) log.info("[TransformPayment_Custom] Skipped ${headerIdx} junk row(s)")

    // ── 3. Build header index ─────────────────────────────────────────────────
    def hdrIdx = [:]
    allRows[headerIdx].eachWithIndex { h, i ->
        def k = h?.trim()?.toLowerCase() ?: ''
        if (k) hdrIdx[k] = i
    }

    def get = { List cells, int idx -> idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx]) }

    def mappingsPath = flowFile.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
    def tableFields  = new JsonSlurper().parse(new File(mappingsPath)).tables?.payment_custom?.fields ?: [:]

    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) {
            def directKey = fieldName.toLowerCase()
            if (hdrIdx.containsKey(directKey)) return hdrIdx[directKey]
            def found = hdrIdx.find { hk, _ -> hk && (hk.contains(directKey) || directKey.contains(hk)) }
            return found ? found.value : -1
        }
        def aliases = []
        if (fDef.source_col)  aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        for (String alias in aliases) { def k = alias.toLowerCase(); if (hdrIdx.containsKey(k)) return hdrIdx[k] }
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            def found = hdrIdx.find { hk, hv -> hk && hk.contains(k) }
            if (found) return found.value
        }
        return -1
    }

    def idIdx     = resolveColIdx('id')
    def dateIdx   = resolveColIdx('Date')
    def cnIdx     = resolveColIdx('CustomerNameid')
    def caIdx     = resolveColIdx('CustomerAddressID')
    def compNmIdx = resolveColIdx('CompanyName')
    def invNoIdx  = resolveColIdx('InvoiceNo')
    def drIdx     = resolveColIdx('Dr')
    def crIdx     = resolveColIdx('Cr')
    def modeIdx   = resolveColIdx('Mode')
    def sourceIdx = resolveColIdx('Source')
    def bankNmIdx = resolveColIdx('BankName')
    def bankIdIdx = resolveColIdx('BankId')
    def remIdx    = resolveColIdx('Remarks')

    log.info("[TransformPayment_Custom] id:${idIdx} date:${dateIdx} custNameId:${cnIdx} " +
             "dr:${drIdx} cr:${crIdx} mode:${modeIdx} source:${sourceIdx} bankName:${bankNmIdx}")

    if (idIdx < 0) {
        log.error('[TransformPayment_Custom] Cannot find id column — aborting')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 4. Fixed output columns ───────────────────────────────────────────────
    def COLS = [
        'id', 'Date', 'CustomerNameid', 'CustomerAddressID',
        'CompanyName', 'InvoiceNo', 'Dr', 'Cr',
        'Mode', 'Source', 'BankName', 'BankId', 'Remarks'
    ]

    def outSb = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0, nullDates = 0
    int writtenInbound = 0, writtenOutbound = 0

    // ── 5. Process rows ───────────────────────────────────────────────────────
    for (int i = headerIdx + 1; i < allRows.size(); i++) {
        def c = allRows[i]

        def rowId = get(c, idIdx)
        if (!rowId) { skipped++; continue }
        if (rowId.toLowerCase() in ['id', 'payment id']) { skipped++; continue }

        rowId = rowId.replaceAll(/\.0+$/, '')

        def drAmt = cleanNum(get(c, drIdx))
        def crAmt = cleanNum(get(c, crIdx))
        if (drAmt == '0' && crAmt == '0') { skipped++; continue }

        def rawDate    = get(c, dateIdx)
        def parsedDate = toDateStr(rawDate)
        if (!parsedDate && rawDate) {
            log.warn("[TransformPayment_Custom] rowId=${rowId}: unrecognized date '${rawDate}'")
            nullDates++
        } else if (!parsedDate) {
            nullDates++
        }

        def cnVal = get(c, cnIdx).replaceAll(/\.0+$/, '')
        def caVal = get(c, caIdx).replaceAll(/\.0+$/, '')
        def row = [
            rowId,
            parsedDate,
            cnVal, caVal, get(c, compNmIdx),
            get(c, invNoIdx),
            drAmt, crAmt,
            get(c, modeIdx), get(c, sourceIdx),
            get(c, bankNmIdx), get(c, bankIdIdx), get(c, remIdx)
        ]
        outSb.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
        def modeOut = get(c, modeIdx)?.toLowerCase() ?: ''
        if (modeOut in ['received', 'receipt']) { writtenInbound++ }
        else { writtenOutbound++ }
    }

    if (written == 0) {
        log.warn('[TransformPayment_Custom] No valid rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 6. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(outSb.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformPayment_Custom] Done — ${written} rows written (${writtenInbound} inbound/Received, ${writtenOutbound} outbound/Purchase), ${skipped} skipped, ${nullDates} null/unparseable dates")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformPayment_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('LoadTaxGroup row: ' + row.toString()?.take(300))

    // ── 2. Read row fields ────────────────────────────────────────────────────
    def taxName  = nvl(row['name'])
    def groupName = nvl(row['tax_group_name'])

    if (!taxName || taxName == 'name') {
        log.warn('Header or empty row — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }
    if (!groupName) {
        log.warn("No tax_group_name for tax '${taxName}' — skipping")
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("taxName=${taxName} groupName=${groupName}")

    // ── 3. Runtime constants — cache / env only ───────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def ctryId   = safeLong(cacheGet('lookup.country_id_in') ?: cacheGet('lookup.country_id'))
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    if (!ctryId) throw new Exception('country_id not in cache — re-run Bootstrap')

    // ── 4. Build ext_id from group name ──────────────────────────────────────
    def groupSlug = groupName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
    def extId     = 'tally_tax_group_' + groupSlug

    // ── 5. Cache check ────────────────────────────────────────────────────────
    def cacheKey   = 'taxgroup.' + groupSlug
    def cachedId   = cacheGet(cacheKey)
    if (cachedId) {
        log.info("Tax group already cached: ${groupName} → ${cachedId}")
        ff = session.putAttribute(ff, 'tax_group_id',   cachedId)
        ff = session.putAttribute(ff, 'tax_group_name', groupName)
        ff = session.putAttribute(ff, 'tax_name',       taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 6. DB check ───────────────────────────────────────────────────────────
    def existingId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingId = r.getLong('res_id') }

    long resId
    if (existingId) {
        resId = existingId
        log.info("Tax group already in DB: ${groupName} → ${resId}")

    } else {
        // ── 7. Build JSONB name ───────────────────────────────────────────────
        def nameSafe = groupName.replace('"', '\\"')
        def nameJson = "{\"en_US\": \"${nameSafe}\"}"

        // ── 8. INSERT account_tax_group ───────────────────────────────────────
        def ps = SQL.myPool.connection.prepareStatement(
            '''INSERT INTO account_tax_group
               (name, sequence, company_id, country_id,
                create_uid, write_uid, create_date, write_date)
               VALUES (?::jsonb, 10, ?, ?, ?, ?, NOW(), NOW())
               RETURNING id'''
        )
        ps.setString(1, nameJson)
        ps.setLong(2,   compId)
        ps.setLong(3,   ctryId)
        ps.setLong(4,   adminUid)
        ps.setLong(5,   adminUid)

        def rs = ps.executeQuery()
        rs.next()
        resId = rs.getLong(1)
        ps.close()

        // ── 9. Register XID ───────────────────────────────────────────────────
        SQL.myPool.execute(
            '''INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date)
               VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING''',
            [module, extId, 'account.tax.group', resId]
        )

        log.info("Tax group INSERTED: ${groupName} → ${resId}")
    }

    // ── 10. Cache for LoadTax script ──────────────────────────────────────────
    CTL.cacheClient.put(cacheKey, resId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'tax_group_id',   resId.toString())
    ff = session.putAttribute(ff, 'tax_group_name', groupName)
    ff = session.putAttribute(ff, 'tax_name',       taxName)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('LoadTaxGroup failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// ─────────────────────────────────────────────────────────────────────────────
// Step3A_TransformTaxes.groovy
// ─────────────────────────────────────────────────────────────────────────────

import TallyCleaners_Taxes
import org.apache.nifi.processor.io.StreamCallback
import org.apache.nifi.processor.io.InputStreamCallback
import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

// ══════════════════════════════════════════════════════════════════════════════
// MAIN
// ══════════════════════════════════════════════════════════════════════════════

def flowFile = session.get()
if (!flowFile) return

try {
    // ── 1. Load mappings ──────────────────────────────────────────────────────
    def mappingsPath = flowFile.getAttribute('mappings.path') ?: '/home/ubuntu/Raw_tally_data/mappings.json'
    log.info("[Step3A] STEP1: Loading mappings from: ${mappingsPath}")

    def mappings   = new JsonSlurper().parseText(new File(mappingsPath).text)
    def taxFields  = mappings.tables?.account_tax?.fields  ?: [:]
    def moveFields = mappings.tables?.account_move?.fields ?: [:]

    if (taxFields.isEmpty()) {
        log.error('[Step3A] account_tax fields missing from mappings.json')
        session.transfer(flowFile, REL_FAILURE); return
    }

    def taxKeywords      = (mappings.line_type_patterns?.tax_keywords      ?: []).collect { it.toString().toLowerCase() }
    def roundingKeywords = (mappings.line_type_patterns?.rounding_keywords ?: []).collect { it.toString().toLowerCase() }
    def taxGroupPatterns = (mappings.tax_group_patterns ?: [:])
                              .collectEntries { k, v -> [k.toString().toLowerCase(), v.toString()] }
    def purchaseTypeKw   = (mappings.voucher_classifier?.purchase_types    ?: []).collect { it.toString().toLowerCase() }
    def purchaseTaxGrpK  = taxGroupPatterns
                              .findAll { k, v -> v.toLowerCase() in ['tds', 'tcs'] }
                              .keySet() as Set

    if (taxKeywords.isEmpty())
        log.warn('[Step3A] line_type_patterns.tax_keywords is empty — no tax rows will be detected')

    log.info("[Step3A] STEP1: taxFields=${taxFields.size()} taxKeywords=${taxKeywords} " +
             "roundingKeywords=${roundingKeywords} taxGroupPatterns=${taxGroupPatterns} " +
             "purchaseTypeKw=${purchaseTypeKw} purchaseTaxGrpK=${purchaseTaxGrpK}")

    // ── 2. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { inputStream ->
        csvText = new String(inputStream.bytes, StandardCharsets.UTF_8)
                   .replaceFirst(/^\uFEFF/, '')
    } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    log.info("[Step3A] STEP2: Total lines: ${lines.size()}")

    if (lines.size() < 2) {
        log.warn('[Step3A] Empty or header-only CSV — skipping')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 3. Auto-detect header row ─────────────────────────────────────────────
    def allAliases = [] as Set
    [taxFields, moveFields].each { fieldMap ->
        fieldMap.each { odooField, fm ->
            if (fm.source_col)
                allAliases << fm.source_col.toString().trim().toLowerCase()
            if (fm.source_cols instanceof List)
                fm.source_cols.each { allAliases << it.toString().trim().toLowerCase() }
        }
    }

    def nameFm      = taxFields['name']
    def nameAliases = [] as Set
    if (nameFm?.source_col) nameAliases << nameFm.source_col.toString().trim().toLowerCase()
    if (nameFm?.source_cols instanceof List)
        nameFm.source_cols.each { nameAliases << it.toString().trim().toLowerCase() }

    int headerLineIdx = -1
    for (int i = 0; i < Math.min(lines.size(), 10); i++) {
        def cols  = TallyCleaners_Taxes.splitCsvLine(lines[i])
        def lower = cols*.trim()*.toLowerCase()
        int matchCount = lower.count { c -> c && allAliases.contains(c) }
        if (matchCount >= 2) { headerLineIdx = i; break }
        if (matchCount >= 1 && lower.any { c -> nameAliases.contains(c) }) { headerLineIdx = i; break }
    }

    if (headerLineIdx < 0) {
        log.error('[Step3A] Cannot find header row in first 10 lines. First line: ' + lines[0])
        session.transfer(flowFile, REL_FAILURE); return
    }

    if (headerLineIdx > 0)
        log.info("[Step3A] Skipped ${headerLineIdx} junk row(s). Header: ${lines[headerLineIdx]}")

    def headers = TallyCleaners_Taxes.splitCsvLine(lines[headerLineIdx])

    // ── 4. Build header → index map ───────────────────────────────────────────
    def headerIdx = [:]
    headers.eachWithIndex { h, i ->
        def key = h?.trim()?.toLowerCase() ?: ''
        if (key) headerIdx[key] = i
    }
    log.info("[Step3A] STEP4: headerIdx: ${headerIdx}")

    // ── 5. Alias-driven column resolver ───────────────────────────────────────
    def resolveColIdx = { String odooField, Map fields ->
        def fm = fields[odooField]
        if (!fm) { log.warn("[Step3A] '${odooField}' not in fields"); return -1 }

        def candidates = []
        if (fm.source_col)                              candidates << fm.source_col.toString().trim()
        if (fm.source_cols instanceof List) candidates += fm.source_cols*.toString()*.trim()
        candidates = candidates.findAll { it }

        // Pass 1 — exact match
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            if (headerIdx.containsKey(aliasL)) {
                log.info("[Step3A] '${odooField}' → EXACT '${alias}' → col ${headerIdx[aliasL]}")
                return headerIdx[aliasL]
            }
        }
        // Pass 2 — contains fallback
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            def found = headerIdx.find { k, v -> k && k.trim() && (k.contains(aliasL) || aliasL.contains(k)) }
            if (found) {
                log.info("[Step3A] '${odooField}' → CONTAINS '${alias}' ~ '${found.key}' → col ${found.value}")
                return found.value
            }
        }
        log.warn("[Step3A] '${odooField}' → NO MATCH in headers")
        return -1
    }

    // ── 6. Resolve column indices from mappings ───────────────────────────────
    // account_tax fields
    int partIdx    = resolveColIdx('name',         taxFields)   // Particulars / tax label
    int amountIdx  = resolveColIdx('amount',       taxFields)   // Amount column
    int typeUseIdx = resolveColIdx('type_tax_use', taxFields)   // explicit type_tax_use
    int activeIdx  = resolveColIdx('active',       taxFields)   // active flag

    // account_move fields — voucher context
    int vchNoIdx   = resolveColIdx('ref',         moveFields)   // Vch No.
    int dateIdx    = resolveColIdx('date',         moveFields)  // Date
    int vchTypeIdx = resolveColIdx('move_type',   moveFields)   // Vch Type
    int partyIdx   = resolveColIdx('partner_id',  moveFields)   // Party Name

    // Positional fallbacks — only when mappings yield no match
    if (vchNoIdx   < 0) { vchNoIdx   = 0; log.warn('[Step3A] vchNoIdx   fallback → col 0') }
    if (dateIdx    < 0) { dateIdx    = 1; log.warn('[Step3A] dateIdx    fallback → col 1') }
    if (vchTypeIdx < 0) { vchTypeIdx = 2; log.warn('[Step3A] vchTypeIdx fallback → col 2') }
    if (partyIdx   < 0) { partyIdx   = 3; log.warn('[Step3A] partyIdx   fallback → col 3') }
    if (partIdx    < 0) { partIdx    = 4; log.warn('[Step3A] partIdx    fallback → col 4') }
    if (amountIdx  < 0) { amountIdx  = 7; log.warn('[Step3A] amountIdx  fallback → col 7') }

    log.info("[Step3A] STEP6: FINAL col indices — vchNo:${vchNoIdx} date:${dateIdx} " +
             "vchType:${vchTypeIdx} party:${partyIdx} part:${partIdx} " +
             "amount:${amountIdx} typeUse:${typeUseIdx} active:${activeIdx}")

    if (partIdx < 0) {
        log.error('[Step3A] Cannot find Particulars column — check source_col/source_cols ' +
                  'for "name" field under account_tax in mappings.json')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 7. Scan rows — build 01_tax_lines.csv ────────────────────────────────
    // 'name'   = tax name  → LoadTaxGroup + LoadTax both read row['name']
    // 'amount' = tax rate  → LoadTax reads row['amount']
    def TAX_LINES_COLS = [
        'id', 'vch_no', 'vch_date', 'party_name', 'vch_type',
        'name',          // ← tax name  (LoadTaxGroup/LoadTax compatible)
        'amount',        // ← tax rate % (LoadTax compatible)
        'tax_amount',    // ← rupee amount from voucher
        'type_tax_use', 'amount_type', 'tax_group_name', 'active'
    ]

    def sbLines     = new StringBuilder()
    sbLines.append(TAX_LINES_COLS.join(',')).append('\n')

    String curVchNo   = ''
    String curVchDate = ''
    String curParty   = ''
    String curVchType = ''
    int    linesWritten = 0

    for (int i = headerLineIdx + 1; i < lines.size(); i++) {
        def cells = TallyCleaners_Taxes.splitCsvLine(lines[i])

        if (TallyCleaners_Taxes.isSkipRow(cells))    continue
        if (TallyCleaners_Taxes.isGrandTotal(cells)) continue

        // Voucher header row — Vch No. cell non-empty
        def vchNo = TallyCleaners_Taxes.cell(cells, vchNoIdx)
        if (vchNo) {
            curVchNo   = vchNo
            curVchDate = TallyCleaners_Taxes.cell(cells, dateIdx)
            curParty   = TallyCleaners_Taxes.cell(cells, partyIdx)
            curVchType = TallyCleaners_Taxes.cell(cells, vchTypeIdx)
            log.info("[Step3A] Header row ${i}: vchNo='${curVchNo}' type='${curVchType}' party='${curParty}'")
            continue
        }

        // Detail row — check if it is a tax row
        def label = TallyCleaners_Taxes.cell(cells, partIdx)
        if (!label) continue

        log.info("[Step3A] DEBUG row ${i}: label='${label}' isTax=${TallyCleaners_Taxes.isTaxRow(label, taxKeywords, roundingKeywords)}")

        if (!TallyCleaners_Taxes.isTaxRow(label, taxKeywords, roundingKeywords)) continue

        def taxName      = TallyCleaners_Taxes.cleanTaxName(label)
        def taxRate      = TallyCleaners_Taxes.parseRate(taxName)
        def taxAmtRaw    = TallyCleaners_Taxes.cell(cells, amountIdx)
        def explicitType = TallyCleaners_Taxes.cell(cells, typeUseIdx)
        def activeRaw    = TallyCleaners_Taxes.cell(cells, activeIdx)

        def typeUse  = TallyCleaners_Taxes.deriveTypeUse(taxName, explicitType, curVchType, purchaseTypeKw, purchaseTaxGrpK)
        def taxGroup = TallyCleaners_Taxes.deriveTaxGroup(taxName, taxGroupPatterns)
        def active   = TallyCleaners_Taxes.deriveActive(activeRaw)

        def lineId = "taxline_${curVchNo.replaceAll(/[^A-Za-z0-9]/, '_')}_${taxName.replaceAll(/[^A-Za-z0-9]/, '_')}"

        def lineRow = [
            lineId,
            curVchNo,
            curVchDate,
            curParty,
            curVchType,
            taxName,                                                          // → 'name'
            taxRate != null ? String.format('%.1f', taxRate) : '',            // → 'amount' (rate %)
            TallyCleaners_Taxes.fmtAmount(taxAmtRaw),                        // → 'tax_amount' (₹)
            typeUse,
            'percent',
            taxGroup,
            active
        ]

        sbLines.append(lineRow.collect { TallyCleaners_Taxes.escapeCsv(it?.toString() ?: '') }.join(',')).append('\n')
        linesWritten++
    }

    log.info("[Step3A] STEP7: ${linesWritten} tax lines written")

    if (linesWritten == 0) {
        log.warn('[Step3A] No tax rows detected — verify line_type_patterns.tax_keywords ' +
                 'in mappings.json matches your Tally tax line labels')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 8. Write single flowfile ──────────────────────────────────────────────
    def outBytes = sbLines.toString().getBytes(StandardCharsets.UTF_8)
    flowFile = session.write(flowFile, { _, out -> out.write(outBytes) } as StreamCallback)
    flowFile = session.putAllAttributes(flowFile, [
        'mime.type'  : 'text/csv',
        'filename'   : '01_tax_lines.csv',
        'entity.type': 'tax_lines',
        'row.count'  : linesWritten.toString()
    ])

    log.info("[Step3A] Done — 01_tax_lines.csv: ${linesWritten} rows")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("[Step3A] Failed: ${e.message}", e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def safeBigDecimal = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll('[^0-9.\\-]', '')
    if (!s || s == '.' || s == '-') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('LoadTax row: ' + row.toString()?.take(300))

    // ── 2. Read row fields — keys are already Odoo staging column names ───────
    def taxName  = nvl(row['name'])
    def typeUse  = nvl(row['type_tax_use'])  ?: 'sale'
    def amtType  = nvl(row['amount_type'])   ?: 'percent'
    def amount   = safeBigDecimal(row['amount'])
    def activeStr = nvl(row['active'])       ?: 'True'
    def active   = !(activeStr.toLowerCase() in ['false', '0', 'no', 'n'])
    def groupName = nvl(row['tax_group_name'])

    if (!taxName || taxName == 'name') {
        log.warn('Header or empty row — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("taxName=${taxName} typeUse=${typeUse} amount=${amount} groupName=${groupName}")

    // ── 3. Runtime constants — cache / env only ───────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def ctryId   = safeLong(cacheGet('lookup.country_id_in') ?: cacheGet('lookup.country_id'))
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    if (!ctryId) throw new Exception('country_id not in cache — re-run Bootstrap')

    // ── 4. Resolve tax_group_id ───────────────────────────────────────────────
    // First: from FlowFile attribute (set by LoadTaxGroup upstream)
    def taxGroupIdStr = ff.getAttribute('tax_group_id')
    log.info("tax_group_id from attr: [${taxGroupIdStr}]")

    // Fallback: derive from groupName and look up cache
    if (!taxGroupIdStr?.trim() || taxGroupIdStr == 'CLEARED') {
        if (groupName) {
            def groupSlug = groupName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
            taxGroupIdStr = cacheGet('taxgroup.' + groupSlug)
            log.info("tax_group_id from cache [taxgroup.${groupSlug}] = [${taxGroupIdStr}]")
        }
    }

    def taxGroupId = safeLong(taxGroupIdStr)
    if (!taxGroupId) {
        log.error("MISSING tax_group_id for: ${taxName} — ensure LoadTaxGroup ran first")
        ff = session.putAttribute(ff, 'error', "missing tax_group_id for ${taxName}")
        session.transfer(ff, REL_FAILURE)
        return
    }

    log.info("taxGroupId=${taxGroupId}")

    // ── 5. Build ext_id ───────────────────────────────────────────────────────
    def taxSlug = taxName.replaceAll(/%/, '').replaceAll(/[^A-Za-z0-9]+/, '_')
                         .toUpperCase().replaceAll(/^_|_$/, '')
    def extId   = 'tally_tax_' + taxSlug + '_' + typeUse.toUpperCase()

    // ── 6. Cache check ────────────────────────────────────────────────────────
    def cacheKey   = 'tax.' + taxName + '_' + typeUse
    def cachedTaxId = cacheGet(cacheKey)
    if (cachedTaxId) {
        log.info("Tax already cached: ${taxName} → ${cachedTaxId}")
        ff = session.putAttribute(ff, 'tax_id',   cachedTaxId)
        ff = session.putAttribute(ff, 'tax_name', taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 7. DB check ───────────────────────────────────────────────────────────
    def existingTaxId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingTaxId = r.getLong('res_id') }

    if (existingTaxId) {
        CTL.cacheClient.put(cacheKey, existingTaxId.toString(), ser, ser)
        log.info("Tax already in DB: ${taxName} → ${existingTaxId}")
        ff = session.putAttribute(ff, 'tax_id',   existingTaxId.toString())
        ff = session.putAttribute(ff, 'tax_name', taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 8. Build JSONB name ───────────────────────────────────────────────────
    def nameSafe = taxName.replace('"', '\\"')
    def nameJson = "{\"en_US\": \"${nameSafe}\"}"

    // ── 9. INSERT account_tax ─────────────────────────────────────────────────
    def ps = SQL.myPool.connection.prepareStatement(
        '''INSERT INTO account_tax
           (name, company_id, tax_group_id, country_id,
            sequence, amount, amount_type, type_tax_use,
            tax_exigibility, active,
            include_base_amount, is_base_affected, analytic, is_domestic,
            create_uid, write_uid, create_date, write_date)
           VALUES
           (?::jsonb, ?, ?, ?,
            10, ?, ?, ?,
            'on_invoice', ?,
            false, true, false, true,
            ?, ?, NOW(), NOW())
           RETURNING id'''
    )

    ps.setString(1,  nameJson)
    ps.setLong(2,    compId)
    ps.setLong(3,    taxGroupId)
    ps.setLong(4,    ctryId)
    ps.setBigDecimal(5, amount)
    ps.setString(6,  amtType)
    ps.setString(7,  typeUse)
    ps.setBoolean(8, active)
    ps.setLong(9,    adminUid)
    ps.setLong(10,   adminUid)

    def rs = ps.executeQuery()
    rs.next()
    def taxId = rs.getLong(1)
    ps.close()

    log.info("Tax INSERTED: ${taxName} → ${taxId}")

    // ── 10. Register XID ──────────────────────────────────────────────────────
    SQL.myPool.execute(
        '''INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date)
           VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING''',
        [module, extId, 'account.tax', taxId]
    )

    // ── 11. INSERT 4 repartition lines ────────────────────────────────────────
    def ps2 = SQL.myPool.connection.prepareStatement(
        '''INSERT INTO account_tax_repartition_line
           (tax_id, company_id, document_type, repartition_type,
            factor_percent, use_in_tax_closing, sequence,
            create_uid, write_uid, create_date, write_date)
           VALUES (?, ?, ?, ?, 100.0, ?, ?, ?, ?, NOW(), NOW())
           ON CONFLICT DO NOTHING'''
    )

    [
        ['invoice', 'base', false, 1],
        ['invoice', 'tax',  true,  2],
        ['refund',  'base', false, 1],
        ['refund',  'tax',  true,  2],
    ].each { docType, reptType, useInClosing, seq ->
        ps2.setLong(1,    taxId)
        ps2.setLong(2,    compId)
        ps2.setString(3,  docType)
        ps2.setString(4,  reptType)
        ps2.setBoolean(5, useInClosing)
        ps2.setInt(6,     seq)
        ps2.setLong(7,    adminUid)
        ps2.setLong(8,    adminUid)
        ps2.addBatch()
    }
    ps2.executeBatch()
    ps2.close()

    log.info("4 repartition lines INSERTED for: ${taxName}")

    CTL.cacheClient.put(cacheKey,           taxId.toString(), ser, ser)
    CTL.cacheClient.put('tax.' + taxName,   taxId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'tax_id',   taxId.toString())
    ff = session.putAttribute(ff, 'tax_name', taxName)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('LoadTax failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// TransformSalesOrder_Custom.groovy
// Full-file Sales Order CSV transformer.
// Each source row = one SO line item; SO header fields repeat across rows.
// Cleans data and normalizes dates. Output column names match what insert scripts read.
//
// NiFi flow:
//   TransformSalesOrder_Custom → SplitRecord → insert_sales_order_custom
//   → insert_sales_order_line_custom
//
// Input (Nevco SO data — column names may vary in case/spacing):
//   soid, CustomerNameId, CustomerAddressID, Date/OrderDate, DeliveryDate,
//   PaymentTerm, Remarks, PONumber, OrderTypeDetails, StatusName, CompanyName,
//   ProductName, Code, Description, Quantity, Price, Discount, AfterDiscount,
//   Tax, Taxamount, Unit
//
// All output columns are ALWAYS present (even empty) — prevents SplitRecord column count errors.

import groovy.json.JsonSlurper
import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets
import java.time.Instant
import java.time.LocalDate
import java.time.ZoneOffset
import java.time.format.DateTimeFormatter

def flowFile = session.get()
if (!flowFile) return

def splitCsv = { String line ->
    // Source CSV uses \, as escape for embedded commas inside unquoted fields.
    def result = []; def inQ = false; def sb = new StringBuilder()
    for (int ci = 0; ci < line.length(); ci++) {
        char c = line.charAt(ci)
        if (c == (char)'"') {
            inQ = !inQ
        } else if (c == (char)'\\' && !inQ && ci + 1 < line.length() && line.charAt(ci + 1) == (char)',') {
            sb.append(','); ci++
        } else if (c == (char)',' && !inQ) {
            result << sb.toString(); sb.setLength(0)
        } else {
            sb.append(c)
        }
    }
    result << sb.toString()
    return result
}

def escCsv = { String v ->
    // NiFi CSVReader Escape Character = \ — always-quoting causes "invalid char" when value ends with \.
    // Quote empty fields as "" (prevents trailing-field drop). Quote non-empty only when needed.
    // Escape \ → \\ inside quoted fields so NiFi reads literal backslash, not an escape prefix.
    def s = (v ?: '').replaceAll(/[\r\n]+/, ' ').trim()
    if (!s) return '""'
    if (s.contains(',') || s.contains('"') || s.contains('\\')) {
        s = s.replace('\\', '\\\\')
        return '"' + s.replace('"', '""') + '"'
    }
    return s
}

// Treat \N and \\N (Tally DB null markers, single and double-backslash variants) as empty.
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '\\\\N' && s != '') ? s : ''
}

def MONTH_MAP = [
    jan:1, feb:2, mar:3, apr:4,  may:5,  jun:6,
    jul:7, aug:8, sep:9, oct:10, nov:11, dec:12
]

def toDateStr = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    if (!s || s == 'null' || s == '\\N' || s == '\\\\N') return ''

    // YYYY-MM-DD (already canonical)
    if (s =~ /^\d{4}-\d{2}-\d{2}$/) return s

    // YYYYMMDD
    if (s =~ /^\d{8}$/) return "${s[0..3]}-${s[4..5]}-${s[6..7]}"

    // YYYY/MM/DD or YYYY-MM-DD with variable spacing
    def m = (s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/)
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())

    // DD-MM-YYYY or DD/MM/YYYY
    def m2 = (s =~ /^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/)
    if (m2) return String.format('%s-%02d-%02d', m2[0][3], m2[0][2].toInteger(), m2[0][1].toInteger())

    // DD-MMM-YYYY or DD/MMM/YYYY (e.g. 31-Mar-2023)
    def m3 = (s =~ /^(\d{1,2})[-\/]([A-Za-z]{3,9})[-\/](\d{4})$/)
    if (m3) {
        def mon = MONTH_MAP[m3[0][2].toLowerCase().take(3)]
        if (mon) return String.format('%s-%02d-%02d', m3[0][3], mon, m3[0][1].toInteger())
    }

    // Unix timestamp in milliseconds (e.g. 1677283200000 = 2023-02-25)
    if (s =~ /^\d+$/) {
        try {
            long ms = s.toLong()
            if (ms > 1000000000000L) {  // > year 2001 — clearly a ms timestamp
                return Instant.ofEpochMilli(ms).atZone(ZoneOffset.UTC).toLocalDate()
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
            // Excel date serial (e.g. 44982 = 2023-02-25): epoch is 1899-12-30
            if (ms > 25569 && ms < 100000) {
                return LocalDate.of(1899, 12, 30).plusDays(ms)
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
        } catch (ignored) {}
    }
    // Excel serial with decimal (e.g. 44982.0)
    if (s =~ /^\d+\.\d+$/) {
        try {
            long serial = Math.round(s.toDouble())
            if (serial > 25569 && serial < 100000) {
                return LocalDate.of(1899, 12, 30).plusDays(serial)
                    .format(DateTimeFormatter.ISO_LOCAL_DATE)
            }
        } catch (ignored) {}
    }
    return ''
}

// Suppress Excel zero-epoch time values (-2209075200000 ms = 1899-12-30 = Excel's day zero).
def cleanTime = { String raw ->
    if (!raw) return ''
    def s = raw.trim()
    if (!s || s == 'null' || s == '\\N' || s == '\\\\N') return ''
    try {
        if (s.toLong() <= -2209075200000L) return ''
    } catch (ignored) {}
    return s
}

try {
    // ── 1. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { is ->
        csvText = new String(is.bytes, StandardCharsets.UTF_8).replaceFirst(/^﻿/, '')
    } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    if (lines.size() < 2) {
        log.warn('[TransformSalesOrder_Custom] Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Resolve header indices ─────────────────────────────────────────────
    def rawHdrs = splitCsv(lines[0])
    def hdrIdx  = [:]
    rawHdrs.eachWithIndex { h, i -> def k = h?.trim()?.toLowerCase() ?: ''; if (k) hdrIdx[k] = i }

    def get           = { List cells, int idx -> idx < 0 || idx >= cells.size() ? '' : nvl(cells[idx]) }
    def mappingsPath  = flowFile.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
    def tableFields   = new JsonSlurper().parse(new File(mappingsPath)).tables?.sale_order?.fields ?: [:]
    def resolveColIdx = { String fieldName ->
        def fDef = tableFields[fieldName]
        if (!fDef) return -1
        def aliases = []
        if (fDef.source_col) aliases << fDef.source_col.toString()
        (fDef.source_cols ?: []).each { if (it) aliases << it.toString() }
        aliases = aliases.unique().findAll { it }
        for (String alias in aliases) { def k = alias.toLowerCase(); if (hdrIdx.containsKey(k)) return hdrIdx[k] }
        for (String alias in aliases) {
            def k = alias.toLowerCase()
            def found = hdrIdx.find { hk, hv -> hk && (hk.contains(k) || k.contains(hk)) }
            if (found) return found.value
        }
        return -1
    }

    def soidIdx      = resolveColIdx('soid')
    def cnIdx        = resolveColIdx('CustomerNameId')
    def caIdx        = resolveColIdx('CustomerAddressID')
    def dateIdx      = resolveColIdx('Date')
    def timeIdx      = resolveColIdx('Time')
    def delivDateIdx = resolveColIdx('DeliveryDate')
    def pmtIdx       = resolveColIdx('PaymentTerm')
    def remIdx       = resolveColIdx('Remarks')
    def poIdx        = resolveColIdx('PONumber')
    def orderTypIdx  = resolveColIdx('OrderTypeDetails')
    def statusIdx    = resolveColIdx('StatusName')
    def compNmIdx    = resolveColIdx('CompanyName')
    def userIdx      = resolveColIdx('UserName')
    def pnIdx        = resolveColIdx('ProductName')
    def codeIdx      = resolveColIdx('Code')
    def descIdx      = resolveColIdx('Description')
    def qtyIdx       = resolveColIdx('Quantity')
    def priceIdx     = resolveColIdx('Price')
    def discIdx      = resolveColIdx('Discount')
    def afterDiscIdx = resolveColIdx('AfterDiscount')
    def taxIdx       = resolveColIdx('Tax')
    def taxAmtIdx    = resolveColIdx('Taxamount')
    def unitIdx      = resolveColIdx('Unit')

    log.info("[TransformSalesOrder_Custom] soid:${soidIdx} date:${dateIdx} time:${timeIdx} " +
             "custNameId:${cnIdx} po:${poIdx} orderType:${orderTypIdx} user:${userIdx} code:${codeIdx} qty:${qtyIdx}")

    if (soidIdx < 0) {
        log.error('[TransformSalesOrder_Custom] Cannot find soid column — aborting')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Fixed output columns (names match insert_sales_order_custom) ───────
    def COLS = [
        'soid', 'CustomerNameId', 'CustomerAddressID',
        'Date', 'Time', 'DeliveryDate', 'PaymentTerm', 'Remarks',
        'PONumber', 'OrderTypeDetails', 'StatusName', 'CompanyName', 'UserName',
        'ProductName', 'Code', 'Description', 'Quantity', 'Price',
        'Discount', 'AfterDiscount', 'Tax', 'Taxamount', 'Unit'
    ]

    def sb = new StringBuilder().append(COLS.join(',')).append('\n')
    int written = 0, skipped = 0, nullDates = 0

    // ── 4. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < lines.size(); i++) {
        def c = splitCsv(lines[i])

        def soid = get(c, soidIdx)
        if (!soid) { skipped++; continue }
        if (soid.toLowerCase() == 'soid' || soid.toLowerCase() == 'so id') { skipped++; continue }

        // Strip trailing .0 from integer-valued floats (Excel artefact)
        soid = soid.replaceAll(/\.0$/, '')

        def rawDate    = get(c, dateIdx)
        def parsedDate = toDateStr(rawDate)
        if (!parsedDate && rawDate) {
            log.warn("[TransformSalesOrder_Custom] soid=${soid}: unrecognized date format '${rawDate}' — date_order will be null")
            nullDates++
        } else if (!parsedDate) {
            nullDates++
        }

        def cnVal = get(c, cnIdx).replaceAll(/\.0$/, '')
        def caVal = get(c, caIdx).replaceAll(/\.0$/, '')

        def row = [
            soid,
            cnVal, caVal,
            parsedDate, cleanTime(get(c, timeIdx)), toDateStr(get(c, delivDateIdx)),
            get(c, pmtIdx), get(c, remIdx),
            get(c, poIdx), get(c, orderTypIdx), get(c, statusIdx), get(c, compNmIdx), get(c, userIdx),
            get(c, pnIdx), get(c, codeIdx), get(c, descIdx),
            get(c, qtyIdx), get(c, priceIdx),
            get(c, discIdx), get(c, afterDiscIdx),
            get(c, taxIdx), get(c, taxAmtIdx), get(c, unitIdx)
        ]
        sb.append(row.collect { escCsv(it) }.join(',')).append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[TransformSalesOrder_Custom] No valid rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 5. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inS, outS ->
        outS.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.putAttribute(flowFile, 'mime.type', 'text/csv')
    session.putAttribute(flowFile, 'row.count', written.toString())
    log.info("[TransformSalesOrder_Custom] Done — ${written} rows written, ${skipped} skipped, ${nullDates} null/unparseable dates")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[TransformSalesOrder_Custom] Failed: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

// insert_sale_order_batch.groovy  (NiFi 2.x — SO batch, step 1 of 2)
//
// NiFi flow: TransformSalesOrder → SplitRecord(500/split, JSON array writer)
//              → [THIS] insert_sale_order_batch
//              → insert_sale_order_line_batch
//
// Input:  JSON array — multiple rows share the same soid (one row per line item)
// Action: For each unique soid INSERT one sale_order; populate cust.soid.{soid} cache
// Output: Pass-through JSON array
//
// IMPORTANT: All SQL.myPool.eachRow calls MUST stay outside withTransaction.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]
def soDefaults   = customCfg.so_defaults     ?: [:]

def soXidPfx   = xidPfx.sale_order ?: 'cust_so_'
def compXidPfx = xidPfx.company    ?: 'cust_company_'
def persXidPfx = xidPfx.person     ?: 'cust_person_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED' || s == '\\N') return null
    try { return s.toLong() } catch (ignored) {}
    try { return (long) s.toDouble() } catch (ignored) { return null }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def toDateStr = { def v ->
    if (!v) return null
    def s = v.toString().trim()
    if (!s || s == 'null' || s == '\\N') return null
    if (s =~ /^\d{4}-\d{2}-\d{2}/) return s.take(10)
    if (s ==~ /\d{13}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong())) } catch(ignored) {}
    }
    if (s ==~ /\d{10}/) {
        try { return new java.text.SimpleDateFormat('yyyy-MM-dd').format(new Date(s.toLong() * 1000L)) } catch(ignored) {}
    }
    def m = s =~ /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/
    if (m) return String.format('%s-%02d-%02d', m[0][1], m[0][2].toInteger(), m[0][3].toInteger())
    return null
}
def slugify = { String s ->
    if (!s) return 'unknown'
    def slug = s.replaceAll(/[^a-zA-Z0-9]/, '_').replaceAll(/_+/, '_')
               .replaceAll(/^_+/, '').replaceAll(/_+$/, '').take(80)
    slug ?: 'unknown'
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[SOBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
    def currId   = safeLong(cacheGet('lookup.currency_id_inr')) ?: safeLong(cacheGet('lookup.currency_id'))
    if (!currId) throw new Exception('currency_id not in cache — run bootstrap first')

    // ── 3. Schema probes (Phase 1) ────────────────────────────────────────────
    def soColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='sale_order' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def hasClientRef = soColExists('client_order_ref')
    def hasNote      = soColExists('note')
    def hasPricelist = soColExists('pricelist_id')
    def hasInvStatus = soColExists('invoice_status')
    log.info("[SOBatch] Schema: clientRef=${hasClientRef} pricelist=${hasPricelist} invStatus=${hasInvStatus}")

    // ── 4. Pricelist (shared across all rows) ─────────────────────────────────
    Long pricelistId = null
    if (hasPricelist) {
        pricelistId = safeLong(cacheGet('lookup.pricelist.default'))
        if (!pricelistId) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_pricelist WHERE currency_id=? AND active=true ORDER BY id LIMIT 1",
                [currId]
            ) { r ->
                pricelistId = safeLong(r['id'])
                if (pricelistId) cacheSet('lookup.pricelist.default', pricelistId.toString())
            }
        }
        log.info("[SOBatch] pricelistId=${pricelistId}")
    }

    // ── 5. Group rows by soid — take first occurrence for header data ──────────
    def soGroups = [:]  // soid → first row
    rows.each { row ->
        def soidRaw = nvl(row['soid'])
        if (!soidRaw) return
        def soid = soidRaw.replaceAll(/\.0$/, '')
        if (!soGroups.containsKey(soid)) soGroups[soid] = row
    }
    log.info("[SOBatch] Unique soids: ${soGroups.size()}")

    // ── 6. Per-soid Phase 1 resolution ────────────────────────────────────────
    def soItems      = []
    def cacheUpdates = []
    int skipCount    = 0

    soGroups.each { soid, row ->
        def soDate      = toDateStr(row['Date'])
        def custNameId  = nvl(row['CustomerNameId'])
        def custAddrId  = nvl(row['CustomerAddressID'])
        def payTermRaw  = nvl(row['PaymentTerm'])
        def poNumber    = nvl(row['PONumber'])
        def orderType   = nvl(row['OrderTypeDetails'])
        def companyName = nvl(row['CompanyName'])

        if (!soDate) {
            log.warn("[SOBatch] soid=${soid}: null/unparseable date — skipping")
            skipCount++; return
        }

        def extId    = soXidPfx + soid
        def cacheKey = 'xid.sale_order.' + extId

        // Idempotency: cache then ir_model_data
        Long existingId = null
        def cachedId = safeLong(cacheGet(cacheKey))
        if (cachedId) {
            def found = false
            SQL.myPool.eachRow('SELECT id FROM sale_order WHERE id=? LIMIT 1', [cachedId]) { found = true }
            if (found) { existingId = cachedId }
            else       { cacheSet(cacheKey, 'CLEARED') }
        }
        if (!existingId) {
            SQL.myPool.eachRow(
                'SELECT res_id FROM ir_model_data WHERE module=? AND name=? LIMIT 1', [module, extId]
            ) { r ->
                def rid = safeLong(r['res_id'])
                if (rid) {
                    def found = false
                    SQL.myPool.eachRow('SELECT id FROM sale_order WHERE id=? LIMIT 1', [rid]) { found = true }
                    if (found) existingId = rid
                }
            }
        }
        if (existingId) {
            cacheUpdates << [cacheKey,            existingId.toString()]
            cacheUpdates << ['cust.soid.' + soid, existingId.toString()]
            log.info("[SOBatch] Already exists: soid=${soid} → ${existingId}")
            skipCount++; return
        }

        // Partner resolution (5 levels, slugify-corrected)
        Long partnerId = null
        def nameSlug   = custNameId ? slugify(custNameId) : null
        def addrSlug   = custAddrId ? slugify(custAddrId) : null

        if (custNameId)  partnerId = safeLong(cacheGet('cust.nameid.'   + custNameId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.personid.' + custAddrId))
        if (!partnerId && custAddrId) partnerId = safeLong(cacheGet('cust.addrid.'   + custAddrId))
        if (!partnerId && nameSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, compXidPfx + nameSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && addrSlug) {
            SQL.myPool.eachRow(
                "SELECT res_id FROM ir_model_data WHERE module=? AND name=? AND model='res.partner' LIMIT 1",
                [module, persXidPfx + addrSlug]
            ) { r -> partnerId = safeLong(r['res_id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE name ILIKE ? AND active=true ORDER BY is_company DESC, id LIMIT 1",
                [companyName]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId && companyName) {
            SQL.myPool.eachRow(
                "SELECT id FROM res_partner WHERE (commercial_company_name ILIKE ? OR complete_name ILIKE ?) AND active=true ORDER BY is_company DESC, id LIMIT 1",
                ["%${companyName}%", "%${companyName}%"]
            ) { r -> partnerId = safeLong(r['id']) }
        }
        if (!partnerId) {
            log.warn("[SOBatch] Partner not resolved for soid=${soid} custNameId=${custNameId} — skipping")
            skipCount++; return
        }

        // Payment term
        Long paytermId = null
        if (payTermRaw) {
            paytermId = safeLong(cacheGet('lookup.payterm.' + payTermRaw))
            if (!paytermId) {
                SQL.myPool.eachRow(
                    "SELECT id FROM account_payment_term WHERE active=true AND name->>'en_US' ILIKE ? LIMIT 1",
                    [payTermRaw]
                ) { r -> paytermId = safeLong(r['id']) }
                if (paytermId) cacheSet('lookup.payterm.' + payTermRaw, paytermId.toString())
            }
        }

        def soPrefix = soDefaults.name_prefix ?: 'SO/'
        def soState  = soDefaults.state          ?: 'sale'
        def soInvSt  = soDefaults.invoice_status ?: 'to invoice'

        soItems << [
            soid      : soid,
            extId     : extId,
            cacheKey  : cacheKey,
            soName    : soPrefix + soid,
            soDate    : soDate,
            soState   : soState,
            soInvSt   : soInvSt,
            partnerId : partnerId,
            paytermId : paytermId,
            poNumber  : poNumber,
            orderType : orderType,
        ]
    }

    log.info("[SOBatch] SOs to insert: ${soItems.size()} skip: ${skipCount}")

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: only conn.prepareStatement inside
    // ════════════════════════════════════════════════════════════════════════
    int written  = 0
    def xidBatch = []

    SQL.myPool.withTransaction { conn ->
        soItems.each { item ->
            // Remove stale XID
            def delPs = conn.prepareStatement('DELETE FROM ir_model_data WHERE module=? AND name=?')
            delPs.setString(1, module); delPs.setString(2, item.extId)
            delPs.executeUpdate(); delPs.close()

            // Dynamic INSERT
            def cols   = ['name','date_order','state','picking_policy',
                          'company_id','currency_id',
                          'partner_id','partner_invoice_id','partner_shipping_id',
                          'create_uid','write_uid','create_date','write_date']
            def vals   = ['?','?::timestamp','?',"'direct'",'?','?','?','?','?','?','?','NOW()','NOW()']
            def params = [item.soName, item.soDate + ' 00:00:00', item.soState,
                          compId, currId,
                          item.partnerId, item.partnerId, item.partnerId,
                          adminUid, adminUid] as List

            if (item.paytermId)              { cols << 'payment_term_id'; vals << '?'; params << item.paytermId }
            if (pricelistId && hasPricelist) { cols << 'pricelist_id';    vals << '?'; params << pricelistId }
            if (hasClientRef && item.poNumber)  { cols << 'client_order_ref'; vals << '?'; params << item.poNumber }
            if (hasNote && item.orderType)      { cols << 'note';              vals << '?'; params << item.orderType }
            if (hasInvStatus)                   { cols << 'invoice_status';    vals << '?'; params << item.soInvSt }

            def soPs = conn.prepareStatement(
                "INSERT INTO sale_order (${cols.join(',')}) VALUES (${vals.join(',')}) RETURNING id"
            )
            params.eachWithIndex { v, i ->
                int pos = i + 1
                if (v == null)                    soPs.setObject(pos, null)
                else if (v instanceof Long)       soPs.setLong(pos, v)
                else if (v instanceof BigDecimal) soPs.setBigDecimal(pos, v)
                else                              soPs.setString(pos, v.toString())
            }
            def rs = soPs.executeQuery()
            rs.next(); long soId = rs.getLong(1); rs.close(); soPs.close()

            xidBatch      << [module, item.extId, 'sale.order', soId]
            cacheUpdates  << [item.cacheKey,          soId.toString()]
            cacheUpdates  << ['cust.soid.' + item.soid, soId.toString()]
            log.info("[SOBatch] INSERTED: ${item.extId} → ${soId} name='${item.soName}'")
            written++
        }

        // Batch XID inserts (sorted to prevent deadlocks)
        if (xidBatch) {
            xidBatch.sort { a, b -> a[1] <=> b[1] }
            def xidPs = conn.prepareStatement(
                'INSERT INTO ir_model_data (module,name,model,res_id,noupdate,create_date,write_date) ' +
                'VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING'
            )
            xidBatch.each { m, n, mdl, rid ->
                xidPs.setString(1, m); xidPs.setString(2, n)
                xidPs.setString(3, mdl); xidPs.setLong(4, rid)
                xidPs.addBatch()
            }
            try { xidPs.executeBatch() }
            catch (java.sql.BatchUpdateException bue) {
                log.error("[SOBatch] XID batch failed: ${bue.message}")
                throw bue
            }
            xidPs.close()
        }

        log.info("[SOBatch] Committed — written:${written}")
    }

    // Post-commit cache
    cacheUpdates.each { ck, v -> cacheSet(ck, v) }

    ff = session.putAllAttributes(ff, [
        'so.written': written.toString(),
        'so.skipped': skipCount.toString(),
        'batch.size': rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[SOBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// insert_sale_order_line_batch.groovy  (NiFi 2.x — SO line batch, step 2 of 2)
//
// NiFi flow: insert_sale_order_batch → [THIS]
//
// Input:  JSON array (same pass-through from step 1)
// Action: For each row INSERT one sale_order_line, link taxes,
//         roll up amounts to sale_order once per unique SO
//
// Idempotency: if a sale_order already has ANY lines, all lines for that SO
//              are skipped. Delete lines before re-running if needed.
//
// IMPORTANT: All SQL.myPool.eachRow calls MUST stay outside withTransaction.

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.InputStreamCallback

def ff = session.get()
if (!ff) return

// ── Load mapping.json ─────────────────────────────────────────────────────────
def mappingsPath = ff.attributes['mappings.path'] ?: '/home/ubuntu/Raw_tally_data/mapping.json'
def mappings     = new JsonSlurper().parse(new File(mappingsPath))
def customCfg    = mappings.custom_settings ?: [:]
def xidPfx       = customCfg.xid_prefixes   ?: [:]

def soXidPfx = xidPfx.sale_order ?: 'cust_so_'

// ── Helpers ───────────────────────────────────────────────────────────────────
def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED' || s == '\\N') return null
    try { return s.toLong() } catch (ignored) {}
    try { return (long) s.toDouble() } catch (ignored) { return null }
}
def safeBD = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll(/[,\s]/, '')
    if (!s || s == 'null' || s == '\\N' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}
def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null' && s != '\\N' && s != '') ? s : null
}
def cacheGet = { String key ->
    try {
        def v = CTL.cacheClient.get(key, ser, deser)
        return (v && v != 'CLEARED' && v != '0') ? v.trim() : null
    } catch(ignored) { return null }
}
def cacheSet = { String key, String val ->
    try { CTL.cacheClient.put(key, val, ser, ser) } catch(ignored) {}
}

try {
    // ── 1. Read JSON array ────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as InputStreamCallback)
    def rows = new JsonSlurper().parseText(jsonText)
    if (!(rows instanceof List)) rows = [rows]
    log.info("[SOLineBatch] Batch size: ${rows.size()}")

    // ── 2. Runtime constants ──────────────────────────────────────────────────
    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'
    def currId   = safeLong(cacheGet('lookup.currency_id_inr')) ?: safeLong(cacheGet('lookup.currency_id'))
    if (!currId) throw new Exception('currency_id not in cache')

    def soLineState = customCfg.so_defaults?.state ?: 'sale'

    // ── 3. Schema probes (Phase 1) ────────────────────────────────────────────
    def solColExists = { String col ->
        def found = false
        SQL.myPool.eachRow(
            "SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='sale_order_line' AND column_name=? LIMIT 1",
            [col]
        ) { found = true }
        return found
    }
    def hasDiscount        = solColExists('discount')
    def hasCurrencyId      = solColExists('currency_id')
    def hasPriceSubtot     = solColExists('price_subtotal')
    def hasPriceTotal      = solColExists('price_total')
    def hasPriceReduceExcl = solColExists('price_reduce_taxexcl')
    def hasPriceReduceInc  = solColExists('price_reduce_taxinc')
    def hasInvoiceStatus   = solColExists('invoice_status')
    def hasOrderPartnerId  = solColExists('order_partner_id')
    log.info("[SOLineBatch] Schema: discount=${hasDiscount} priceSubtot=${hasPriceSubtot} invStatus=${hasInvoiceStatus} orderPartner=${hasOrderPartnerId}")

    // ── 4. Tax junction table detection (Phase 1) ─────────────────────────────
    String taxRelTable  = null
    String taxRelLinCol = 'order_line_id'
    String taxRelTaxCol = 'tax_id'
    ['account_tax_sale_order_line_rel', 'sale_order_line_tax_rel', 'sale_order_line_taxes_rel'].each { tbl ->
        if (!taxRelTable) {
            def found = false
            SQL.myPool.eachRow(
                "SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name=? LIMIT 1", [tbl]
            ) { found = true }
            if (found) {
                taxRelTable = tbl
                if (tbl == 'account_tax_sale_order_line_rel') {
                    taxRelLinCol = 'sale_order_line_id'
                    taxRelTaxCol = 'account_tax_id'
                }
            }
        }
    }
    log.info("[SOLineBatch] taxRelTable=${taxRelTable} linCol=${taxRelLinCol} taxCol=${taxRelTaxCol}")

    // ── 5. Collect unique soids → soIds (Phase 1) ─────────────────────────────
    def soidToSoId = [:]  // soid → Long soId (null if SO not found)
    rows.each { row ->
        def soidRaw = nvl(row['soid'])
        if (!soidRaw) return
        def soid = soidRaw.replaceAll(/\.0$/, '')
        if (soidToSoId.containsKey(soid)) return
        Long soId = safeLong(cacheGet('cust.soid.' + soid))
        if (!soId) {
            SQL.myPool.eachRow(
                'SELECT res_id FROM ir_model_data WHERE module=? AND name=? LIMIT 1',
                [module, soXidPfx + soid]
            ) { r -> soId = safeLong(r['res_id']) }
        }
        soidToSoId[soid] = soId  // may be null
    }

    // Check which SOs already have lines (skip entire SO if any lines exist)
    def soHasLines    = [:]  // soId → boolean
    def soPartnerMap  = [:]  // soId → partnerId (for order_partner_id column)
    def uniqueSoIds   = soidToSoId.values().findAll { it }.toList().unique()
    uniqueSoIds.each { Long soId ->
        long cnt = 0
        SQL.myPool.eachRow('SELECT COUNT(*) AS c FROM sale_order_line WHERE order_id=?', [soId]) { r ->
            cnt = r['c'] as Long ?: 0L
        }
        soHasLines[soId] = cnt > 0
        if (hasOrderPartnerId) {
            SQL.myPool.eachRow('SELECT partner_id FROM sale_order WHERE id=? LIMIT 1', [soId]) { r ->
                soPartnerMap[soId] = safeLong(r['partner_id'])
            }
        }
    }

    // ── 6. Per-row Phase 1 resolution ─────────────────────────────────────────
    def lineItems = []
    int skipCount = 0

    rows.each { row ->
        def soidRaw = nvl(row['soid'])
        if (!soidRaw) { skipCount++; return }
        def soid = soidRaw.replaceAll(/\.0$/, '')

        Long soId = soidToSoId[soid]
        if (!soId) {
            log.warn("[SOLineBatch] No SO for soid=${soid} — skipping line")
            skipCount++; return
        }
        if (soHasLines[soId]) {
            skipCount++; return
        }

        def prodCode    = nvl(row['Code'])
        def prodName    = nvl(row['ProductName'])
        def description = nvl(row['Description']) ?: prodName
        def qty         = safeBD(row['Quantity']) ?: BigDecimal.ONE
        def unitPrice   = safeBD(row['Price'])
        def discount    = safeBD(row['Discount'])
        def afterDisc   = safeBD(row['AfterDiscount'])
        def taxPctRaw   = safeBD(row['Tax'])
        def taxAmount   = safeBD(row['Taxamount'])
        def uomRaw      = nvl(row['Unit'])

        def HUNDRED = new BigDecimal('100')
        if (afterDisc == BigDecimal.ZERO && unitPrice > BigDecimal.ZERO) {
            afterDisc = unitPrice.multiply(qty).multiply(
                BigDecimal.ONE.subtract(discount.divide(HUNDRED, 10, java.math.RoundingMode.HALF_UP))
            )
        }
        def priceSubtotal = afterDisc
        def priceTotal    = afterDisc.add(taxAmount)
        def priceReduceVal = discount > BigDecimal.ZERO
            ? unitPrice.multiply(BigDecimal.ONE.subtract(discount.divide(HUNDRED, 10, java.math.RoundingMode.HALF_UP)))
            : unitPrice

        // Product resolution
        Long prodVariantId = null
        Long prodTmplId    = null
        if (prodCode) {
            def cachedProdId = safeLong(cacheGet('product.code.' + prodCode))
            if (cachedProdId) {
                SQL.myPool.eachRow(
                    'SELECT product_tmpl_id FROM product_product WHERE id=? AND active=true LIMIT 1',
                    [cachedProdId]
                ) { r ->
                    prodVariantId = cachedProdId
                    prodTmplId    = safeLong(r['product_tmpl_id'])
                }
                if (!prodVariantId) cacheSet('product.code.' + prodCode, 'CLEARED')
            }
            if (!prodVariantId) {
                SQL.myPool.eachRow(
                    "SELECT id, product_tmpl_id FROM product_product WHERE default_code=? AND active=true LIMIT 1",
                    [prodCode]
                ) { r ->
                    prodVariantId = safeLong(r['id'])
                    prodTmplId    = safeLong(r['product_tmpl_id'])
                    if (prodVariantId) cacheSet('product.code.' + prodCode, prodVariantId.toString())
                }
            }
        }

        // UOM resolution
        Long uomId = null
        if (uomRaw) {
            uomId = safeLong(cacheGet('lookup.uom.' + uomRaw))
            if (!uomId) {
                SQL.myPool.eachRow(
                    "SELECT id FROM uom_uom WHERE active=true AND name->>'en_US' ILIKE ? LIMIT 1", [uomRaw]
                ) { r ->
                    uomId = safeLong(r['id'])
                    if (uomId) cacheSet('lookup.uom.' + uomRaw, uomId.toString())
                }
            }
        }
        if (!uomId && prodTmplId) {
            SQL.myPool.eachRow('SELECT uom_id FROM product_template WHERE id=? LIMIT 1', [prodTmplId]) { r ->
                uomId = safeLong(r['uom_id'])
            }
        }
        if (!uomId) {
            uomId = safeLong(cacheGet('lookup.uom.Units'))
            if (!uomId) {
                SQL.myPool.eachRow(
                    "SELECT id FROM uom_uom WHERE active=true AND name->>'en_US' ILIKE 'Unit%' ORDER BY id LIMIT 1"
                ) { r ->
                    uomId = safeLong(r['id'])
                    if (uomId) cacheSet('lookup.uom.Units', uomId.toString())
                }
            }
        }

        // Tax resolution (3-level: cache → numeric amount-based → product taxes)
        def taxPct = (int) taxPctRaw.longValue()
        List<Long> taxIds = []
        if (taxPct > 0) {
            def ck  = 'lookup.tax.sale.' + taxPct
            def tid = safeLong(cacheGet(ck))
            if (tid) {
                def taxExists = false
                SQL.myPool.eachRow("SELECT 1 FROM account_tax WHERE id=? AND active=true LIMIT 1", [tid]) { taxExists = true }
                if (taxExists) taxIds << tid
                else           cacheSet(ck, 'CLEARED')
            }
            if (!taxIds) {
                try {
                    SQL.myPool.eachRow("""
                        SELECT id FROM account_tax
                        WHERE company_id=? AND active=true AND amount=? AND amount_type='percent'
                        ORDER BY CASE WHEN type_tax_use='sale' THEN 0
                                      WHEN type_tax_use='none' THEN 1
                                      ELSE 2 END, id LIMIT 1
                    """, [compId, taxPctRaw]) { r ->
                        def tid2 = safeLong(r['id'])
                        if (tid2) { taxIds << tid2; cacheSet(ck, tid2.toString()) }
                    }
                } catch(ignored) {}
            }
        }
        if (!taxIds && prodTmplId) {
            SQL.myPool.eachRow("""
                SELECT ptr.tax_id FROM product_taxes_rel ptr
                JOIN account_tax at ON at.id = ptr.tax_id
                WHERE ptr.prod_id=? AND at.active=true AND at.type_tax_use IN ('sale','all')
            """, [prodTmplId]) { r ->
                def tid = safeLong(r['tax_id'])
                if (tid) taxIds << tid
            }
        }

        lineItems << [
            soId           : soId,
            orderPartnerId : soPartnerMap[soId],
            prodVariantId  : prodVariantId,
            description    : description ?: prodName ?: '',
            qty            : qty,
            unitPrice      : unitPrice,
            discount       : discount,
            taxPctRaw      : taxPctRaw,
            priceSubtotal  : priceSubtotal,
            priceTotal     : priceTotal,
            priceReduceVal : priceReduceVal,
            uomId          : uomId,
            taxIds         : taxIds,
        ]
    }

    log.info("[SOLineBatch] Lines to insert: ${lineItems.size()} skip: ${skipCount}")

    // ════════════════════════════════════════════════════════════════════════
    // PHASE 2 — transaction: only conn.prepareStatement inside
    // ════════════════════════════════════════════════════════════════════════
    int written = 0
    Set<Long> affectedSoIds = []

    if (lineItems) {
        SQL.myPool.withTransaction { conn ->
            lineItems.each { item ->
                // Dynamic INSERT sale_order_line
                def cols   = ['order_id', 'sequence']
                def vals   = ['?', '10']
                def params = [item.soId] as List

                if (item.prodVariantId) { cols << 'product_id';    vals << '?'; params << item.prodVariantId }
                cols << 'name';            vals << '?';  params << item.description
                cols << 'product_uom_qty'; vals << '?';  params << item.qty
                cols << 'qty_delivered';   vals << '0'
                cols << 'qty_invoiced';    vals << '0'
                cols << 'price_unit';      vals << '?';  params << item.unitPrice
                cols << 'customer_lead';   vals << '0.0'
                cols << 'state';           vals << '?';  params << soLineState
                cols << 'company_id';      vals << '?';  params << compId
                cols << 'create_uid';      vals << '?';  params << adminUid
                cols << 'write_uid';       vals << '?';  params << adminUid

                if (item.uomId) {
                    cols << 'product_uom_id'; vals << '?'; params << item.uomId
                }
                if (hasDiscount) {
                    cols << 'discount'; vals << '?'; params << item.discount
                }
                if (hasCurrencyId) {
                    cols << 'currency_id'; vals << '?'; params << currId
                }
                if (hasPriceSubtot) {
                    cols << 'price_subtotal'; vals << '?'; params << item.priceSubtotal
                }
                if (hasPriceTotal) {
                    cols << 'price_total'; vals << '?'; params << item.priceTotal
                }
                if (hasPriceReduceExcl) {
                    cols << 'price_reduce_taxexcl'; vals << '?'; params << item.priceReduceVal
                }
                if (hasPriceReduceInc) {
                    def taxInc = item.priceReduceVal.add(
                        item.priceReduceVal.multiply(item.taxPctRaw)
                            .divide(new BigDecimal('100'), 10, java.math.RoundingMode.HALF_UP)
                    )
                    cols << 'price_reduce_taxinc'; vals << '?'; params << taxInc
                }
                if (hasInvoiceStatus) {
                    cols << 'invoice_status'; vals << "'invoiced'"
                }
                if (hasOrderPartnerId && item.orderPartnerId) {
                    cols << 'order_partner_id'; vals << '?'; params << item.orderPartnerId
                }

                cols << 'create_date'; vals << 'NOW()'
                cols << 'write_date';  vals << 'NOW()'

                def lnPs = conn.prepareStatement(
                    "INSERT INTO sale_order_line (${cols.join(',')}) VALUES (${vals.join(',')}) RETURNING id"
                )
                params.eachWithIndex { v, i ->
                    int pos = i + 1
                    if (v == null)                    lnPs.setObject(pos, null)
                    else if (v instanceof Long)       lnPs.setLong(pos, v)
                    else if (v instanceof BigDecimal) lnPs.setBigDecimal(pos, v)
                    else                              lnPs.setString(pos, v.toString())
                }
                def lnRs = lnPs.executeQuery()
                lnRs.next(); long lineId = lnRs.getLong(1); lnRs.close(); lnPs.close()

                // Link taxes
                if (item.taxIds && taxRelTable) {
                    item.taxIds.each { Long tid ->
                        def txPs = conn.prepareStatement(
                            "INSERT INTO ${taxRelTable} (${taxRelLinCol}, ${taxRelTaxCol}) VALUES (?,?) ON CONFLICT DO NOTHING"
                        )
                        txPs.setLong(1, lineId); txPs.setLong(2, tid)
                        txPs.executeUpdate(); txPs.close()
                    }
                }

                affectedSoIds << item.soId
                written++
            }

            // Roll up amounts to sale_order (once per unique SO)
            affectedSoIds.each { Long soId ->
                def ruPs = conn.prepareStatement("""
                    UPDATE sale_order so
                    SET amount_untaxed = COALESCE(sub.untaxed, 0),
                        amount_tax     = COALESCE(sub.tax,     0),
                        amount_total   = COALESCE(sub.total,   0)
                    FROM (
                        SELECT SUM(price_subtotal)               AS untaxed,
                               SUM(price_total - price_subtotal) AS tax,
                               SUM(price_total)                  AS total
                        FROM sale_order_line WHERE order_id=?
                    ) sub
                    WHERE so.id=?
                """)
                ruPs.setLong(1, soId); ruPs.setLong(2, soId)
                ruPs.executeUpdate(); ruPs.close()
            }

            log.info("[SOLineBatch] Committed — lines:${written} SOs rolled up:${affectedSoIds.size()}")
        }
    }

    ff = session.putAllAttributes(ff, [
        'sol.written': written.toString(),
        'sol.skipped': skipCount.toString(),
        'batch.size' : rows.size().toString()
    ])
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('[SOLineBatch] Failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

import TallyCleaner
import org.apache.nifi.processor.io.InputStreamCallback
import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

try {
    // ── 1. Load mappings ──────────────────────────────────────────────────────
    def mappingsPath = flowFile.getAttribute('mappings.path') ?: '/home/ubuntu/Raw_tally_data/mappings.json'
    log.info("[CoA] STEP1: Loading mappings from: ${mappingsPath}")

    def mappingJson = new File(mappingsPath).text
    def mappings    = new JsonSlurper().parseText(mappingJson)

    // tally_group_to_odoo — already at root of mappings.json
    def groupMap  = mappings.tally_group_to_odoo ?: [:]

    // account_account table config — already in mappings.tables.account_account
    def coaTable  = mappings.tables?.account_account ?: [:]
    def coaFields = coaTable.fields ?: [:]

    log.info("[CoA] STEP1: coaFields loaded — ${coaFields.size()} fields")

    if (coaFields.isEmpty()) {
        log.error("[CoA] STEP1: tables.account_account.fields is EMPTY — check mappings.json")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (groupMap.isEmpty()) {
        log.error("[CoA] STEP1: tally_group_to_odoo is EMPTY — check mappings.json")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { is -> csvText = is.text } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    log.info("[CoA] STEP2: Total lines: ${lines.size()}")

    if (lines.size() < 2) {
        log.warn('[CoA] STEP2: Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    def headers = TallyCleaners.splitCsvLine(lines[0])
    log.info("[CoA] STEP2: CSV headers: ${headers}")

    // ── 3. Build header index — skip empty headers (identical to contacts) ────
    def headerIdx = [:]
    headers.eachWithIndex { h, i ->
        def key = h?.trim()?.toLowerCase() ?: ''
        if (key) headerIdx[key] = i
    }
    log.info("[CoA] STEP3: headerIdx: ${headerIdx}")

    // ── 4. Alias-driven column resolver — exact copy of contacts pattern ──────
    def resolveColIdx = { String odooField ->
        def fm = coaFields[odooField]
        if (!fm) {
            log.warn("[CoA] STEP4: '${odooField}' not in coaFields")
            return -1
        }

        def candidates = []
        if (fm.source_col)                              candidates << fm.source_col.toString().trim()
        if (fm.source_cols instanceof List) candidates += fm.source_cols*.toString()*.trim()
        candidates = candidates.findAll { it }

        // a) Exact match first
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (headerIdx.containsKey(aliasL)) {
                log.info("[CoA] STEP4: '${odooField}' → EXACT '${alias}' → col ${headerIdx[aliasL]}")
                return headerIdx[aliasL]
            }
        }

        // b) Contains fallback
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            def found = headerIdx.find { k, v ->
                k && k.trim() && (k.contains(aliasL) || aliasL.contains(k))
            }
            if (found) {
                log.info("[CoA] STEP4: '${odooField}' → CONTAINS '${alias}' ~ '${found.key}' → col ${found.value}")
                return found.value
            }
        }

        log.warn("[CoA] STEP4: '${odooField}' → NO MATCH in headers")
        return -1
    }

    // ── 5. Resolve column indices ─────────────────────────────────────────────
    // Field names match exactly what is in mappings.tables.account_account.fields
    int nameIdx    = resolveColIdx('name')        
    int groupIdx   = resolveColIdx('tally_group') 
    int codeIdx    = resolveColIdx('code_store')  

    log.info("[CoA] STEP5: FINAL indices — name:${nameIdx} group:${groupIdx} code:${codeIdx}")

    if (nameIdx < 0) {
        log.error("[CoA] STEP5: nameIdx=-1 — name column not found — all rows will be skipped")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (groupIdx < 0) {
        log.error("[CoA] STEP5: groupIdx=-1 — tally_group/under column not found — cannot map account types")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 6. Output config — all from mappings, ──────────────
    // output_cols, id_prefix, filename — add these 3 keys to account_account in mappings.json
    // (see mappings_coa_additions.json); fallback defaults keep script working without them
    def OUT_COLS    = (coaTable.output_cols   as List<String>) ?: ['id', 'code_store', 'name', 'account_type', 'reconcile']
    def idPrefix    = coaTable.id_prefix   ?: 'tally_account_'
    def outFilename = coaTable.filename    ?: '02_coa.csv'

    // Code counter — auto-generates prefix001, prefix002 … per prefix group
    def codeCounters = [:]
    def nextCode = { String prefix ->
        def n = (codeCounters[prefix] ?: 0) + 1
        codeCounters[prefix] = n
        return prefix + String.format('%03d', n)
    }

    def sb      = new StringBuilder().append(OUT_COLS.join(',')).append('\n')
    int written = 0
    int skipped = 0

    // ── 7. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < lines.size(); i++) {
        def rawCells = TallyCleaners.splitCsvLine(lines[i])
        def cells    = TallyCleaners.fixShiftedRow(rawCells, headers, nameIdx)

        // a) Name — mandatory
        def name = TallyCleaners.cell(cells, nameIdx)
        if (!name || TallyCleaners.isEmpty(name)) {
            skipped++
            continue
        }

        // b) Tally group → Odoo entry
        def tallyGroup = TallyCleaners.cell(cells, groupIdx)?.trim()
        def entry      = groupMap[tallyGroup]
        if (!entry) {
            log.warn("[CoA] STEP7: Unknown group '${tallyGroup}' for '${name}' — skipping")
            skipped++
            continue
        }

        // c) Account code — use CSV column if present (code_store/alias), else auto-generate
        def code
        if (codeIdx >= 0) {
            def csvCode = TallyCleaners.cell(cells, codeIdx)?.trim()
            code = (csvCode && !TallyCleaners.isEmpty(csvCode)) ? csvCode : nextCode(entry.code_prefix as String)
        } else {
            code = nextCode(entry.code_prefix as String)
        }

        // d) Assemble row — OUT_COLS drives order and which fields appear
        def vals = [
            'id'          : idPrefix + code,
            'code_store'        : code,
            'name'        : name,
            'account_type': entry.account_type as String,
            'reconcile'   : entry.reconcile ? 'True' : 'False',
            'tally_group' : tallyGroup ?: '',
        ]

        def row = OUT_COLS.collect { vals.getOrDefault(it, '') }
        sb.append(row.collect { TallyCleaners.escapeCsv(it as String) }.join(',')).append('\n')
        log.info("[CoA] [row] ${row}")
        written++
    }

    log.info("[CoA] STEP7: DONE — written=${written} skipped=${skipped} of ${lines.size() - 1} rows")

    if (written == 0) {
        log.warn('[CoA] STEP7: No valid rows produced — check tally_group_to_odoo coverage in mappings.json')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 8. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inStream, outStream ->
        outStream.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as org.apache.nifi.processor.io.StreamCallback)

    session.putAttribute(flowFile, 'mime.type',    'text/csv')
    session.putAttribute(flowFile, 'filename',     outFilename)
    session.putAttribute(flowFile, 'staging.file', outFilename)
    session.putAttribute(flowFile, 'entity.type',  'coa')
    session.putAttribute(flowFile, 'row.count',    written.toString())
    log.info("[CoA] STEP8: Complete — ${outFilename} — row.count=${written}")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[CoA] FAILED: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('insert_account_account row: ' + row.toString()?.take(300))

    // ── 2. Read fields ────────────────────────────────────────────────────────
    def name        = nvl(row['name'])
    def accountType = nvl(row['account_type'])
    def reconcile   = row['reconcile']?.toString()?.trim()?.toLowerCase() == 'true'
    def csvCode     = nvl(row['code_store'])

    log.info("name=${name} accountType=${accountType} reconcile=${reconcile} csvCode=${csvCode}")

    if (!name) {
        log.warn('Empty name — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }
    if (!accountType) {
        log.warn("Empty account_type for '${name}' — skipping")
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 3. Runtime constants ──────────────────────────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // ── 4. Resolve account code ───────────────────────────────────────────────
    def code = csvCode

    if (!code) {
        def prefixMap = [
            asset_receivable    : '13',
            liability_payable   : '21',
            asset_cash          : '11',
            asset_fixed         : '16',
            asset_current       : '14',
            asset_non_current   : '15',
            equity              : '31',
            income              : '41',
            income_other        : '42',
            expense             : '51',
            expense_direct_cost : '52',
            liability_current   : '22',
            liability_non_current: '23',
            liability_credit_card: '22',
        ]
        def prefix      = prefixMap[accountType] ?: '90'
        def prefixFloor = "${prefix}000".toString()
        def compKey     = compId.toString()

        log.info("code missing — auto-generating with prefix='${prefix}'")

        SQL.myPool.eachRow("""
            SELECT COALESCE(
                MAX((code_store->>'${compKey}')::int), ${prefixFloor}::int
            ) + 1 AS next_code
            FROM account_account
            WHERE code_store->>'${compKey}' LIKE '${prefix}%'
        """) { r -> code = r.next_code?.toString() }

        log.info("Auto-generated code='${code}'")
    }

    if (!code) throw new Exception("code could not be resolved for '${name}' accountType='${accountType}'")

    // ── 5. Build JSONB values ─────────────────────────────────────────────────
    def nameSafe = name.replace('"', '\\"')
    def nameJson = "{\"en_US\": \"${nameSafe}\"}"
    def codeJson = JsonOutput.toJson([(compId.toString()): code])
    log.info("nameJson=${nameJson} codeJson=${codeJson}")

    // ── 6. External ID ────────────────────────────────────────────────────────
    def extId = nvl(row['id']) ?: ('tally_account_' + code.replaceAll(/[^a-zA-Z0-9]/, '_'))
    log.info("extId=${extId}")

    // ── 7. Cache check ────────────────────────────────────────────────────────
    def cacheKey = 'xid.account_account.' + extId
    def cachedId = cacheGet(cacheKey)

    if (cachedId) {
        log.info("Account already cached: ${name} -> ${cachedId}")
        ff = session.putAttribute(ff, 'res_id',       cachedId)
        ff = session.putAttribute(ff, 'account_xid',  extId)
        ff = session.putAttribute(ff, 'account_code', code)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 8. DB check ───────────────────────────────────────────────────────────
    def existingId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingId = r.getLong('res_id') }

    long resId

    if (existingId) {
        // ── Already in DB — ensure company rel exists (handles re-runs / backfill)
        resId = existingId
        log.info("Account already in DB: ${name} -> ${resId} — ensuring company rel exists")

        SQL.myPool.execute(
            '''INSERT INTO account_account_res_company_rel (account_account_id, res_company_id)
               VALUES (?, ?)
               ON CONFLICT DO NOTHING''',
            [resId, compId]
        )

    } else {
        // ── 9. INSERT account_account ─────────────────────────────────────────
        // NOTE: No company_id column in Odoo 17+.
        // Company is encoded in code_store JSONB key AND in the junction table (step 11).
        def ps = SQL.myPool.connection.prepareStatement('''
            INSERT INTO account_account
              (account_type, name, code_store, reconcile, active,
               create_asset, non_trade,
               create_uid, write_uid, create_date, write_date)
            VALUES (
              ?, ?::jsonb, ?::jsonb, ?, true,
              'no', false,
              ?, ?, NOW(), NOW()
            )
            RETURNING id
        ''')

        int p = 1
        ps.setString(p++, accountType)
        ps.setString(p++, nameJson)
        ps.setString(p++, codeJson)
        ps.setBoolean(p++, reconcile)
        ps.setLong(p++,   adminUid)
        ps.setLong(p++,   adminUid)

        def rs = ps.executeQuery()
        rs.next()
        resId = rs.getLong(1)
        ps.close()

        log.info("account_account INSERTED: ${name} (${code}) -> ${resId}")

        // ── 10. Register XID in ir_model_data ─────────────────────────────────
        SQL.myPool.execute(
            '''INSERT INTO ir_model_data
               (module, name, model, res_id, noupdate, create_date, write_date)
               VALUES (?,?,?,?,false,NOW(),NOW())
               ON CONFLICT (module,name) DO NOTHING''',
            [module, extId, 'account.account', resId]
        )

        SQL.myPool.execute(
            '''INSERT INTO account_account_res_company_rel (account_account_id, res_company_id)
               VALUES (?, ?)
               ON CONFLICT DO NOTHING''',
            [resId, compId]
        )

        log.info("Company rel inserted: account ${resId} -> company ${compId} — account now visible in UI")
    }

    // ── 12. Populate caches ───────────────────────────────────────────────────
    CTL.cacheClient.put(cacheKey,                        resId.toString(), ser, ser)
    CTL.cacheClient.put('account.code.' + code,          resId.toString(), ser, ser)
    CTL.cacheClient.put('account.name.' + name,          resId.toString(), ser, ser)
    CTL.cacheClient.put('xid.account_account.' + extId,  resId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'res_id',       resId.toString())
    ff = session.putAttribute(ff, 'account_xid',  extId)
    ff = session.putAttribute(ff, 'account_code', code)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('insert_account_account failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}
